-- Poems batch 415
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-322','满庭芳','康与之','宋','宋词','song-ci','满庭芳','[]','霜幕风帘，闲斋小户，素蟾初上雕笼。',118,'宋词/ci.song.8000.json','["霜幕风帘，闲斋小户，素蟾初上雕笼。", "玉杯醽醁，还与可人同。", "古鼎沈烟篆细，玉笋破、橙橘香浓。", "梳妆懒，脂轻粉薄，约略淡眉峰。", "清新，歌几许，低随慢唱，语笑相供。", "道文书针线，今夜休攻。", "莫厌兰膏更继，明朝又、粉冗匆匆。", "酩酊也，冠儿未卸，先把被儿烘。"]'),
('song-ci-323','减字木兰花','康与之','宋','宋词','song-ci','减字木兰花','[]','杨花飘尽。',52,'宋词/ci.song.8000.json','["杨花飘尽。", "云压绿阴风乍定。", "帘幕闲垂。", "弄语千般燕子飞。", "小楼深静。", "睡起残妆犹未整。", "梦不成归。", "泪滴斑斑金缕衣。"]'),
('song-ci-324','采桑子','康与之','宋','宋词','song-ci','采桑子','[]','晚来一霎风兼雨，洗尽炎光。',52,'宋词/ci.song.8000.json','["晚来一霎风兼雨，洗尽炎光。", "理罢笙篁。", "却对菱花淡淡妆。", "绛绡缕薄冰肌莹，雪腻酥香。", "笑语檀郎。", "今夜纱厨枕簟凉。"]'),
('song-ci-325','荷叶铺水面','康与之','宋','宋词','song-ci','荷叶铺水面','[]','春光艳冶，游人踏绿苔。',68,'宋词/ci.song.8000.json','["春光艳冶，游人踏绿苔。", "千红万紫竞香开。", "暖风拂鼻籁，蓦地暗香透满怀。", "荼縻似锦裁。", "娇红间绿白，只怕迅速春回。", "误落在尘埃。", "折向鬓云间、金凤钗。"]'),
('song-ci-326','菩萨蛮','康与之','宋','宋词','song-ci','菩萨蛮','[]','弱柳小腰身。',12,'宋词/ci.song.8000.json','["弱柳小腰身。", "双双蛾翠颦。"]'),
('song-ci-327','水龙吟','曾觌','宋','宋词','song-ci','水龙吟','[]','楚天千里无云，露华洗出秋容净。',126,'宋词/ci.song.8000.json','["楚天千里无云，露华洗出秋容净。", "银蟾台榭，玉壶天地，参差桂影。", "鸳瓦寒生，画檐光射，碧梧金井。", "听韶华半夜，江梅三弄，风袅袅、良宵永。", "携手西园宴罢，下瑶台、醉魂初醒。", "吹箫仙子，骖鸾归路，一襟清兴。", "鳷鹊楼高，建章门迥，星河耿耿。", "看沧江潮上，丹枫落叶，浸关山冷。"]'),
('song-ci-328','念奴娇','曾觌','宋','宋词','song-ci','念奴娇','[]','霁天湛碧，正新凉风露，冰壶清彻。',120,'宋词/ci.song.8000.json','["霁天湛碧，正新凉风露，冰壶清彻。", "河汉无声□□□，涌出银蟾孤绝。", "岩桂香飘，井梧影转，冷浸宫袍洁。", "西厢往事，一帘幽梦凄切。", "肠断楚峡云归，尊前无绪，只有愁如发。", "此夕姮娥应也恨，冷落琼楼金阙。", "禁漏迢迢，边鸿杳杳，密意凭谁说。", "阑干星汉，落梅三弄初阕。"]'),
('song-ci-329','念奴娇','曾觌','宋','宋词','song-ci','念奴娇','[]','群花渐老，向晓来微雨，芳心初拆。',120,'宋词/ci.song.8000.json','["群花渐老，向晓来微雨，芳心初拆。", "拂掠娇红香旖旎，浑欲不胜春色。", "淡月梨花，新晴繁杏，装点成标格。", "风光都在，半开深院人寂。", "刚要买断东风，袅栾枝低映，舞茵歌席。", "记得当时曾共赏，玉人纤手轻摘。", "醉里妖饶，醒时风韵，比并堪端的。", "谁知憔悴，对花空恁思忆。"]'),
('song-ci-330','念奴娇','曾觌','宋','宋词','song-ci','念奴娇','[]','人生行乐，算一春欢赏，都来几日。',120,'宋词/ci.song.8000.json','["人生行乐，算一春欢赏，都来几日。", "绿暗红稀春已去，赢得星星头白。", "醉里狂歌，花前起舞，拚罚金杯百。", "淋漓宫锦，忍辜妖艳姿色。", "须信殿得韶光，只愁花谢，又作经年别。", "嫩紫娇红还解语，应为主人留客。", "月落乌啼，酒阑烛暗，离绪伤吴越。", "竹西歌吹，不堪老去重忆。"]'),
('song-ci-331','念奴娇','曾觌','宋','宋词','song-ci','念奴娇','[]','媚容素态，比群花、赢了风流颜色。',120,'宋词/ci.song.8000.json','["媚容素态，比群花、赢了风流颜色。", "昵枕低帏销受得，□□轻怜深惜。", "怎望如今，瓶沈簪折，蓦地成疏隔。", "□□夕雨，甚时重见踪迹。", "门外暂泊兰舟，一行霜树，□一重山碧。", "泪眼相看争忍望，天际孤村寒驿。", "卞水无情，催人东去，去也添愁寂。", "鳞鸿方便，为人传个消息。"]'),
('song-ci-332','瑞鹤仙','曾觌','宋','宋词','song-ci','瑞鹤仙','[]','陡寒生翠幕。',127,'宋词/ci.song.8000.json','["陡寒生翠幕。", "冻云垂，缤纷飞雪初落。", "萦风度池阁。", "袅馀妍，时趁舞腰纤弱。", "江天漠漠。", "认残梅、吹散画角。", "正貂裘乍怯，黄昏院宇，入檐飘泊。", "依约。", "银河迢递，种玉群仙，共骖鸾鹤。", "东君未觉。", "先春绽，万花萼。", "向尊前、已喜丰年呈瑞，人间何事最乐。", "拥笙歌、绣阁低帷，纵欢细酌。"]'),
('song-ci-333','倾杯乐','曾觌','宋','宋词','song-ci','倾杯乐','[]','锦帐寒添，画檐雀噪，冻云布野。',133,'宋词/ci.song.8000.json','["锦帐寒添，画檐雀噪，冻云布野。", "望空际、瑶峰微吐，琼花初绽，江山如画。", "裁冰剪水装鸳瓦。", "杳旗亭路，依稀管弦台榭。", "倚小楼佳兴，一行珠帘不下。", "随缕板、歌声闲暇。", "傍翠袖云鬟、怜艳冶。", "似佯醉、不奈娇羞，浓欢旋学风雅。", "相暝色、双鸾舞罢。", "红兽暖、春生金斝。", "但殢饮，香雾卷、壶天不夜。"]'),
('song-ci-334','木兰花慢','曾觌','宋','宋词','song-ci','木兰花慢','[]','正枝头荔子，晚红皱、袅熏风。',122,'宋词/ci.song.8000.json','["正枝头荔子，晚红皱、袅熏风。", "对碧瓦迷云，青山似浪，返照浮空。", "高台称吟眺处，□繁华、清胜两无穷。", "帘卷榕阴暮合，万家香霭溟濛。", "年光冉冉逐飞鸿。", "叹雨迹云踪。", "渐暑退兰房，凉生象簟，知与谁同。", "临鸾晚妆初罢，怨清宵、好梦不相逢。", "看即天涯秋也，恨随一叶梧桐。"]'),
('song-ci-335','水调歌头','曾觌','宋','宋词','song-ci','水调歌头','[]','溪山多胜事，诗酒辨清游。',114,'宋词/ci.song.8000.json','["溪山多胜事，诗酒辨清游。", "主人为我，增茸台榭足凝眸。", "仿佛玉壶天地，隐见瀛洲风月，千首傲王侯。", "谁与共登眺，公子气横秋。", "记当年，曾共醉，庾公楼。", "一杯此际，重话前事逐东流。", "多谢兼金清唱，更拟重阳佳节，挼菊任扶头。", "但愿身长健，浮世拚悠悠。"]'),
('song-ci-336','水调歌头','曾觌','宋','宋词','song-ci','水调歌头','[]','图画上鳞阁，莫使鬓先秋。',114,'宋词/ci.song.8000.json','["图画上鳞阁，莫使鬓先秋。", "壮年豪气，无奈黯黯阵云浮。", "常记青油幕下，一矢聊城飞去，谈笑静边头。", "勋业出无意，非为快恩雠。", "卷龙韬，随凤诏，与时谋。", "朱幡皂盖南下，聊试海山州。", "邂逅故人相见，俯仰浮生今古，蝼蚁共王侯。", "万事偶然耳，风月恣嬉游。"]'),
('song-ci-337','水调歌头','曾觌','宋','宋词','song-ci','水调歌头','[]','长乐富山水，杖屡足追游。',114,'宋词/ci.song.8000.json','["长乐富山水，杖屡足追游。", "故人千里，西望双剑黯回眸。", "多谢扁舟乘兴，慰我天涯羁思，何必羡封侯。", "暮雨疏帘卷，爽气飒如秋。", "送征鸿，浮大白，倚危楼。", "参横月落，耿耿河汉近人流。", "堪叹人生离合，后日征鞍西去，别语却从头。", "老矣江边路，清兴漫悠悠。"]'),
('song-ci-338','醉蓬莱','曾觌','宋','宋词','song-ci','醉蓬莱','[]','向逍遥物外，造化工夫，做成幽致。',120,'宋词/ci.song.8000.json','["向逍遥物外，造化工夫，做成幽致。", "杳霭壶天，映满空苍翠。", "耸秀峰峦，媚春花木，对玉阶金砌。", "方丈瀛洲，非烟非雾，恍移平地。", "况值良辰，宴游时候，日永风和，暮春天气。", "金母龟台，傍碧桃阴里。", "地久天长，父尧子舜，灿绮罗佳会。", "一部仙韶，九重鸾仗，年年同醉。"]'),
('song-ci-339','满庭芳','曾觌','宋','宋词','song-ci','满庭芳','[]','冶态轻盈，香风摇荡，画栏淑景初长。',118,'宋词/ci.song.8000.json','["冶态轻盈，香风摇荡，画栏淑景初长。", "彩霞深处，明艳夺昭阳。", "试问沈香旧事，应劝我、莫负韶光。", "多情是，低徊顾影，云幕淡微凉。", "人间，春更好，一枝斜插，犹记疏狂。", "到如今潘鬓，暗点吴霜。", "乐事直须年少，何妨拚、一饮千觞。", "醺醺醉，壶天向晚，春思正悠扬。"]'),
('song-ci-340','燕山亭','曾觌','宋','宋词','song-ci','燕山亭','[]','河汉风情，庭户夜凉，皓月澄秋时候。',123,'宋词/ci.song.8000.json','["河汉风情，庭户夜凉，皓月澄秋时候。", "冰鉴乍开，跨海飞来，光掩满天星斗。", "四卷珠帘，渐移影、宝阶鸳甃。", "还又。", "看岁岁婵娟，向人依旧。", "朱邸高宴簪缨，正歌吹瑶台，舞翻宫袖。", "银管竞酬，棣萼相辉，风流古来谁有。", "玉笛横空，更听彻、裳霓三奏。", "难偶。", "拚醉倒、参横晓漏。"]'),
('song-ci-341','燕山亭','曾觌','宋','宋词','song-ci','燕山亭','[]','玉立明光，才业冠伦，汉历方承休运。',123,'宋词/ci.song.8000.json','["玉立明光，才业冠伦，汉历方承休运。", "江左奏功，塞垒宣威，紫绶几垂金印。", "岁晚归来，望丹极、新清氛祲。", "忠愤。", "著挠节朋俦，便成嘉遁。", "千载云海茫茫，记举目新亭，壮怀难尽。", "蝴蝶梦惊，化鹤飞还，荣华等闲一瞬。", "七十尊前，算畴昔、都无可恨。", "休问。", "长占取、朱颜绿鬓。"]'),
('song-ci-342','沁园春','曾觌','宋','宋词','song-ci','沁园春','[]','更漏迢迢，乍寒天气，画烛对床。',140,'宋词/ci.song.8000.json','["更漏迢迢，乍寒天气，画烛对床。", "正井梧飘砌，边鸿度月，故人何处，水远山长。", "老去功名，年来情绪，宽尽寒衣销旧香。", "除非是，仗蛮笺象管，时伴吟窗。", "词章。", "莫话行藏。", "且喜见捷书来帝乡。", "看锐师云合，妖氛电扫，随堤宫柳，依旧成行。", "梦绕他年，青门紫陌，对酒花前歌正当。", "空成恨，奈潘郎两鬓，新点吴霜。"]'),
('song-ci-343','喜迁莺','曾觌','宋','宋词','song-ci','喜迁莺','[]','七闽形胜。',125,'宋词/ci.song.8000.json','["七闽形胜。", "镇南纪会府，山川交映。", "箫鼓喧天，绮罗盈市，不负四时风景。", "共喜太平无事，岂料潢池不逞。", "殄群丑，看一鼓雷奔，沧溟波静。", "指纵诗书帅，曾到凤池，密勿陪几政。", "暂掩筹帏，催分战舰，总出智谋先定。", "想见捷书初上，尽道臣贤主圣。", "正图旧，听重宣丹诏，归调金鼎。"]'),
('song-ci-344','金人捧露盘','曾觌','宋','宋词','song-ci','金人捧露盘','[]','记神京、繁华地，旧游踪。',98,'宋词/ci.song.8000.json','["记神京、繁华地，旧游踪。", "正御沟、春水溶溶。", "平康巷陌，绣鞍金勒跃青骢。", "解衣沽酒醉弦管，柳绿花红。", "到如今、馀霜鬓，嗟前事、梦魂中。", "但寒烟、满目飞蓬。", "雕栏玉砌，空锁三十六离宫。", "塞笳惊起暮天雁，寂寞东风。"]'),
('song-ci-345','传言玉女','曾觌','宋','宋词','song-ci','传言玉女','[]','凤阙龙楼，清夜月华初照。',90,'宋词/ci.song.8000.json','["凤阙龙楼，清夜月华初照。", "万点星球，护花梢寒峭。", "华胥梦里，老去欢情终少。", "花愁醉闷，总消除了。", "紫陌嬉游，不似少年怀抱。", "珠帘十里，听笙箫声香。", "幽期密约，暗想浅颦轻笑。", "良时莫负，玉山频倒。"]'),
('song-ci-346','好事近','曾觌','宋','宋词','song-ci','好事近','[]','摇扬杏花风，迟日淡阴双阙。',53,'宋词/ci.song.8000.json','["摇扬杏花风，迟日淡阴双阙。", "丝管缓随檀板，看舞腰回雪。", "龙舟闲舣画桥边，须趁好花折。", "频劝御杯宜满，正清歌初阕。"]'),
('song-ci-347','好事近','曾觌','宋','宋词','song-ci','好事近','[]','一梦别长安，山路雨斜风细。',53,'宋词/ci.song.8000.json','["一梦别长安，山路雨斜风细。", "行到子陵滩畔，谢主人深意。", "多情低唱下梁尘，拚十分沈醉。", "去也为伊消瘦，悄不禁思忆。"]'),
('song-ci-348','好事近','曾觌','宋','宋词','song-ci','好事近','[]','霁雪好风光，恰是相逢时节。',53,'宋词/ci.song.8000.json','["霁雪好风光，恰是相逢时节。", "酒量不禁频劝，便醉倒人侧。", "严城更漏夜厌厌，应有断肠客。", "莫问落梅三弄，喜一枝曾折。"]'),
('song-ci-349','柳梢青','曾觌','宋','宋词','song-ci','柳梢青','[]','梅粉轻匀。',61,'宋词/ci.song.8000.json','["梅粉轻匀。", "和风布暖，香径无尘。", "凤阁凌虚，龙池澄碧，芳意鳞鳞。", "清时酒圣花神。", "对内苑、风光又新。", "一部仙韶，九重鸾仗，天上长春。"]'),
('song-ci-350','柳梢青','曾觌','宋','宋词','song-ci','柳梢青','[]','花柳争春。',61,'宋词/ci.song.8000.json','["花柳争春。", "湖山竟秀，恰近清明。", "绮席从容，兰舟摇曳，稳泛波平。", "君恩许宴簪缨。", "密座促、仍多故情。", "一部清音，两行红粉，醉入严城。"]'),
('song-ci-351','柳梢青','曾觌','宋','宋词','song-ci','柳梢青','[]','品雅风流，端端正正，堪人怜惜。',61,'宋词/ci.song.8000.json','["品雅风流，端端正正，堪人怜惜。", "因甚新来，眉儿不展，愁情如织。", "倡条冶叶无情，犹为他、千思万忆。", "据恁当初，真心实意，如何亏得。"]'),
('song-ci-352','春光好','曾觌','宋','宋词','song-ci','春光好','[]','胭脂腻，粉光轻。',52,'宋词/ci.song.8000.json','["胭脂腻，粉光轻。", "正新晴。", "枝上闹红无处著，近清明。", "仙娥进酒多情。", "向花下、相闹盈盈。", "不惜十分倾玉斝，惜凋零。"]'),
('song-ci-353','春光好','曾觌','宋','宋词','song-ci','春光好','[]','心下事，不思量。',52,'宋词/ci.song.8000.json','["心下事，不思量。", "自难忘。", "花底梦回春漠漠，恨偏长。", "闲日多少韶光。", "雕阑静、芳草池塘。", "风急落红留不住，又斜阳。"]'),
('song-ci-354','春光好','曾觌','宋','宋词','song-ci','春光好','[]','槐阴密，蔗浆寒。',52,'宋词/ci.song.8000.json','["槐阴密，蔗浆寒。", "荔枝丹。", "珍重主人怜客意，荐雕盘。", "多情翠袖凭栏。", "晚妆罢、谁与共欢。", "帘卷玉钩风细细，敛眉山。"]'),
('song-ci-355','减字木兰花','曾觌','宋','宋词','song-ci','减字木兰花','[]','一声杜宇。',52,'宋词/ci.song.8000.json','["一声杜宇。", "满地落红愁不语。", "国色春娇。", "不逐风前柳絮飘。", "珠帘休卷。", "爱惜龙香藏粉艳。", "胜友俱来。", "同醉君恩倒玉杯。"]'),
('song-ci-356','点绛唇','曾觌','宋','宋词','song-ci','点绛唇','[]','璧月香风，万家帘幕烟如昼。',50,'宋词/ci.song.8000.json','["璧月香风，万家帘幕烟如昼。", "闹蛾雪柳。", "人似梅花瘦。", "行乐清时，莫惜笙歌奏。", "更阑后。", "满斟金斗。", "且醉厌厌酒。"]'),
('song-ci-357','点绛唇','曾觌','宋','宋词','song-ci','点绛唇','[]','细雨斜风，上元灯火还空过。',50,'宋词/ci.song.8000.json','["细雨斜风，上元灯火还空过。", "下帘孤坐。", "老去知因果。", "风月词情，冷落教谁和。", "今忘我。", "静中看破。", "万事空花堕。"]'),
('song-ci-358','浣溪沙','曾觌','宋','宋词','song-ci','浣溪沙','[]','艳杏红芳透粉肌。',48,'宋词/ci.song.8000.json','["艳杏红芳透粉肌。", "沈香亭宴太真妃。", "新晴庭馆燕来迟。", "试抹么弦妆半掩，满斟绿醑袖交飞。", "九重天上捧金卮。"]'),
('song-ci-359','浣溪沙','曾觌','宋','宋词','song-ci','浣溪沙','["\u6d1e\u5ead\u6e56"]','元是昭阳宫里人。',48,'宋词/ci.song.8000.json','["元是昭阳宫里人。", "惊鸿宛转掌中身。", "只疑飞过洞庭云。", "按彻凉州莲步紧，好花风袅一枝新。", "画堂香暖不胜春。"]'),
('song-ci-360','浣溪沙','曾觌','宋','宋词','song-ci','浣溪沙','[]','绮陌寻芳惜少年。',48,'宋词/ci.song.8000.json','["绮陌寻芳惜少年。", "长楸走马著金鞭。", "玉楼春醉杏花前。", "憔悴如今谁作伴，别离还近养花天。", "碧云凝处忆婵娟。"]'),
('song-ci-361','浣溪沙','曾觌','宋','宋词','song-ci','浣溪沙','[]','一扇熏风入座凉。',48,'宋词/ci.song.8000.json','["一扇熏风入座凉。", "轻云微雨弄晴光。", "绿团梅子未成黄。", "渐近日长愁闷处，更堪羁旅送归艎。", "乱山重叠水茫茫。"]'),
('song-ci-362','钗头凤・撷坊词','曾觌','宋','宋词','song-ci','钗头凤・撷坊词','[]','华灯闹。',76,'宋词/ci.song.8000.json','["华灯闹。", "银蟾照。", "万家罗幕香风透。", "金尊侧。", "花颜色。", "醉里人人，向人情极。", "惜惜惜。", "春寒峭。", "腰肢小。", "鬓云斜亸蛾儿袅。", "清宵寂。", "香闺隔。", "好梦难寻，雨踪云迹。", "忆忆忆。"]'),
('song-ci-363','诉衷情','曾觌','宋','宋词','song-ci','诉衷情','[]','建章宫殿晚生寒。',54,'宋词/ci.song.8000.json','["建章宫殿晚生寒。", "飞雪点朱阑。", "舞腰缓随檀板，轻絮殢春闲。", "愁思乱，酒肠悭。", "漏将残。", "玉人今夜，滴粉搓酥，应敛眉山。"]'),
('song-ci-364','诉衷情','曾觌','宋','宋词','song-ci','诉衷情','[]','半钩珠箔小扬州。',54,'宋词/ci.song.8000.json','["半钩珠箔小扬州。", "春色在重楼。", "曾醉玳筵歌舞，楚梦苦难留。", "情脉脉，恨悠悠。", "几时休。", "大都人世，会少离多，总是闲愁。"]'),
('song-ci-365','诉衷情','曾觌','宋','宋词','song-ci','诉衷情','[]','晚妆初试蕊珠宫。',54,'宋词/ci.song.8000.json','["晚妆初试蕊珠宫。", "随步异香浓。", "檀槽缓垂鸾带，纤指拈春葱。", "莺语巧，上林中。", "正娇慵。", "暂教花下，帘影微开，多谢东风。"]'),
('song-ci-366','诉衷情','曾觌','宋','宋词','song-ci','诉衷情','[]','兰亭曲水擅风流。',54,'宋词/ci.song.8000.json','["兰亭曲水擅风流。", "移宴向清秋。", "黄花未应憔悴，盏面尚堪浮。", "围艳质，发歌喉。", "细相酬。", "明年此会，主人还是，在凤池头。"]'),
('song-ci-367','踏莎行','曾觌','宋','宋词','song-ci','踏莎行','[]','翠幄成阴，谁家帘幕。',82,'宋词/ci.song.8000.json','["翠幄成阴，谁家帘幕。", "绮罗香拥处、觥筹错。", "清和将近，□春寒更薄。", "高歌看簌簌、梁尘落。", "好景良辰，人生行乐。", "金杯无奈是、苦相虐。", "残红飞尽，袅垂杨轻弱。", "来岁断不负、莺花约。"]'),
('song-ci-368','眼儿媚','曾觌','宋','宋词','song-ci','眼儿媚','[]','花近清明晚风寒。',58,'宋词/ci.song.8000.json','["花近清明晚风寒。", "锦幄兽香残。", "醺醺醉里，匆匆相见，重听哀弹。", "春情入指莺声碎，危柱不胜弦。", "十分得意，一场轻梦，淡月阑干。"]'),
('song-ci-369','眼儿媚','曾觌','宋','宋词','song-ci','眼儿媚','[]','重劝离觞泪相看。',58,'宋词/ci.song.8000.json','["重劝离觞泪相看。", "寂寞上征鞍。", "临行欲话，风流心事，万绪千端。", "春光漫漫人千里，归梦绕长安。", "不堪向晚，孤城吹角，回首关山。"]'),
('song-ci-370','蝶恋花','曾觌','宋','宋词','song-ci','蝶恋花','[]','翠箔垂云香喷雾。',70,'宋词/ci.song.8000.json','["翠箔垂云香喷雾。", "年少疏狂，载酒寻芳路。", "多少惜花春意绪。", "劝人金盏歌金缕。", "桃李飘零风景暮。", "只有闲愁，不逐流年去。", "旧事而今谁共语。", "画楼空指行云处。"]'),
('song-ci-371','蝶恋花','曾觌','宋','宋词','song-ci','蝶恋花','[]','御柳风柔春正暖。',70,'宋词/ci.song.8000.json','["御柳风柔春正暖。", "紫殿朱楼，赫奕祥光远。", "十二玉龙迎凤辇。", "香腾锦绣闻弦管。", "扇却双鸾开宝宴。", "绿绕红围，宣劝金卮满。", "万岁千秋流宠眷。", "此身欲备昭阳燕。"]'),
('song-ci-372','隔浦莲・隔浦莲近拍','曾觌','宋','宋词','song-ci','隔浦莲・隔浦莲近拍','[]','凉秋湖上过雨。',88,'宋词/ci.song.8000.json','["凉秋湖上过雨。", "作意回商素。", "暗绿翻轻盖，萧然姑射俦侣。", "妆脸宜淡伫。", "红衣妒。", "步袜凌波去。", "异香度。", "天教占断，风汀月浦烟渚。", "纤尘不到，梦绕玉壶清处。", "多少芳心待怨诉。", "无语。", "飞来一片鸥鹭。"]'),
('song-ci-373','浪淘沙','曾觌','宋','宋词','song-ci','浪淘沙','[]','一线海门来。',64,'宋词/ci.song.8000.json','["一线海门来。", "雪喷云开。", "崑山移玉下瑶台。", "卷地西风吹不断，直到蓬莱。", "羯鼓噪春雷。", "鼍舞蛟回。", "歌楼鼓吹夕阳催。", "今古清愁流不尽，都一樽罍。"]'),
('song-ci-374','蓦山溪','曾觌','宋','宋词','song-ci','蓦山溪','[]','催花小雨，轻把香尘洒。',102,'宋词/ci.song.8000.json','["催花小雨，轻把香尘洒。", "帘卷水亭风，梅影转、夕阳初下。", "靓妆窥鉴，鸳甃湛清漪，浮暗麝，剪芳琼，消得连城价。", "玉楼十二，寒怯铢衣挂。", "曾是绿华仙，眷馀情、新词如画。", "花随人圣，须信世无双，腾凤吹，驻銮舆，堪与瑶池亚。"]'),
('song-ci-375','蓦山溪','曾觌','宋','宋词','song-ci','蓦山溪','[]','凋红减翠，正是清秋杪。',102,'宋词/ci.song.8000.json','["凋红减翠，正是清秋杪。", "深院袅香风，看梨花、一枝开早。", "珑璁映面，依约认娇颦，天淡淡，月溶溶，春意知多少。", "清明池馆，芳信年年好。", "更向五侯家，把江梅、风光占了。", "休教寂寞，辜负向人心，檀板响，宝杯倾，潘鬓从他老。"]'),
('song-ci-376','感皇恩','曾觌','宋','宋词','song-ci','感皇恩','[]','依旧惜春心，花枝常好。',81,'宋词/ci.song.8000.json','["依旧惜春心，花枝常好。", "只恐尊前被花笑。", "少年青鬓，耐得几番重到。", "旧欢重记省，如天杳。", "绮陌青门，斜阳芳草。", "今古销沈送人老。", "帝城春事，又是等闲来了。", "乱红随过雨，莺声悄。"]'),
('song-ci-377','阮郎归','曾觌','宋','宋词','song-ci','阮郎归','[]','柳阴庭馆占风光。',56,'宋词/ci.song.8000.json','["柳阴庭馆占风光。", "呢喃清昼长。", "碧波新涨小池塘。", "双双蹴水忙。", "萍散漫，絮飘扬。", "轻盈体态狂。", "为怜流去落红香。", "衔将归画梁。"]'),
('song-ci-378','鹧鸪天','曾觌','宋','宋词','song-ci','鹧鸪天','[]','龙驭亲迎玉辇来。',64,'宋词/ci.song.8000.json','["龙驭亲迎玉辇来。", "江梅枝上雪培堆。", "东风上苑春光到，更放金莲匝地开。", "腾凤吹，进瑶杯。", "两宫交劝正欢谐。", "父慈子孝从今数，准拟开筵一万回。"]'),
('song-ci-379','鹧鸪天','曾觌','宋','宋词','song-ci','鹧鸪天','[]','桃李飘零春已深。',64,'宋词/ci.song.8000.json','["桃李飘零春已深。", "可怜轻负惜花心。", "尊前赖有红千叠，窗外休惊绿满林。", "灯灼灼，醉沈沈。", "笙歌丛里酒频斟。", "留欢且莫匆匆去，怅望春归何处寻。"]'),
('song-ci-380','鹧鸪天','曾觌','宋','宋词','song-ci','鹧鸪天','[]','每上春泥向晓乾。',64,'宋词/ci.song.8000.json','["每上春泥向晓乾。", "花间幽鸟舞姗姗。", "年华不管人将老，门外东风依旧寒。", "投簪易，息机难。", "鹿门归路不曾关。", "羡君早觉无生法，识破南柯一梦间。"]'),
('song-ci-381','鹧鸪天','曾觌','宋','宋词','song-ci','鹧鸪天','[]','故乡寒食醉酡颜。',64,'宋词/ci.song.8000.json','["故乡寒食醉酡颜。", "秋千彩索眩斓斑。", "如今头上灰三斗，赢得疏慵到处闲。", "锺已动，漏将残。", "浮生犹恨别离难。", "镬汤转作清凉地，只在人心那样看。"]'),
('song-ci-382','定风波','曾觌','宋','宋词','song-ci','定风波','[]','捍拨金泥雅制新。',73,'宋词/ci.song.8000.json','["捍拨金泥雅制新。", "紫檀槽映小腰身。", "娅姹雏莺相对语。", "欣睹。", "上林花底暖生春。", "飒飒胡沙飞指下。", "休讶。", "一般奇绝称精神。", "向道曲终多少意。", "须记。", "昭阳殿里旧承恩。"]'),
('song-ci-383','定风波','曾觌','宋','宋词','song-ci','定风波','[]','上苑秾芳初雨晴。',73,'宋词/ci.song.8000.json','["上苑秾芳初雨晴。", "香风袅袅泛轩楹。", "犹记洛阳开小宴。", "娇面。", "粉光依约认倾城。", "流落江南重此会。", "相对。", "金蕉蘸甲十分倾。", "怕见人间春更好。", "向道。", "如今老去尚多情。"]'),
('song-ci-384','定风波','曾觌','宋','宋词','song-ci','定风波','[]','极目秋光夕照开。',70,'宋词/ci.song.8000.json','["极目秋光夕照开。", "潮头初自海门来。", "杳杳江天横一线。", "如练。", "疾驱千骑鼓声催。", "杰槛翠飞争徙倚。", "一行新雁去仍回。", "翠袖半空歌笑迥。", "低映。", "十分沈醉劝金杯。"]'),
('song-ci-385','定风波','曾觌','宋','宋词','song-ci','定风波','[]','天语丁宁对未央。',70,'宋词/ci.song.8000.json','["天语丁宁对未央。", "少摅素志向荆襄。", "烜赫家声今不坠。", "英伟。", "风姿飒爽紫髯郎。", "别酒一杯君莫阻。", "烛前粉艳俨成行。", "领略大堤花好处。", "无绪。", "也应回首水云乡。"]'),
('song-ci-386','南乡子','曾觌','宋','宋词','song-ci','南乡子','[]','霜月晚云收。',66,'宋词/ci.song.8000.json','["霜月晚云收。", "萧瑟西风满院秋。", "雅会难期嗟易散，迟留。", "把酒听歌且劝酬。", "万事拚悠悠。", "只有情亲意未休。", "后夜扁舟烟浪里，回头。", "叶叶丹枫总是愁。"]'),
('song-ci-387','忆秦娥','曾觌','宋','宋词','song-ci','忆秦娥','[]','晴空碧。',56,'宋词/ci.song.8000.json','["晴空碧。", "吴山染就丹青色。", "丹青色。", "西风摇落，可堪凄恻。", "世情冷暖君应识。", "鬓边各自侵寻白。", "侵寻白。", "江南江北，几时归得。"]'),
('song-ci-388','忆秦娥','曾觌','宋','宋词','song-ci','忆秦娥','[]','西风节。',56,'宋词/ci.song.8000.json','["西风节。", "碧云卷尽秋宵月。", "秋宵月。", "关河千里，照人离别。", "尊前俱是天涯客。", "那堪三载遥相忆。", "遥相忆。", "年光依旧，渐成华发。"]'),
('song-ci-389','忆秦娥','曾觌','宋','宋词','song-ci','忆秦娥','[]','暮云蹙。',56,'宋词/ci.song.8000.json','["暮云蹙。", "小亭带雪斟醽醁。", "斟醽醁。", "一声羌管，落梅蔌蔌。", "舞衣旋趁霓裳曲。", "倚阑相对人如玉。", "人如玉。", "锦屏罗幌，看成不足。"]'),
('song-ci-390','忆秦娥','曾觌','宋','宋词','song-ci','忆秦娥','[]','正飞雪。',56,'宋词/ci.song.8000.json','["正飞雪。", "园林一样梨花白。", "梨花白。", "画堂帘卷，暖生春色。", "嵇康转轴声幽噎。", "新来多病娇无力。", "娇无力。", "浅红转黛，自然标格。"]'),
('song-ci-391','忆秦娥','曾觌','宋','宋词','song-ci','忆秦娥','[]','风萧瑟。',56,'宋词/ci.song.8000.json','["风萧瑟。", "邯郸古道伤行客。", "伤行客。", "繁华一瞬，不堪思忆。", "丛台歌舞无消息。", "金尊玉管空尘迹。", "空尘迹。", "连天草树，暮云凝碧。"]'),
('song-ci-392','鹊桥仙','曾觌','宋','宋词','song-ci','鹊桥仙','[]','菊花小摘，西风斜照，帘影轻笼暝色。',68,'宋词/ci.song.8000.json','["菊花小摘，西风斜照，帘影轻笼暝色。", "玉尊侧倒莫辞空，□满座、宾朋弁侧。", "乡邦万里，北来年少，几个如今在得。", "扶头一任且留连，叹人世、光阴半百。"]'),
('song-ci-393','清平乐','曾觌','宋','宋词','song-ci','清平乐','[]','松姿不老。',54,'宋词/ci.song.8000.json','["松姿不老。", "独立蓬莱杪。", "风卷流苏香雾晓。", "又是江梅开了。", "丹青早画麒麟。", "貂蝉自属王门。", "闻道碧桃花绽，一枝枝祝千春。"]'),
('song-ci-394','长相思','曾觌','宋','宋词','song-ci','长相思','[]','清夜长。',44,'宋词/ci.song.8000.json','["清夜长。", "泛玉觞。", "照座江梅花正芳。", "风传细细香。", "围艳妆。", "留醉乡。", "一曲清歌声绕梁。", "尊前人断肠。"]'),
('song-ci-395','虞美人','曾觌','宋','宋词','song-ci','虞美人','[]','芙蓉池畔都开遍。',66,'宋词/ci.song.8000.json','["芙蓉池畔都开遍。", "又是西风晚。", "霁天碧净暝云收。", "渐看一轮冰魄、冷悬秋。", "闽山层叠迷归路。", "把酒宽愁绪。", "旧欢新恨几凄凉。", "暗想瀛洲何处、梦悠扬。"]'),
('song-ci-396','采桑子','曾觌','宋','宋词','song-ci','采桑子','[]','清明池馆晴还雨，绿涨溶溶。',52,'宋词/ci.song.8000.json','["清明池馆晴还雨，绿涨溶溶。", "花里游蜂。", "宿粉栖香锦绣中。", "玉箫声断人何处，依旧春风。", "万点愁红。", "乱逐烟波总向东。"]'),
('song-ci-397','朝中措','曾觌','宋','宋词','song-ci','朝中措','[]','画堂帘卷兽香浓。',57,'宋词/ci.song.8000.json','["画堂帘卷兽香浓。", "花上雪玲珑。", "平地十州三岛，蟠桃已试春红。", "清朝旧德，仙姿难老，主眷方隆。", "烂醉笙歌丛里，年年先占春风。"]'),
('song-ci-398','朝中措','曾觌','宋','宋词','song-ci','朝中措','[]','画堂栏槛占韶光。',57,'宋词/ci.song.8000.json','["画堂栏槛占韶光。", "端不负年芳。", "依倚东风向晓，数行浓淡仙妆。", "停杯醉折，多情多恨，冶艳真香。", "只恐去为云雨，梦魂时恼襄王。"]'),
('song-ci-399','朝中措','曾觌','宋','宋词','song-ci','朝中措','[]','金沙架上日璁珑。',57,'宋词/ci.song.8000.json','["金沙架上日璁珑。", "浓绿衬轻红。", "花下两行红袖，直疑春在壶中。", "如今尚觉，惜花爱酒，依旧情浓。", "无限少年心绪，从教醉倒东风。"]'),
('song-ci-400','朝中措','曾觌','宋','宋词','song-ci','朝中措','[]','休论社燕与秋鸿。',57,'宋词/ci.song.8000.json','["休论社燕与秋鸿。", "时节太匆匆。", "海上一番微雨，朱门浓绿阴中。", "主人情厚，金杯满泛，且共从容。", "莫问莺花俱老，今朝犹是春风。"]'),
('song-ci-401','朝中措','曾觌','宋','宋词','song-ci','朝中措','["\u897f\u6e56"]','西湖南北旧游空。',57,'宋词/ci.song.8000.json','["西湖南北旧游空。", "谁料一尊同。", "回首四年间事，浑如飞絮濛濛。", "林花谢了，明年春到，依旧芳容。", "惟有朱颜绿鬓，暗随流水常东。"]'),
('song-ci-402','朝中措','曾觌','宋','宋词','song-ci','朝中措','[]','双溪楼上凭栏时。',57,'宋词/ci.song.8000.json','["双溪楼上凭栏时。", "潋滟泛金卮。", "醉到闹花深处，歌声遏住云飞。", "风流太守，鸾台家世，玉鉴丰姿。", "行奉紫泥褒诏，要看击浪天池。"]'),
('song-ci-403','朝中措','曾觌','宋','宋词','song-ci','朝中措','[]','雕车南陌碾香尘。',57,'宋词/ci.song.8000.json','["雕车南陌碾香尘。", "一梦尚如新。", "回首旧游何在，柳烟花雾迷春。", "如今霜鬓，愁停短棹，懒傍清尊。", "二十四桥风月，寻思只有消魂。"]'),
('song-ci-404','朝中措','曾觌','宋','宋词','song-ci','朝中措','[]','功名虽未压英游。',57,'宋词/ci.song.8000.json','["功名虽未压英游。", "一种旧风流。", "人世百年须到，如今七十春秋。", "当时帷幄，貂珰贵重，誉蔼朋俦。", "赢得尊前沈醉，浮华付去悠悠。"]'),
('song-ci-405','南柯子・南歌子','曾觌','宋','宋词','song-ci','南柯子・南歌子','[]','璧月窥红粉，金莲映彩山。',62,'宋词/ci.song.8000.json','["璧月窥红粉，金莲映彩山。", "东风丝管满长安。", "移下十洲三岛、在人间。", "两两人初散，厌厌夜向阑。", "倦妆残醉怯春寒。", "手拈玉梅无绪、倚阑干。"]'),
('song-ci-406','南柯子・南歌子','曾觌','宋','宋词','song-ci','南柯子・南歌子','[]','粉黛娉婷艳，芝兰笑语香。',62,'宋词/ci.song.8000.json','["粉黛娉婷艳，芝兰笑语香。", "延平春色斗芬芳。", "不管清宵更漏、听霓裳。", "烛暗人方醉，杯传意更长。", "可堪羁客九回肠。", "萧瑟一檐风雨、过横塘。"]'),
('song-ci-407','南柯子・南歌子','曾觌','宋','宋词','song-ci','南柯子・南歌子','[]','绿阴侵檐净，红榴照眼明。',62,'宋词/ci.song.8000.json','["绿阴侵檐净，红榴照眼明。", "主人开宴出倾城。", "正是雨馀天气、暑风清。", "别酒殷勤竟，危弦要妙声。", "年年相见岂无情。", "后日暮云回首、奈乘行。"]'),
('song-ci-408','南柯子・南歌子','曾觌','宋','宋词','song-ci','南柯子・南歌子','[]','共禀阴阳数，谁知造化工。',62,'宋词/ci.song.8000.json','["共禀阴阳数，谁知造化工。", "安闲百计总输公。", "掩映芙蓉花径、郡城东。", "风月三秋兴，尊罍一笑同。", "新词佳丽见情通。", "更唤雪儿、低唱慰衰容。"]'),
('song-ci-409','玉楼春','曾觌','宋','宋词','song-ci','玉楼春','[]','江天暝色伤心目。',64,'宋词/ci.song.8000.json','["江天暝色伤心目。", "冻鹊争投林下竹。", "四垂云幕一襟寒，片片飞花轻镂玉。", "美人试按新翻曲。", "点破舞裙春草绿。", "融尊侧倒也思量，清坐有人寒起粟。"]'),
('song-ci-410','江神子・江城子','曾觌','宋','宋词','song-ci','江神子・江城子','[]','故人情分转绸缪。',86,'宋词/ci.song.8000.json','["故人情分转绸缪。", "小窗幽。", "话离愁。", "海阔天遥，鸿雁两悠悠。", "今日相逢谁较健，应怪我、鬓先秋。", "功名淅米在刀头。", "壮心休。", "弊貂裘。", "何事留欢，不竟漾扁舟。", "桃李春风将近也，如后会、醉青楼。"]'),
('song-ci-411','踏莎行','曾觌','宋','宋词','song-ci','踏莎行','[]','凤翼双双，金泥细细。',68,'宋词/ci.song.8000.json','["凤翼双双，金泥细细。", "四弦斜抱拢纤指。", "紫檀香暖转春雷，嘈嘈切切声相继。", "弱柳腰肢，轻云情思。", "曲中多少风流事。", "红牙拍碎少年心，可怜辜负尊前意。"]'),
('song-ci-412','生查子','曾觌','宋','宋词','song-ci','生查子','[]','温柔乡内人，翠微阁中女。',48,'宋词/ci.song.8000.json','["温柔乡内人，翠微阁中女。", "颜笑洛阳花，肌莹荆山玉。", "东君深有情，解与花为主。", "移傍楚峰居，容易为云雨。"]'),
('song-ci-413','青玉案','曾觌','宋','宋词','song-ci','青玉案','[]','蒲葵佳节初经雨。',80,'宋词/ci.song.8000.json','["蒲葵佳节初经雨。", "正栏槛、薰风度。", "满泛香蒲斟醁醑。", "故人情厚，艳歌娇舞。", "总是留宾处。", "榴花照眼江天暮。", "醉里春情荡轻絮。", "岂止卷帘通一顾。", "今宵酒醒，一襟风露。", "梦指高唐去。"]'),
('song-ci-414','青玉案','曾觌','宋','宋词','song-ci','青玉案','[]','乘鸾影里冰轮度。',80,'宋词/ci.song.8000.json','["乘鸾影里冰轮度。", "秋空净、南楼暮。", "袅袅天风吹玉兔。", "今宵只在，旧时圆处。", "往事难重数。", "天涯几见新霜露。", "怎得朱颜旧如故。", "对酒临风慵作赋。", "蓝桥烟浪，故人千里，梦也无由做。"]'),
('song-ci-415','菩萨蛮','曾觌','宋','宋词','song-ci','菩萨蛮','[]','杏花寒食佳期近。',52,'宋词/ci.song.8000.json','["杏花寒食佳期近。", "一帘烟雨琴书润。", "砌下水潺潺。", "玉笙吹暮寒。", "阳台云易散。", "往事寻思懒。", "花底醉相扶。", "当时人在无。"]'),
('song-ci-416','菩萨蛮','曾觌','宋','宋词','song-ci','菩萨蛮','[]','云烟漠漠秋容老。',52,'宋词/ci.song.8000.json','["云烟漠漠秋容老。", "茅檐映水人家好。", "林叶未凋疏。", "远山横有无。", "平生耕钓事。", "若个安身事。", "劝君早归来。", "碧香新瓮开。"]'),
('song-ci-417','西江月','曾觌','宋','宋词','song-ci','西江月','[]','焕烂莲灯高下，参差梅影横斜。',58,'宋词/ci.song.8000.json','["焕烂莲灯高下，参差梅影横斜。", "凭栏一目尽天涯。", "雪月交辉清夜。", "莫惜柔荑劝酒，从教醉脸红霞。", "烂银宫阙对仙家。", "一段风光如画。"]'),
('song-ci-418','西江月','曾觌','宋','宋词','song-ci','西江月','[]','桂苑旋生凉思，银河左界秋高。',58,'宋词/ci.song.8000.json','["桂苑旋生凉思，银河左界秋高。", "纤尘不动湛清霄。", "皓月照人偏好。", "诗为情多却减，酒因愁里难销。", "一声羌管梦魂劳。", "可惜风光虚老。"]'),
('song-ci-419','西江月','曾觌','宋','宋词','song-ci','西江月','[]','醉伴三千珠履，如登十二琼楼。',58,'宋词/ci.song.8000.json','["醉伴三千珠履，如登十二琼楼。", "壶天澄爽露华秋。", "滟滟金波酾酒。", "罗扇不随恩在，佳时须要人酬。", "麒麟阁画为谁留。", "只见浮生白首。"]'),
('song-ci-420','绣带儿・好女儿','曾觌','宋','宋词','song-ci','绣带儿・好女儿','[]','潇洒陇头春。',55,'宋词/ci.song.8000.json','["潇洒陇头春。", "取次一枝新。", "还是东风来也，犹作未归人。", "微月淡烟村。", "谩伫立、惆怅黄昏。", "暮寒香细，疏英几点，尽奈销魂。"]'),
('song-ci-421','卜算子','曾觌','宋','宋词','song-ci','卜算子','[]','数尽万般花，不比梅花韵。',52,'宋词/ci.song.8000.json','["数尽万般花，不比梅花韵。", "雪压风欺恁地寒，划地清喷香。", "半醉折归来，插向乌云鬓。", "不是愁人闷带花，花带愁人闷。"]'),
('song-ci-422','柳梢青','曾觌','宋','宋词','song-ci','柳梢青','[]','雨过风微。',61,'宋词/ci.song.8000.json','["雨过风微。", "温泉浴倦，妃子妆迟。", "翠袖牵云，朱唇得酒，脸晕胭脂。", "年年海燕新归。", "怎奈向、黄昏恁时。", "倚遍琼干，烧残银烛，花又争知。"]'),
('song-ci-423','柳梢青','曾觌','宋','宋词','song-ci','柳梢青','[]','□杏堂前，清深窗外，宛似蓬瀛。',61,'宋词/ci.song.8000.json','["□杏堂前，清深窗外，宛似蓬瀛。", "珠翠分行，笙歌争奏，音韵清新。", "玉皇金母情亲。", "劝醁醑、更酬嗣君。", "地久天长，花朝月夕，天上长春。"]'),
('song-ci-424','柳梢青','曾觌','宋','宋词','song-ci','柳梢青','[]','小宴清秋。',61,'宋词/ci.song.8000.json','["小宴清秋。", "霎时见了，雨散云收。", "柳絮轻柔，梅花闲澹，宫院风流。", "空教梦绕青楼。", "待说个、相思又休。", "无奈情何，不来眼底，常在心头。"]'),
('song-ci-425','醉落魄・一斛珠','曾觌','宋','宋词','song-ci','醉落魄・一斛珠','[]','情深恨切。',67,'宋词/ci.song.8000.json','["情深恨切。", "忆伊诮没些休歇。", "百般做处百厮惬。", "管是前生，曾负你冤业。", "临岐不忍匆匆别。", "两行珠泪流红颊。", "关山渐远音书绝。", "一个心肠，两处对风月。"]'),
('song-ci-426','鹊桥仙','曾觌','宋','宋词','song-ci','鹊桥仙','[]','娇波媚靥，尊前席上，只是寻常梳裹。',68,'宋词/ci.song.8000.json','["娇波媚靥，尊前席上，只是寻常梳裹。", "温柔伶俐总天然，没半掏、教人看破。", "从来可恁，痴迷著相，百计消除不过。", "烟花不是不曾经，放不下、唯他一个。"]'),
('song-ci-427','清平乐','曾觌','宋','宋词','song-ci','清平乐','[]','艳苞初拆。',54,'宋词/ci.song.8000.json','["艳苞初拆。", "偏借东君力。", "上苑梨花风露湿。", "新染胭脂颜色。", "玉人小立帘栊。", "轻匀媚脸妆红。", "斜插一枝云鬓，看谁剩□春风。"]'),
('song-ci-428','诉衷情','曾觌','宋','宋词','song-ci','诉衷情','[]','闲窗静院漏声长。',54,'宋词/ci.song.8000.json','["闲窗静院漏声长。", "金鸭冷残香。", "几番梦回枕上，飞絮恨悠扬。", "身在此，意伊行。", "㬠思量。", "不言不语，几许闲情，月上回廊。"]'),
('song-ci-429','浣溪沙','曾觌','宋','宋词','song-ci','浣溪沙','[]','谷雨郊园喜弄晴。',48,'宋词/ci.song.8000.json','["谷雨郊园喜弄晴。", "满林璀璨缀繁星。", "筠篮新采绛珠倾。", "樊素扇边歌未发，葛洪炉内药初成。", "金盘乳酪齿流冰。"]'),
('song-ci-430','壶中天慢・念奴娇','曾觌','宋','宋词','song-ci','壶中天慢・念奴娇','[]','素飙漾碧，看天衢稳送、一轮明月。',120,'宋词/ci.song.8000.json','["素飙漾碧，看天衢稳送、一轮明月。", "翠水瀛壶人不到，比似世间秋别。", "玉手瑶笙，一时同色，小按霓裳叠。", "天津桥上，有人偷记新阙。", "当日谁幻银桥，阿瞒儿戏，一笑成痴绝。", "肯信群仙高宴处，移下水晶宫阙。", "云海尘清，山河影满，桂冷吹香雪。", "何劳玉斧，金瓯千古无缺。"]'),
('song-ci-431','点绛唇','黄公度','宋','宋词','song-ci','点绛唇','[]','嫩绿娇红，砌成别恨千千斗。',50,'宋词/ci.song.8000.json','["嫩绿娇红，砌成别恨千千斗。", "短亭回首。", "不是缘春瘦。", "一曲阳关，杯送纤纤手。", "还知否。", "凤池归后。", "无路陪尊酒。"]'),
('song-ci-432','千秋岁','黄公度','宋','宋词','song-ci','千秋岁','[]','郁葱佳气。',87,'宋词/ci.song.8000.json','["郁葱佳气。", "天降麒麟瑞。", "回首处，江城外。", "一麾遗爱在，万口欢声沸。", "人乍远，危楼目断天无际。", "五马徘徊地。", "春色随归旆。", "寿水绿，壶山翠。", "风轻香篆直，日暖歌喉脆。", "椒觞举，人人尽祝千秋岁。"]'),
('song-ci-433','菩萨蛮','黄公度','宋','宋词','song-ci','菩萨蛮','[]','高楼目断南来翼。',52,'宋词/ci.song.8000.json','["高楼目断南来翼。", "玉人依旧无消息。", "愁绪促眉端。", "不随衣带宽。", "萋萋天外草。", "何处春归早。", "无语凭栏杆。", "竹声生暮寒。"]'),
('song-ci-434','青玉案','黄公度','宋','宋词','song-ci','青玉案','[]','邻鸡不管离怀苦。',80,'宋词/ci.song.8000.json','["邻鸡不管离怀苦。", "又还是、催人去。", "回首高城音信阻。", "霜桥月馆，水村烟市，总是思君处。", "裛残别袖燕支雨。", "谩留得、愁千缕。", "欲倩归鸿分付与。", "鸿飞不住。", "倚栏无语。", "独立长天暮。"]'),
('song-ci-435','卜算子','黄公度','宋','宋词','song-ci','卜算子','[]','寒透小窗纱，漏断人初醒。',52,'宋词/ci.song.8000.json','["寒透小窗纱，漏断人初醒。", "翡翠屏间拾落钗，背立残釭影。", "欲去更踟蹰，离恨终难整。", "陇首流泉不忍闻，月落双溪冷。"]'),
('song-ci-436','好事近','黄公度','宋','宋词','song-ci','好事近','[]','湖上送残春，已负别时归约。',53,'宋词/ci.song.8000.json','["湖上送残春，已负别时归约。", "好在故园桃李，为谁开谁落。", "还家应是荔支天，浮蚁要人酌。", "莫把舞裙歌扇，便等闲抛却。"]'),
('song-ci-437','菩萨蛮','黄公度','宋','宋词','song-ci','菩萨蛮','[]','眉尖早识愁滋味。',52,'宋词/ci.song.8000.json','["眉尖早识愁滋味。", "娇羞未解论心事。", "试问忆人不。", "无言但点头。", "嗔人归不早。", "故把金杯恼。", "醉看舞时腰。", "还如旧日娇。"]'),
('song-ci-438','卜算子','黄公度','宋','宋词','song-ci','卜算子','[]','薄宦各东西，往事随风雨。',54,'宋词/ci.song.8000.json','["薄宦各东西，往事随风雨。", "先自离歌不忍闻，又何况、春将暮。", "愁共落花多，人逐征鸿去。", "君向潇湘我向秦，后会知何处。"]'),
('song-ci-439','眼儿媚','黄公度','宋','宋词','song-ci','眼儿媚','[]','一枝雪里冷光浮。',58,'宋词/ci.song.8000.json','["一枝雪里冷光浮。", "空自许清流。", "如今憔悴，蛮烟瘴雨，谁肯寻搜。", "昔年曾共孤芳醉，争插玉钗头。", "天涯幸有，惜花人在，杯酒相酬。"]'),
('song-ci-440','朝中措','黄公度','宋','宋词','song-ci','朝中措','[]','幽香冷艳缀疏枝。',57,'宋词/ci.song.8000.json','["幽香冷艳缀疏枝。", "横影卧霜溪。", "清楚浑如南郭，孤高胜似东篱。", "岁寒风味，黄花尽处，密雪飞时。", "不比三春桃李，芳菲急在人知。"]'),
('song-ci-441','朝中措','黄公度','宋','宋词','song-ci','朝中措','[]','屑瑶飘絮满层空。',57,'宋词/ci.song.8000.json','["屑瑶飘絮满层空。", "人在广寒宫。", "已觉楼台改观，渐看桃李春融。", "一城和气，宾筵不夜，舞态回风。", "正是为霖手段，南来先做年丰。"]'),
('song-ci-442','一翦梅','黄公度','宋','宋词','song-ci','一翦梅','[]','冷艳幽香冰玉姿。',72,'宋词/ci.song.8000.json','["冷艳幽香冰玉姿。", "占断孤高，压尽芳菲。", "东君先暖向南枝。", "要使天涯，管领春归。", "不受人间莺蝶知。", "长是年年，雪约霜期。", "嫣然一笑百花迟。", "调鼎行看，结子黄时。"]'),
('song-ci-443','满庭芳','黄公度','宋','宋词','song-ci','满庭芳','[]','一径叉分，三亭鼎峙，小园别是清幽。',114,'宋词/ci.song.8000.json','["一径叉分，三亭鼎峙，小园别是清幽。", "曲阑低槛，春色四时留。", "怪石参差卧虎，长松偃蹇拿虬。", "携筇晚，风来万里，冷撼一天秋。", "优游。", "销永昼，琴尊左右，宾主风流。", "且偷闲，不妨身在南州。", "故国归帆隐隐，西崑往事悠悠。", "都休问，金钗十二，满酌听轻讴。"]'),
('song-ci-444','浣溪沙','黄公度','宋','宋词','song-ci','浣溪沙','[]','风送清香过短墙。',48,'宋词/ci.song.8000.json','["风送清香过短墙。", "烟笼晚色近修篁。", "夕阳楼外角声长。", "欲去还留无限思，轻匀淡抹不成妆。", "一尊相对月生凉。"]'),
('song-ci-445','满庭芳','黄公度','宋','宋词','song-ci','满庭芳','[]','枫岭摇丹，梧阶飘冷，一天风露惊秋。',118,'宋词/ci.song.8000.json','["枫岭摇丹，梧阶飘冷，一天风露惊秋。", "数丛篱下，滴滴晓香浮。", "不趁桃红李白，堪匹配、梅淡兰幽。", "孤芳晚，狂蜂戏蝶，长负岁寒愁。", "年年，重九日，龙山高会，彭泽清流。", "向尊前一笑，未觉淹留。", "况有甘滋玉铉，佳名算、合在金瓯。", "功成后，夕英饱饵，相伴赤松游。"]'),
('song-ci-446','卜算子','黄童','宋','宋词','song-ci','卜算子','[]','不忍更回头，别泪多於雨。',53,'宋词/ci.song.8000.json','["不忍更回头，别泪多於雨。", "肺腑相看四十秋，奚止朝朝暮暮。", "何事值花时，又是匆匆去。", "过了阳关更向西，总是思兄处。"]'),
('song-ci-447','临江仙','倪偁','宋','宋词','song-ci','临江仙','[]','结束征鞍临驿路，长林积雪消初。',70,'宋词/ci.song.8000.json','["结束征鞍临驿路，长林积雪消初。", "天回春色到平芜。", "不禁杯酒罢，便与故人疏。", "一曲阳关歌未彻，仆夫催驾修途。", "非君思我更谁欤。", "西风吹过雁，应有寄来书。"]'),
('song-ci-448','临江仙','倪偁','宋','宋词','song-ci','临江仙','[]','万里凉风收积雨，一天晴碧新开。',70,'宋词/ci.song.8000.json','["万里凉风收积雨，一天晴碧新开。", "暮云归尽绝纤埃。", "金波明静夜，玉露湿苍苔。", "坐有霜髯诗酒客，平生见月衔杯。", "传闻丹诏日边来。", "莫辞通夕醉，对景且徘徊。"]'),
('song-ci-449','临江仙','倪偁','宋','宋词','song-ci','临江仙','[]','竹里轩窗真可爱，况当暑退新凉。',70,'宋词/ci.song.8000.json','["竹里轩窗真可爱，况当暑退新凉。", "檐前岩桂向人芳。", "清阴团翠盖，金粟淡微黄。", "坐到夜深明月出，好风时度幽香。", "莫辞沈醉倒霞觞。", "一枝聊赠子，早冠绿衣郎。"]'),
('song-ci-450','临江仙','倪偁','宋','宋词','song-ci','临江仙','[]','木落西风秋已半，正当璧月圆时。',70,'宋词/ci.song.8000.json','["木落西风秋已半，正当璧月圆时。", "为登绝岭赋新诗。", "酒摇金凿落，波净碧琉璃。", "细看冰轮还有意，要君把盏休辞。", "看看两鬓欲成丝。", "明年当此夜，千里共相思。"]'),
('song-ci-451','临江仙','倪偁','宋','宋词','song-ci','临江仙','[]','茅屋三间临木杪，门前流水潺潺。',70,'宋词/ci.song.8000.json','["茅屋三间临木杪，门前流水潺潺。", "林泉得趣喜身闲。", "开窗延翠竹，翦树纳青山。", "行乐政须筋力健，莫令白发衰颜。", "与君藜杖极跻攀。", "岭头舒望眼，天末数烟鬟。"]'),
('song-ci-452','临江仙','倪偁','宋','宋词','song-ci','临江仙','[]','湖上青山千万叠，倏如阵马交驰。',70,'宋词/ci.song.8000.json','["湖上青山千万叠，倏如阵马交驰。", "平湖百顷却逶迟。", "晴光相荡激，倒影落沦漪。", "何日漾舟深碧处，细听羌笛高吹。", "多君起我以新诗。", "未能同寓目，聊复一伸眉。"]'),
('song-ci-453','临江仙','倪偁','宋','宋词','song-ci','临江仙','[]','鸟语朝来新雨霁，杖藜呼我闲行。',70,'宋词/ci.song.8000.json','["鸟语朝来新雨霁，杖藜呼我闲行。", "天晴腰脚上山轻。", "清风收积润，斜日弄新晴。", "最爱飞泉鸣野涧，清如万壑松声。", "回风溅沫湿冠缨。", "归来魂梦冷，幽响杂瑶琼。"]'),
('song-ci-454','南歌子','倪偁','宋','宋词','song-ci','南歌子','[]','佳月当今夕，清尊尽客欢。',62,'宋词/ci.song.8000.json','["佳月当今夕，清尊尽客欢。", "参横斗转夜将阑。", "试泛小溪深处、与重看。", "野水从磨激，群山势郁盘。", "殷勤照我一杯残。", "更有谪仙奇句、斗清寒。"]'),
('song-ci-455','南歌子','倪偁','宋','宋词','song-ci','南歌子','[]','置酒临清夜，狂歌尽一欢。',62,'宋词/ci.song.8000.json','["置酒临清夜，狂歌尽一欢。", "主人幽兴未渠阑。", "不负一天明月、卷帘看。", "影动黄金阙，光摇承露盘。", "君今双鬓未凋残。", "明岁玉堂兹夕、赏高寒。"]'),
('song-ci-456','南歌子','倪偁','宋','宋词','song-ci','南歌子','[]','对月中秋夜，传觞一笑欢。',62,'宋词/ci.song.8000.json','["对月中秋夜，传觞一笑欢。", "飘然逸兴未应阑。", "步向望湖桥上、倚阑看。", "松径风萧瑟，山腰路屈盘。", "南飞惊鹊五更残。", "小立水云光里、葛衣寒。"]'),
('song-ci-457','南歌子','倪偁','宋','宋词','song-ci','南歌子','[]','露下衣微湿，杯深意甚欢。',62,'宋词/ci.song.8000.json','["露下衣微湿，杯深意甚欢。", "西风吹暑十分阑。", "月满中秋、仍共故人看。", "酒好鹅黄嫩，茶珍小凤盘。", "醉吟不觉曙锺残。", "犹记归来扑面、井花寒。"]'),
('song-ci-458','南歌子','倪偁','宋','宋词','song-ci','南歌子','[]','嫩竹呈新绿，幽花露浅红。',62,'宋词/ci.song.8000.json','["嫩竹呈新绿，幽花露浅红。", "一檐苍翠落杯中。", "更有飞泉鸣佩、响丁东。", "乐事知难并，良辰得暂逢。", "晚风林下一尊同。", "便觉飘然身在、广寒宫。"]'),
('song-ci-459','南歌子','倪偁','宋','宋词','song-ci','南歌子','[]','积水凝深碧，斜阳散满红。',62,'宋词/ci.song.8000.json','["积水凝深碧，斜阳散满红。", "扁舟轻漾白苹风。", "曲港孤村萦绕、路相通。", "野色浮尊净，荷香入座浓。", "胜游聊复五人同。", "恰似辋川当日、画图中。"]'),
('song-ci-460','水调歌头','倪偁','宋','宋词','song-ci','水调歌头','["\u5e90\u5c71"]','昨夜狂雷怒，鞭起卞山龙。',114,'宋词/ci.song.8000.json','["昨夜狂雷怒，鞭起卞山龙。", "怪见朝来急雨，万木偃颠风。", "试看潭头落涧，一片练波飞出，河汉与天通。", "向晚馀霏落，巾已垫林宗。", "向高岩，凭曲槛，抚孤松。", "为雕好句，快倾桑落玉壶空。", "借问庐山三峡，与此飞流溅沫，今日定谁雄。", "乞与丹青手，写入紫微宫。"]'),
('song-ci-461','水调歌头','倪偁','宋','宋词','song-ci','水调歌头','[]','风卷暮云尽，镜净一天秋。',114,'宋词/ci.song.8000.json','["风卷暮云尽，镜净一天秋。", "试把鹅黄新酒，细酌散闲愁。", "西望群山千叠，眇眇飞鸿没处，爽气与俱浮。", "且尽尊中绿，不用叹淹留。", "对西风，歌妙曲，意绸缪。", "万顷烟云奇变，所得过封侯。", "何事苦萦名利，便合绿蓑青笠，投绂早归休。", "他日君寻我，小艇钓寒流。"]'),
('song-ci-462','念奴娇','倪偁','宋','宋词','song-ci','念奴娇','["\u6d1e\u5ead\u6e56"]','素秋向晚，正洞庭木落，疏林凋绿。',120,'宋词/ci.song.8000.json','["素秋向晚，正洞庭木落，疏林凋绿。", "惟有岩前双桂树，翠叶香浮金粟。", "皓月飞来，徘徊树杪，光射林间屋。", "夜深人静，好风忽起庭竹。", "俄顷万籁号鸣，清寒疑乍，听高岩悬瀑。", "起看碧天澄似洗，应费明河千斛。", "细酌鹅黄，宴搜奇句，逸气凌鸿鹄。", "浩歌归去，却愁踏碎琼玉。"]'),
('song-ci-463','减字木兰花','倪偁','宋','宋词','song-ci','减字木兰花','[]','凭高一览。',52,'宋词/ci.song.8000.json','["凭高一览。", "紫翠相围光照眼。", "下瞰平湖。", "鹭立鸥飞意自如。", "天清境胜。", "云澹烟横鱼动镜。", "不是公诗。", "谁写新亭一段奇。"]'),
('song-ci-464','减字木兰花','倪偁','宋','宋词','song-ci','减字木兰花','[]','超然远览。',52,'宋词/ci.song.8000.json','["超然远览。", "是我辈人方俱眼。", "默想江湖。", "何处山川略得如。", "凉秋最胜。", "万顷芙蕖盖明镜。", "更乞清诗。", "要见胸中一吐奇。"]'),
('song-ci-465','减字木兰花','倪偁','宋','宋词','song-ci','减字木兰花','[]','新晴眺览。',52,'宋词/ci.song.8000.json','["新晴眺览。", "空翠相磨明老眼。", "水满溪湖。", "来往风帆得自如。", "天公济胜。", "明月当空开宝镜。", "咏谪仙诗。", "醉里骑鲸也大奇。"]'),
('song-ci-466','减字木兰花','倪偁','宋','宋词','song-ci','减字木兰花','[]','岭头独览。',52,'宋词/ci.song.8000.json','["岭头独览。", "诗料森然纷满眼。", "倒影摇湖。", "西子新妆定不如。", "溪南更胜。", "一片寒光明泻镜。", "赖有新诗。", "不负西山万叠奇。"]'),
('song-ci-467','减字木兰花','倪偁','宋','宋词','song-ci','减字木兰花','[]','新诗细览。',52,'宋词/ci.song.8000.json','["新诗细览。", "满纸骊珠光眩眼。", "高论倾湖。", "倒峡词源世不如。", "园池日胜。", "只恨孤鸾犹舞镜。", "陶写须诗。", "怪得连篇字字奇。"]'),
('song-ci-468','减字木兰花','倪偁','宋','宋词','song-ci','减字木兰花','[]','雨馀还览。',52,'宋词/ci.song.8000.json','["雨馀还览。", "隐隐遥岑花病眼。", "嫩绿浮湖。", "百顷蒲萄染不如。", "晨光绝胜。", "不许纤尘微点镜。", "满目皆诗。", "莫怪骚人语益奇。"]'),
('song-ci-469','蝶恋花','倪偁','宋','宋词','song-ci','蝶恋花','[]','长羡东林山下路。',70,'宋词/ci.song.8000.json','["长羡东林山下路。", "万叠云山，流水从倾注。", "两两三三飞白鹭。", "不须更觅神仙处。", "夜久望湖桥上语。", "欸乃渔歌，深入荷花去。", "修竹满山梅十亩。", "烦君为我成幽趣。"]'),
('song-ci-470','蝶恋花','倪偁','宋','宋词','song-ci','蝶恋花','[]','紫翠空濛庵畔路。',70,'宋词/ci.song.8000.json','["紫翠空濛庵畔路。", "满室松声，错认潺湲注。", "潇洒苹汀清立鹭。", "溪山真我归休处。", "老子平生无妄语。", "梅竹阴成，肯舍斯亭去。", "种秫会须盈百亩。", "非君谁识渊明趣。"]'),
('song-ci-471','蝶恋花','倪偁','宋','宋词','song-ci','蝶恋花','["\u897f\u6e56"]','我爱西湖湖上路。',70,'宋词/ci.song.8000.json','["我爱西湖湖上路。", "万顷沧波，河汉连天注。", "一片寒光明白鹭。", "依稀似我登临处。", "报答溪山须好语。", "痛饮高歌，何必骑鲸去。", "环舍清阴消几亩。", "无人肯办归来趣。"]'),
('song-ci-472','蝶恋花','倪偁','宋','宋词','song-ci','蝶恋花','[]','绿叶阴阴亭下路。',70,'宋词/ci.song.8000.json','["绿叶阴阴亭下路。", "修竹乔松，中有飞泉注。", "水满寒溪清照鹭。", "个中不住归何处。", "枝上幽禽相对语。", "细听声声，道不如归去。", "只待小园成数亩。", "归来占尽山中趣。"]'),
('song-ci-473','蝶恋花','倪偁','宋','宋词','song-ci','蝶恋花','[]','茅屋三间林临水路。',71,'宋词/ci.song.8000.json','["茅屋三间林临水路。", "棐几明窗，待把虫鱼注。", "我已忘机狎鸥鹭。", "溪山买得幽深处。", "小雨招君连夜语。", "野服纶巾，胜日寻君去。", "借问良田千万亩。", "何如乐取林泉趣。"]'),
('song-ci-474','朝中措','倪偁','宋','宋词','song-ci','朝中措','[]','森然修竹满晴窗。',56,'宋词/ci.song.8000.json','["森然修竹满晴窗。", "山色净明妆。", "无限凄凉古意，白苹红蓼斜阳。", "松风一枕借僧床。", "馥馥桂花香。", "暂远世尘萦染，坐令心地清凉。"]'),
('song-ci-475','西江月','倪偁','宋','宋词','song-ci','西江月','[]','四面烟鬟绕翠，一川鸭绿摇光。',58,'宋词/ci.song.8000.json','["四面烟鬟绕翠，一川鸭绿摇光。", "危亭缥缈短松冈。", "把酒与君西望。", "万事尽皆前定，人生底用乾忙。", "只应醉里是家乡。", "且尽玉壶新酿。"]'),
('song-ci-476','鹧鸪天','倪偁','宋','宋词','song-ci','鹧鸪天','[]','萧瑟西风万里秋。',64,'宋词/ci.song.8000.json','["萧瑟西风万里秋。", "暮云收尽月华流。", "偶然北海清尊满，况是西山爽气浮。", "登翠岭，更溪游。", "素光何处不清幽。", "悬知明岁君思我，今夕欢娱可罢休。"]'),
('song-ci-477','鹧鸪天','倪偁','宋','宋词','song-ci','鹧鸪天','[]','拟看今宵璧月秋。',64,'宋词/ci.song.8000.json','["拟看今宵璧月秋。", "浮云却妒素光流。", "天公肯放冰轮出，我辈宁辞大白浮。", "穿翠密，极遨游。", "人间那得此深幽。", "金波若到清尊里，下笔联篇未肯休。"]'),
('song-ci-478','鹧鸪天','倪偁','宋','宋词','song-ci','鹧鸪天','[]','野旷无尘夕霭收。',64,'宋词/ci.song.8000.json','["野旷无尘夕霭收。", "人间八月桂花秋。", "三更爽气山围座，万里凉风月满楼。", "登绝岭，小迟留。", "人言惟酒可忘忧。", "一杯径入无何有，未愧当年赤壁游。"]'),
('song-ci-479','鹧鸪天','倪偁','宋','宋词','song-ci','鹧鸪天','[]','去岁登高感叹长。',64,'宋词/ci.song.8000.json','["去岁登高感叹长。", "今年九日倍幽凉。", "怀人独下西州泪，对菊谁空北海觞。", "夸酒量，斗新狂。", "尚馀醉墨在巾箱。", "眼前风物都非旧，祗有青山带夕阳。"]'),
('song-ci-480','菩萨蛮','王之望','宋','宋词','song-ci','菩萨蛮','[]','华灯的皪明金碧。',52,'宋词/ci.song.8000.json','["华灯的皪明金碧。", "玳筵剧饮杯馀湿。", "珠翠隔房栊。", "微闻笑语通。", "蓬瀛知已近。", "青鸟仍传信。", "应为整云鬟。", "教侬倒玉山。"]'),
('song-ci-481','好事近','王之望','宋','宋词','song-ci','好事近','[]','五载复相逢，俱被一官驱役。',53,'宋词/ci.song.8000.json','["五载复相逢，俱被一官驱役。", "惊我雪髯霜鬓，只声香相识。", "翠帷珍重出笙歌，醉迟迟春日。", "亲到鹊桥津畔，见天机停织。"]'),
('song-ci-482','好事近','王之望','宋','宋词','song-ci','好事近','[]','彩舰载娉婷，宛在玉楼琼宇。',53,'宋词/ci.song.8000.json','["彩舰载娉婷，宛在玉楼琼宇。", "人欲御风仙去，觉衣裳飘举。", "玉京咫尺是蓝桥，一见已心许。", "梦解汉皋珠佩，但茫茫烟浦。"]'),
('song-ci-483','好事近','王之望','宋','宋词','song-ci','好事近','[]','缓带抚雄边，一面灭烽休役。',53,'宋词/ci.song.8000.json','["缓带抚雄边，一面灭烽休役。", "歌舞后堂高宴，喜倾城初识。", "红绫小砑写新词，佳句丽星日。", "从此锦城机杼，把回文休织。"]'),
('song-ci-484','好事近','王之望','宋','宋词','song-ci','好事近','[]','清唱动梁尘，窈窕夜深庭宇。',53,'宋词/ci.song.8000.json','["清唱动梁尘，窈窕夜深庭宇。", "一笑满斟芳酒，看霞觞争举。", "弓靴三寸坐中倾，惊叹小如许。", "子建向来能赋，过凌波仙浦。"]'),
('song-ci-485','好事近','王之望','宋','宋词','song-ci','好事近','[]','萧寺两珠红，欲共晓霞争色。',53,'宋词/ci.song.8000.json','["萧寺两珠红，欲共晓霞争色。", "独占岁寒天气，正群芳休息。", "坐中清唱并阳春，写物妙诗格。", "霜鬓自羞簪帽，叹如何抛得。"]'),
('song-ci-486','减字木兰花','王之望','宋','宋词','song-ci','减字木兰花','[]','珠帘乍见。',52,'宋词/ci.song.8000.json','["珠帘乍见。", "云雨无踪空有怨。", "锦字新词。", "青鸟衔来恼暗期。", "桃溪得路。", "直到仙家留客处。", "今日东邻。", "远忆当年窥宋人。"]'),
('song-ci-487','减字木兰花','王之望','宋','宋词','song-ci','减字木兰花','[]','糟糠相乐。',52,'宋词/ci.song.8000.json','["糟糠相乐。", "早共梁鸿同隐约。", "著籍天门。", "隔品新封感帝恩。", "满堂儿女。", "妇捧金杯孙屡舞。", "白发卿卿。", "与尔尊前作寿星。"]'),
('song-ci-488','丑奴儿・采桑子','王之望','宋','宋词','song-ci','丑奴儿・采桑子','[]','蒙泉秋色登临处，愁送将归。',58,'宋词/ci.song.8000.json','["蒙泉秋色登临处，愁送将归。", "一梦经时。", "肠断佳人、犹唱渭城词。", "春来重醉分携地，人在天涯。", "别后应知。", "两鬓萧萧、多半已成丝。"]'),
('song-ci-489','丑奴儿・采桑子','王之望','宋','宋词','song-ci','丑奴儿・采桑子','[]','去年池馆同君醉，正是花时。',58,'宋词/ci.song.8000.json','["去年池馆同君醉，正是花时。", "隔院韶辉。", "桃李欣欣、如与故人期。", "相望两地今千里，还对芳菲。", "春色分谁。", "雨惨风愁、依旧可怜枝。"]'),
('song-ci-490','惜分飞','王之望','宋','宋词','song-ci','惜分飞','[]','要眇新声生宝柱。',58,'宋词/ci.song.8000.json','["要眇新声生宝柱。", "弹到离肠断处。", "细落檐花雨。", "夜阑清唱行云住。", "洞府春长还易暮。", "凡客暂来终去。", "不忍回头觑。", "乱山流水桃溪路。"]'),
('song-ci-491','醉花阴','王之望','宋','宋词','song-ci','醉花阴','[]','弧门此日犹能记。',62,'宋词/ci.song.8000.json','["弧门此日犹能记。", "叹居诸难系。", "弹指片声中，不觉流年，五十还加二。", "儿童寿酒邀翁醉。", "笑欣欣相戏。", "休画老人星，白发苍髯，怎解如翁似。"]'),
('song-ci-492','鹧鸪天','王之望','宋','宋词','song-ci','鹧鸪天','[]','撩乱江云雪欲飞。',64,'宋词/ci.song.8000.json','["撩乱江云雪欲飞。", "小轩幽会酒行时。", "佳人喜得鸳鸯侣，豪客争题鹦鹉词。", "歌舞地，喜追随。", "歙州端恨外迁迟。", "谪仙狂监从来识，七步初看子建诗。"]'),
('song-ci-493','虞美人','王之望','宋','宋词','song-ci','虞美人','[]','鸳鸯碧瓦寒留雪。',66,'宋词/ci.song.8000.json','["鸳鸯碧瓦寒留雪。", "玉树先春发。", "小楼歌舞夜流连。", "月落参横、一梦绕梅边。", "尊前酒量谁能惜。", "都是高阳客。", "十分莫厌羽觞传。", "半醉娉婷、云鬓亸金钿。"]'),
('song-ci-494','小重山','王之望','宋','宋词','song-ci','小重山','[]','幂幂轻云护晓霜。',70,'宋词/ci.song.8000.json','["幂幂轻云护晓霜。", "银花千万朵，烂韶光。", "宝山金字屡更张。", "笙箫远，帘幕閟重廊。", "车马暗尘香。", "一邦如蜡日，尽豪狂。", "游人归路笑声长。", "长歌里，击壤咏陶唐。"]'),
('song-ci-495','临江仙','王之望','宋','宋词','song-ci','临江仙','[]','十二峰前朝复暮，忽愁望断行云。',70,'宋词/ci.song.8000.json','["十二峰前朝复暮，忽愁望断行云。", "梦回江浦晓风清。", "远山思翠黛，蔓草记罗裙。", "锦字织成千万恨，翻成第入新声。", "幽期谁为反离魂。", "主人无浪语，狂客最锺情。"]'),
('song-ci-496','临江仙','王之望','宋','宋词','song-ci','临江仙','[]','霓作衣裳冰作面，铅华不涴天真。',70,'宋词/ci.song.8000.json','["霓作衣裳冰作面，铅华不涴天真。", "临风几待逐行云。", "自从留得住，不肯系仙裙。", "对客挥毫惊满座，银钩虿尾争新。", "数行草圣妙如神。", "从今王逸少，不学卫夫人。"]'),
('song-ci-497','临江仙','王之望','宋','宋词','song-ci','临江仙','[]','家在蓬莱山下住，乘风时到尘寰。',70,'宋词/ci.song.8000.json','["家在蓬莱山下住，乘风时到尘寰。", "双凫偶堕网罗间。", "惊容凝粉泪，愁鬓乱云鬟。", "人世风波难久驻，云霞终反仙关。", "虚无仙路拥归鸾。", "却随烟雾去，长向洞天闲。"]'),
('song-ci-498','洞仙歌','王之望','宋','宋词','song-ci','洞仙歌','[]','玉楼玄圃，旧是神仙伴。',102,'宋词/ci.song.8000.json','["玉楼玄圃，旧是神仙伴。", "鸣佩时朝紫皇殿。", "种蟠桃成树，碧柰开花，著子满，金母盘中屡献。", "飘然乘彩凤，东望蓬莱，曾共扁舟五湖泛。", "正珈笄未老，兰玉盈前，春欲转、喜对芳辰开宴。", "愿绿发朱颜镇长新，教岁岁年年，寿觞深劝。"]'),
('song-ci-499','满庭芳','王之望','宋','宋词','song-ci','满庭芳','[]','海国寒轻，江南春早，小梅已漏芳妍。',118,'宋词/ci.song.8000.json','["海国寒轻，江南春早，小梅已漏芳妍。", "岁前冬后，和气欲回旋。", "此际瑶台阆苑，仙人下、白玉云軿。", "人间世，风帆月棹，同泛五湖船。", "当年。", "参谒地，鱼轩象服，锵佩朝天。", "向闽邦开国，福地真传。", "今日华筵寿斝，儿孙拥、兰玉相鲜。", "休辞□，蓬莱清浅，看取变桑田。"]'),
('song-ci-500','满庭芳','王之望','宋','宋词','song-ci','满庭芳','[]','犀隐雕龙，蟾将威凤，建溪初贡新芽。',118,'宋词/ci.song.8000.json','["犀隐雕龙，蟾将威凤，建溪初贡新芽。", "九天春色，先到列仙家。", "今日磨圭碎璧，天香动、风入窗纱。", "清泉嫩，江南锡乳，一脉贯天涯。", "芳华。", "瑶圃宴，群真飞佩，同引流霞。", "醉琼筵红绿，眼乱繁花。", "一碗分云饮露，尘凡尽、斗牛何赊。", "归途稳，清飙两腋，不用泛灵槎。"]'),
('song-ci-501','念奴娇','王之望','宋','宋词','song-ci','念奴娇','[]','堂堂七尺，懔一时人物，孤映三蜀。',120,'宋词/ci.song.8000.json','["堂堂七尺，懔一时人物，孤映三蜀。", "闲雅风流豪醉后，犹有临邛遗俗。", "十载虞庠，一官楚塞，雅操凌寒玉。", "江山千里，惠然来慰幽独。", "落笔妙语如神，两章入手，不觉珠盈掬。", "从此西归荣耀处，宁假华旌高纛。", "乐府新声，郢都馀唱，应纪阳春曲。", "老夫一醉，故人高义堪服。"]'),
('song-ci-502','念奴娇','王之望','宋','宋词','song-ci','念奴娇','[]','蒙泉岁晚，偶扁舟、同泛一池寒渌。',120,'宋词/ci.song.8000.json','["蒙泉岁晚，偶扁舟、同泛一池寒渌。", "四者难并谁信道，草草幽欢能足。", "美景良辰，赏心乐事，更有人如玉。", "今宵此会，陋邦惊破衰俗。", "豪俊傅粉诸孙，几年分袂，一笑还相逐。", "痛饮厌厌清夜永，那管更深催促。", "宋玉词章，陶潜风概，况继前贤躅。", "故人未至，坐中仍对梅福。"]'),
('song-ci-503','念奴娇','王之望','宋','宋词','song-ci','念奴娇','[]','柳花飞絮，又还是、清明寂寞时节。',120,'宋词/ci.song.8000.json','["柳花飞絮，又还是、清明寂寞时节。", "洞府人间嗟素手，今日匆匆分拆。", "巧笑难成，含情谁解，顾影无颜色。", "风流满面，却成春恨凄恻。", "云鬓从亸金蝉，纷纷红泪，千点胭脂湿。", "聚调轻盈离调惨，声入低空愁碧。", "祖帐将收，骊驹欲驾，去也劳相忆。", "伤心南浦，断肠芳草如积。"]'),
('song-ci-504','永遇乐','王之望','宋','宋词','song-ci','永遇乐','[]','元夜风光，上都灯火，辉映春色。',128,'宋词/ci.song.8000.json','["元夜风光，上都灯火，辉映春色。", "鳌冠仙山，龙衔瑞烛，银阙凌空碧。", "紫烟深拥，黄云孤起，人喜乍瞻天日。", "□云里，□□□□，侍臣□□鹄立。", "雾收霞卷，珠帘开遍，翠幕娉婷争出。", "倾国丛中，钧天合处，忽听鸣清跸。", "貂裘小帽，随车信马，犹忆少年豪逸。", "如今对，山城皓月，但馀叹息。"]'),
('song-ci-505','风流子','王之望','宋','宋词','song-ci','风流子','[]','江国东风早，芳菲又、迤逦报寒梅。',136,'宋词/ci.song.8000.json','["江国东风早，芳菲又、迤逦报寒梅。", "正元气孕和，小春归候，数丁千载，喜动三台。", "向此际，上天开景运，王国产英材。", "想崇岳洞天，暗书苔藓，海山烟雨，空锁楼台。", "煌煌天人表，琼林与瑶树，照映庭槐。", "中有丽天星斗，惊世风雷。", "况朱颜绿发，年光鼎盛，绣裳华衮，人望归来。", "好对玳筵满举，眉寿觥罍。"]'),
('song-ci-506','满庭芳','葛立方','宋','宋词','song-ci','满庭芳','[]','霜叶停飞，冰鱼初跃，梅花犹閟芳丛。',118,'宋词/ci.song.8000.json','["霜叶停飞，冰鱼初跃，梅花犹閟芳丛。", "剪酥装玉，应为费天工。", "争奈江南驿使，征鞍待、一朵香浓。", "凭谁报，冰肌仙子，闻早驾飞龙。", "溶溶。", "春意动，寒姿未展，终愧群红。", "与斩新来上，开伴长松。", "要看黄昏庭院，横斜映、霜月朦胧。", "兰堂畔，巡檐索笑，谁羡杜陵翁。"]'),
('song-ci-507','满庭芳','葛立方','宋','宋词','song-ci','满庭芳','[]','未许蜂知，难交雀啅，芳丛犹是寒丛。',118,'宋词/ci.song.8000.json','["未许蜂知，难交雀啅，芳丛犹是寒丛。", "东方解冻，春仗做春工。", "何事仙葩未放，寒苞秘、冰麝香浓。", "应须是、惊闻羯鼓，谁敢喷髯龙。", "梅花，君自看，丁香已白，桃脸将红。", "结岁寒三友，久迟筠松。", "要看含章檐下，闲妆靓、春睡朦胧。", "知音是，冻云影底，铁面葛仙翁。"]'),
('song-ci-508','满庭芳','葛立方','宋','宋词','song-ci','满庭芳','[]','狂吹鸣篱，祥霙剪水，分明欺压寒梅。',118,'宋词/ci.song.8000.json','["狂吹鸣篱，祥霙剪水，分明欺压寒梅。", "冰威初敛，曦影上池台。", "应有一番和气，南枝上、恐有春来。", "须勤探，呼吾筇杖，屐齿上苍苔。", "春风，浑未到，徘徊香径，巡绕千回。", "见琼英一点，小占条枚。", "且看先锋素艳，看看便、繁蕾齐开。", "香浮动，微薰诗梦，须更著诗催。"]'),
('song-ci-509','满庭芳','葛立方','宋','宋词','song-ci','满庭芳','[]','腊雪方凝，春曦俄漏，画堂小秩芳筵。',118,'宋词/ci.song.8000.json','["腊雪方凝，春曦俄漏，画堂小秩芳筵。", "玉台仙蕊，帘外幂瑶烟。", "莫话青山万树，聊须对、一段孤妍。", "杯行处，香参鼻观，百濯未为贤。", "吾庐，何处好，绣香竹畔，偶桂溪边。", "且为渠珍重，满泛金船。", "已拚春酲一枕，如今且、醉倒花前。", "花飞后，欢呼一笑，又是说明年。"]'),
('song-ci-510','满庭芳','葛立方','宋','宋词','song-ci','满庭芳','[]','庾信何愁，休文何瘦，范叔一见何寒。',118,'宋词/ci.song.8000.json','["庾信何愁，休文何瘦，范叔一见何寒。", "梅花酷似，索笑画檐看。", "便肯嫣然一笑，疏篱上、玉脸冰颜。", "须勤赏，莫教青子，半著树头酸。", "朱阑。", "聊掩映，昆仑顶上，琪树团栾。", "命儿曹班坐，草草杯盘。", "旋折溪边□朵，琼蕤泛、蕉叶杯宽。", "从教□，尊前有客，拍手笑颓山。"]'),
('song-ci-511','满庭芳','葛立方','宋','宋词','song-ci','满庭芳','[]','弄月黄昏，封霜清晓，数枝影堕溪滨。',118,'宋词/ci.song.8000.json','["弄月黄昏，封霜清晓，数枝影堕溪滨。", "化工先手，幻出一番新。", "片片雕酥碾玉，寒苞似、已泄香尘。", "聊相对，畸人投分，尊酒认荀陈。", "吾年，今老矣，佳人薄相，笑插林巾。", "愧苍颜白发，回授乌云。", "玉镜台边试看，相宜是、浅笑轻颦。", "君知否，寿阳额上，不似鬓边春。"]'),
('song-ci-512','满庭芳','葛立方','宋','宋词','song-ci','满庭芳','[]','一阵轻香，不知来处，元来梅已舒英。',118,'宋词/ci.song.8000.json','["一阵轻香，不知来处，元来梅已舒英。", "出篱含笑，芳意为人倾。", "细看高标孤韵，谁家有、别得花人。", "应须是，魏徵妩媚，夷甫太鲜明。", "北枝，方半吐，水边疏影，绰约娉婷。", "问横空皎月，匝地寒霙。", "何似此花清绝，凭君为、子细推评。", "幽奇处，素娥青女，著意为横陈。"]'),
('song-ci-513','锦堂春・锦堂春慢','葛立方','宋','宋词','song-ci','锦堂春・锦堂春慢','[]','气应三阳，氛澄六幕，翔乌初上云端。',119,'宋词/ci.song.8000.json','["气应三阳，氛澄六幕，翔乌初上云端。", "问朝来何事，喜动门阑。", "田父占来好岁，星翁说道宜官。", "拟更凭高望远，春在烟波，春在晴峦。", "歌管雕堂宴喜，任重帘不卷，交护春寒。", "况金钗整整，玉树团团。", "柏叶轻浮重醑，梅枝巧缀新幡。", "共祝年年如愿，寿过松椿，寿过彭聃。"]'),
('song-ci-514','水龙吟','葛立方','宋','宋词','song-ci','水龙吟','[]','九州雄杰溪山，遂安自古称佳处。',128,'宋词/ci.song.8000.json','["九州雄杰溪山，遂安自古称佳处。", "云迷半岭，风号浅濑，轻舟斜渡。", "朱阁横飞，渔矶无恙，鸟啼林坞。", "吊高人陈迹，空瞻遗像，知英烈、垂千古。", "忆昔龙飞光武。", "怅当年、故人何许。", "羊裘自贵，龙章难换，不如归去。", "七里溪边，鸬鸶源畔，一蓑烟雨。", "叹如今宕子，翻将钓手遮日，向西秦路。"]'),
('song-ci-515','菩萨蛮','葛立方','宋','宋词','song-ci','菩萨蛮','[]','井梧叶叶秋风晚。',52,'宋词/ci.song.8000.json','["井梧叶叶秋风晚。", "东篱点点金钱满。", "开急为重阳。", "日烘深院香。", "幽姿无众草。", "莫恨生非早。", "嚼蕊傍池台。", "寿公桑落杯。"]'),
('song-ci-516','风流子','葛立方','宋','宋词','song-ci','风流子','[]','夜半春阳启，东风峭、犹带去年寒。',137,'宋词/ci.song.8000.json','["夜半春阳启，东风峭、犹带去年寒。", "叹榆塞战尘，玉关烟燧，壮心耿耿，青鬓斑斑。", "又还是，一年头上到，日月信跳丸。", "看门贴绘鸡，历颁金凤，酒浮柏叶，人颂椒盘。", "幽园。", "春信近，帘栊静，小宴取次追欢。", "聊□水沈烟袅，清唱声闲。", "况良辰渐有，梅舒琼蕊，柳摇金缕，巧缀新幡。", "莫惜醉吟亲侧，衣曳荆兰。"]'),
('song-ci-517','多丽','葛立方','宋','宋词','song-ci','多丽','["\u897f\u6e56"]','冷云收，小园一段瑶芳。',173,'宋词/ci.song.8000.json','["冷云收，小园一段瑶芳。", "乍春来、未回穷腊，几枝开犯严霜。", "傍黄昏、暗香浮动，照清浅、疏影低昂。", "却月幽姿，含章媚态，姮娥姑射下仙乡。", "倚阑看、殷勤持酒，索笑也何妨。", "堪怜处，东君不管，独自凄凉。", "算何人、为伊销断，古今才子篇章。", "有西湖、赋诗处士，□东阁、年少台郎。", "驿使来时，吴王醉处，几番牵动广平肠。", "剩宴赏、微酸如豆，又是隔年长。", "高楼外，莫教羌管，吹堕寒香。"]'),
('song-ci-518','沙塞子','葛立方','宋','宋词','song-ci','沙塞子','[]','天生玉骨冰肌。',61,'宋词/ci.song.8000.json','["天生玉骨冰肌。", "瘦损也、知他为谁。", "□寒底、傲霜凌雪，不教春知。", "高楼横笛试轻吹。", "要一片、花飞酒卮。", "拚沈醉、帽帘斜插，折取南枝。"]'),
('song-ci-519','多丽','葛立方','宋','宋词','song-ci','多丽','[]','破波光如镜，三翼轻舟。',173,'宋词/ci.song.8000.json','["破波光如镜，三翼轻舟。", "对雨馀、重岩叠嶂，何妨影堕清流。", "望芙蕖、渺然如海，张云锦、掩映汀洲。", "出水奇姿，凌波艳态，眼看□叶弄新秋。", "恍疑是、金沙池内，玉井认峰头。", "花深处，田田叶底，鱼戏龟游。", "正微凉、西风初度，一弯斜月如钩。", "想天津、鹊桥将驾，看宝奁、蛛网初抽。", "晒腹何勘，穿针无绪，不如溪上少淹留。", "竞笑语、追寻惟有，沈醉可忘忧。", "凭清唱，一声檀板，惊起沙鸥。"]'),
('song-ci-520','满庭芳','葛立方','宋','宋词','song-ci','满庭芳','[]','扉映琉璃，窗摇云母，水堂新甃云湾。',118,'宋词/ci.song.8000.json','["扉映琉璃，窗摇云母，水堂新甃云湾。", "际天波面，玉镜宝奁宽。", "栏外青山几叠，瑶烟敛、影落千鬟。", "寒汀晚，芦花飞雪，风定白鸥闲。", "尘寰。", "何处有，方壶圆峤，弱水波翻。", "问何如藜杖，此地跻攀。", "种竹今逾万个，风枝静、日报平安。", "他年事、苍云屯处，千亩看栖鸾。"]'),
('song-ci-521','春光好','葛立方','宋','宋词','song-ci','春光好','[]','去年曾寿生朝。',58,'宋词/ci.song.8000.json','["去年曾寿生朝。", "正菊黄、初舒翠翘。", "今岁雕堂重预宴，梨雪香飘。", "明年应傍丹霄。", "看宝胯、重重在腰。", "鹊尾吹香笼绣段，且醉金蕉。"]'),
('song-ci-522','西江月','葛立方','宋','宋词','song-ci','西江月','[]','风送丹枫卷地，霜乾枯苇鸣溪。',58,'宋词/ci.song.8000.json','["风送丹枫卷地，霜乾枯苇鸣溪。", "兽炉重展向深闺。", "红入麒麟方炽。", "翠箔底垂银蒜，罗帏小钉金泥。", "笙歌送我玉东西。", "谁管摇花舞砌。"]'),
('song-ci-523','蝶恋花','葛立方','宋','宋词','song-ci','蝶恋花','[]','缇室群阴清晓散。',70,'宋词/ci.song.8000.json','["缇室群阴清晓散。", "灰动葭莩，渐觉微阳扇。", "日永绣工才一线。", "挈壶已报添银箭。", "六幕无尘开碧汉。", "非雾非烟，彷佛登台见。", "梅萼飘香萦小宴。", "霞浆莫放琉璃浅。"]'),
('song-ci-524','清平乐','葛立方','宋','宋词','song-ci','清平乐','[]','文章惊世。',54,'宋词/ci.song.8000.json','["文章惊世。", "半挹南宫第。", "蟾窟澄辉天似洗。", "折得窅窊丹桂。", "当年蓬矢生贤。", "流霞满祝长年。", "更愿巨鳌连钓，枫宸第一胪传。"]'),
('song-ci-525','减字木兰花','葛立方','宋','宋词','song-ci','减字木兰花','[]','摇毫铸藻。',52,'宋词/ci.song.8000.json','["摇毫铸藻。", "纵有微之应压倒。", "万里鹏程。", "南省今书淡墨名。", "胪传丹陛。", "月里桂花先著袂。", "雁塔高题。", "玉季巍科尚觉低。"]'),
('song-ci-526','满庭芳','葛立方','宋','宋词','song-ci','满庭芳','[]','栗里田园，乌衣门巷，别来几换星霜。',118,'宋词/ci.song.8000.json','["栗里田园，乌衣门巷，别来几换星霜。", "华阳仙窟，翠桁彩衣香。", "梦堕当涂风月，披绛帐、欲指鱣堂。", "浮鸥外，来宁老子，特泛霅溪航。", "相逢，春正好，梅舒香白，柳曳宫黄。", "且相将一笑，乐未渠央。", "须念离多会少，难轻负、百榼霞浆。", "深深观，舞回飞雪，乐奏小宫商。"]'),
('song-ci-527','水调歌头','葛立方','宋','宋词','song-ci','水调歌头','[]','睡鸭凝香缕，白酒泻无声。',114,'宋词/ci.song.8000.json','["睡鸭凝香缕，白酒泻无声。", "郊墟不办羊酪，照箸紫丝莼。", "此去青山深处，邀得白云为伴，绝意请长缨。", "一舸背君去，几幅布帆轻。", "帝恩重，容绿隐，吏祠庭。", "膝间文度安亲，得计是扬名。", "珍重金兰交契，共惜匆匆别去，送我几烟林。", "异日怀君处，凝睇乱层岑。"]'),
('song-ci-528','风流子','葛立方','宋','宋词','song-ci','风流子','[]','细草芳南苑，东风里、赢得一身闲。',135,'宋词/ci.song.8000.json','["细草芳南苑，东风里、赢得一身闲。", "见花朵绣田，柳丝络岸，沼冰方泮，山雪初残。", "又还是，陇头春信动，梅蕊入征鞍。", "月里暗香，水边疏影，淡妆宜瘦，玉骨禁寒。", "泛金溪上好，开幽户、聊面翠麓云湾。", "知道醉吟堪老，名利难关。", "算书帏意懒，宦途游倦，旧时习气，惟有跻攀。", "拟待杖藜花底，直到春阑。"]'),
('song-ci-529','满庭芳','葛立方','宋','宋词','song-ci','满庭芳','[]','江国麾幢，边城鼓角，湓川几报严更。',118,'宋词/ci.song.8000.json','["江国麾幢，边城鼓角，湓川几报严更。", "笑谈油幕，英杰为时生。", "腹贮六韬三略，新诗就、矛槊频横。", "功名事，他年未晚，一笴落欃枪。", "归来，何早计，白苹洲畔，危获深耕。", "又何如，竹帛彝鼎垂名。", "犀节徵还伊迩，春风外、文鹢催行。", "岩廊上，谈兵齿颊，谠论佐休明。"]'),
('song-ci-530','玉漏迟','葛立方','宋','宋词','song-ci','玉漏迟','[]','窗户明环堵。',115,'宋词/ci.song.8000.json','["窗户明环堵。", "山容黛染，水光绡舞。", "荷盖擎烟，花映步波神女。", "嫩脸铅华掩素，无语向、薰风凝伫。", "晴又雨。", "征鞞隐隐，云洲沙渚。", "须臾风卷还晴，看香泄丹囊，乍飘沈炷。", "鱼飐荷衣，珠颗乱倾无数。", "休话金沙玉井，争似我、神龟□处。", "觞为举。", "何人解歌金缕。"]'),
('song-ci-531','行香子','葛立方','宋','宋词','song-ci','行香子','[]','风透纱窗。',84,'宋词/ci.song.8000.json','["风透纱窗。", "叶落银床。", "夹缬林、吹下严霜。", "新篘浮蚁，班坐飞觞。", "有岩中秀，篱中艳，洛中香。", "金钿放蕊，玉粒争芳。", "惯年年、来趁清商。", "不应素节，还有花王。", "看正封诗，龟年调，太真狂。"]'),
('song-ci-532','玉楼春','葛立方','宋','宋词','song-ci','玉楼春','[]','青女飞花浓剪水。',63,'宋词/ci.song.8000.json','["青女飞花浓剪水。", "寒气霏微度窗纸。", "人间那得骨为帘，有麒麟尊有蚁。", "笙簧冻涩闲纤指。", "香雾暖熏罗帐底。", "却教试作忽雷声，往往惊开桃与李。"]'),
('song-ci-533','瑞鹧鸪','葛立方','宋','宋词','song-ci','瑞鹧鸪','[]','榴花庭院戏氍毹。',64,'宋词/ci.song.8000.json','["榴花庭院戏氍毹。", "水剪双眸画不如。", "莫恨未能通瑟僩，只今先已辩之无。", "虎晴浅缀新花帽，龙脑浓熏小绣襦。", "乃祖未须贻厥力，及时须读五车书。"]'),
('song-ci-534','浪淘沙','葛立方','宋','宋词','song-ci','浪淘沙','[]','休看辋川图。',64,'宋词/ci.song.8000.json','["休看辋川图。", "未是幽居。", "何如云水绕储胥。", "新湿青红开栋宇，雾拱风疏。", "小圃秀郊墟。", "花破平芜。", "五峰列影水平铺。", "只欠五城楼十二，便是蓬壶。"]'),
('song-ci-535','卜算子','葛立方','宋','宋词','song-ci','卜算子','[]','明镜盖红蕖，轩户临烟渚。',52,'宋词/ci.song.8000.json','["明镜盖红蕖，轩户临烟渚。", "窣窣珠帘淡淡风，香里开尊俎。", "莫把碧筒弯，恐带荷心苦。", "唤我溪边太乙舟，潋滟盛芳醑。"]'),
('song-ci-536','卜算子','葛立方','宋','宋词','song-ci','卜算子','[]','袅袅水芝红，脉脉蒹葭浦。',52,'宋词/ci.song.8000.json','["袅袅水芝红，脉脉蒹葭浦。", "淅淅西风淡淡烟，几点疏疏雨。", "草草展杯觞，对此盈盈女。", "叶叶红衣当酒船，细细流霞举。"]'),
('song-ci-537','减字木兰花','葛立方','宋','宋词','song-ci','减字木兰花','[]','张南周北。',52,'宋词/ci.song.8000.json','["张南周北。", "谩说清漳摇绀碧。", "何似幽栖。", "甥舅相望共一溪。", "璇题沙版。", "不用买邻糜百万。", "余户增辉。", "庭列芝兰户戟枝。"]'),
('song-ci-538','夜行船','葛立方','宋','宋词','song-ci','夜行船','[]','百尺雕堂悬蜀绣。',68,'宋词/ci.song.8000.json','["百尺雕堂悬蜀绣。", "珠帘外、玉阑琼甃。", "调鼎名家，吹箫贤胄，新卜凤皇佳繇。", "银叶添香香满袖。", "满金杯、寿君芳酒。", "喜动蟾宫，祥生熊帐，应在细君归后。"]'),
('song-ci-539','雨中花・夜行船','葛立方','宋','宋词','song-ci','雨中花・夜行船','[]','壮岁嬉游，乐事几经，青门紫陌芳春。',118,'宋词/ci.song.8000.json','["壮岁嬉游，乐事几经，青门紫陌芳春。", "未见廉纤，膏雨浥花尘。", "濯锦宝丝增艳，洗妆玉颊尤新。", "向韶光浓处，点染芳菲，总是东君。", "苏州老子，经雨南园，为谁一扫花林。", "谁信道、佳声著处，肌润香匀。", "晓试何郎汤饼，暮留巫女行云。", "寄言游子，也须留眄，小驻蹄轮。"]'),
('song-ci-540','雨中花・夜行船','葛立方','宋','宋词','song-ci','雨中花・夜行船','[]','寄径濉阳，陌上忽看，夭桃秾李争春。',118,'宋词/ci.song.8000.json','["寄径濉阳，陌上忽看，夭桃秾李争春。", "又见楚宫，行雨洗芳尘。", "红艳霞光夕照，素华琼树朝新。", "为奇姿芳润，拟倩游丝，留住东君。", "拾遗杜老，犹爱南塘，寄情萝薜山林。", "争似此、花如姝丽，獭髓轻匀。", "不数江陵玉杖，休夸花岛红云。", "少须澄霁，一番清影，更待冰轮。"]'),
('song-ci-541','好事近','葛立方','宋','宋词','song-ci','好事近','[]','几骑汉旌回，喜动满川花木。',53,'宋词/ci.song.8000.json','["几骑汉旌回，喜动满川花木。", "遥睇清淮古岸，散离愁千斛。", "烟笼沙嘴定连艘，鹊脚蘸波绿。", "归话隔年心事，秉夜阑银烛。"]'),
('song-ci-542','好事近','葛立方','宋','宋词','song-ci','好事近','[]','归日指清明，肯把话言轻食。',53,'宋词/ci.song.8000.json','["归日指清明，肯把话言轻食。", "已是飞花时候，赖东风无力。", "青帘沽酒送春归，莫惜万金掷。", "屈指明年春事，有红梅消息。"]'),
('song-ci-543','朝中措','葛立方','宋','宋词','song-ci','朝中措','[]','暂时莫荡出燕然。',57,'宋词/ci.song.8000.json','["暂时莫荡出燕然。", "冰柱冻层檐。", "时节马蹄归路，杨花乱扑征鞯。", "如今归去，银铛宜见，七宝床边。", "待得退朝花底，家人争卷珠帘。"]'),
('song-ci-544','春光好','葛立方','宋','宋词','song-ci','春光好','[]','禁烟却酿新愁。',58,'宋词/ci.song.8000.json','["禁烟却酿新愁。", "正系马、清淮渡头。", "后日清明催叠鼓，应在扬州。", "归时元已临流。", "要绮陌、芳郊恣游。", "三月羁怀当一洗，莫放觥筹。"]'),
('song-ci-545','虞美人','魏杞','宋','宋词','song-ci','虞美人','[]','冰肤玉面孤山裔。',66,'宋词/ci.song.8000.json','["冰肤玉面孤山裔。", "肯到人间世。", "天然不与百花同。", "却恨无情轻付、与东风。", "丽谯三弄江梅晓。", "立马溪桥小。", "只应明月最相思。", "曾见幽香一点、未开时。"]'),
('song-ci-546','卜算子','魏杞','宋','宋词','song-ci','卜算子','[]','一叶鉴中来，两岸青山起。',52,'宋词/ci.song.8000.json','["一叶鉴中来，两岸青山起。", "送我红蕖万柄香，疑在蓬壶里。", "天地莹无尘，巾袂凉如水。", "白浪无声月自高，不是人间世。"]'),
('song-ci-547','人月圆','陈知柔','宋','宋词','song-ci','人月圆','[]','鬓缘心事随时改，依旧在天涯。',29,'宋词/ci.song.8000.json','["鬓缘心事随时改，依旧在天涯。", "多情惟有，篱边黄菊，到处能华。"]'),
('song-ci-548','水调歌头','王识','宋','宋词','song-ci','水调歌头','[]','一雨洗空阁，象纬迫人清。',114,'宋词/ci.song.8000.json','["一雨洗空阁，象纬迫人清。", "披襟台上，坐看北斗正旋衡。", "知是南宫列宿，初出极星未远，龙角正分明。", "河汉馀千里，风露已三更。", "坐未久，书帙散，酒壶倾。", "凉生殿阁，冷然邀我御风行。", "拟欲乘槎一问，但得天孙领略，安用访君平。", "莫笑儒生事，造化掌中生。"]'),
('song-ci-549','临江仙','许庭','宋','宋词','song-ci','临江仙','[]','不见昭阳宫内柳，黄金齐拈轻柔。',68,'宋词/ci.song.8000.json','["不见昭阳宫内柳，黄金齐拈轻柔。", "东君昨夜到皇州。", "玉阶金井，无处不风流。", "怅望翠华春欲暮，六宫都锁春愁。", "暖风吹动绣帘钩。", "飞花委地，时转玉香球。"]'),
('song-ci-550','临江仙','许庭','宋','宋词','song-ci','临江仙','[]','不见隋河堤上柳，绿阴流水依依。',69,'宋词/ci.song.8000.json','["不见隋河堤上柳，绿阴流水依依。", "龙舟东下疾於飞。", "千条万叶，浓翠染旌旗。", "记得当年春去也，锦帆不见西归。", "故抛轻絮点人衣。", "如将亡国恨，说与路人知。"]'),
('song-ci-551','临江仙','许庭','宋','宋词','song-ci','临江仙','[]','不见陶家门外柳，柴扉一径遥通。',68,'宋词/ci.song.8000.json','["不见陶家门外柳，柴扉一径遥通。", "闭门终日掩清风。", "感君高节，绿荫向人浓。", "篱落萧疏鸡犬静，日长飞絮濛濛。", "先生一醉万缘空。", "经时高卧，不到翠阴中。"]'),
('song-ci-552','临江仙','许庭','宋','宋词','song-ci','临江仙','[]','不见都门亭畔柳，春来绿尽长条。',68,'宋词/ci.song.8000.json','["不见都门亭畔柳，春来绿尽长条。", "柳边行色马萧萧。", "一枝折赠，相见又何朝。", "酒尽曲终人去也，风前亦自无聊。", "祗应於我恨偏饶。", "东君特地，付与沈郎腰。"]'),
('song-ci-553','临江仙','许庭','宋','宋词','song-ci','临江仙','[]','不见灞陵原上柳，往来过尽蹄轮。',68,'宋词/ci.song.8000.json','["不见灞陵原上柳，往来过尽蹄轮。", "朝离南楚暮西秦。", "不成名利，赢得鬓毛新。", "莫怪枝条憔悴损，一生唯苦征尘。", "两三烟树倚孤村。", "夕阳影里，愁杀宦游人。"]'),
('song-ci-554','清平乐','邵某','宋','宋词','song-ci','清平乐','[]','阿郎去日。',54,'宋词/ci.song.8000.json','["阿郎去日。", "不道长为客。", "底事桐庐无处觅。", "却得广州消息。", "江头一支兰船。", "风雨湘妃庙前。", "死恨无情江水，送郎一去三年。"]'),
('song-ci-555','如梦令','陈祖安','宋','宋词','song-ci','如梦令','[]','月直金波潋滟。',40,'宋词/ci.song.8000.json','["月直金波潋滟。", "此去水仙不远。", "霜重夜风清，骨冷□□□□。", "谁见。", "谁见。", "醉眼参横斗转。"]'),
('song-ci-556','二郎神','王十朋','宋','宋词','song-ci','二郎神','[]','深深院。',129,'宋词/ci.song.8000.json','["深深院。", "夜雨过，帘栊高卷。", "正满槛、海棠开欲半。", "仍朵朵、红深红浅。", "遥认三千宫女面。", "匀点点、胭脂未遍。", "更微带、春醪宿醉，袅娜香肌娇艳。", "日暖。", "芳心暗吐，含羞轻颤。", "笑繁杏夭桃争烂漫。", "爱容易、出墙临岸。", "子美当年游蜀苑。", "又岂是、无心眷恋。", "都只为、天然体态，难把诗工裁翦。"]'),
('song-ci-557','点绛唇','王十朋','宋','宋词','song-ci','点绛唇','[]','野态芳姿，枝头占得春长久。',50,'宋词/ci.song.8000.json','["野态芳姿，枝头占得春长久。", "怕钩衣袖。", "不放攀花手。", "试问东山，花似当时否。", "还依旧。", "谪仙去后。", "风月今谁有。"]'),
('song-ci-558','点绛唇','王十朋','宋','宋词','song-ci','点绛唇','[]','庭院深深，异香一片来天上。',50,'宋词/ci.song.8000.json','["庭院深深，异香一片来天上。", "傲春迟放。", "百卉皆推让。", "忆昔西都，姚魏声名旺。", "堪惆怅。", "醉翁何往。", "谁与花标榜。"]'),
('song-ci-559','点绛唇','王十朋','宋','宋词','song-ci','点绛唇','[]','近侍盈盈，向人自笑还无语。',50,'宋词/ci.song.8000.json','["近侍盈盈，向人自笑还无语。", "牡丹飘雨。", "开作群芳主。", "柔美温香，剪染劳天女。", "青春去。", "花间歌舞。", "学个狂韩愈。"]'),
('song-ci-560','点绛唇','王十朋','宋','宋词','song-ci','点绛唇','[]','芳友依依，结根遥向深林外。',50,'宋词/ci.song.8000.json','["芳友依依，结根遥向深林外。", "国香风递。", "始见殊萧艾。", "雅操幽姿，不怕无人采。", "堪纫佩。", "灵均千载。", "九畹遗芳在。"]'),
('song-ci-561','点绛唇','王十朋','宋','宋词','song-ci','点绛唇','[]','仙友苍苍，西风吹散天香好。',50,'宋词/ci.song.8000.json','["仙友苍苍，西风吹散天香好。", "暗飘龙脑。", "金栗枝头小。", "谁种丹霄，造化玄功妙。", "真堪笑。", "学仙疏谬。", "有似西河老。"]'),
('song-ci-562','点绛唇','王十朋','宋','宋词','song-ci','点绛唇','[]','雪径深深，北枝贪睡南枝醒。',50,'宋词/ci.song.8000.json','["雪径深深，北枝贪睡南枝醒。", "暗香疏影。", "孤压群芳顶。", "玉艳冰姿，妆点园林景。", "凭阑咏。", "月明溪静。", "忆昔林和靖。"]'),
('song-ci-563','点绛唇','王十朋','宋','宋词','song-ci','点绛唇','[]','霜蕊鲜鲜，野人开径新栽植。',50,'宋词/ci.song.8000.json','["霜蕊鲜鲜，野人开径新栽植。", "冷香佳色。", "趁得重阳摘。", "预约比邻，有酒须相觅。", "东篱侧。", "为花辞职。", "古有陶彭泽。"]'),
('song-ci-564','点绛唇','王十朋','宋','宋词','song-ci','点绛唇','[]','羽盖垂垂，玉英乱簇春光满。',50,'宋词/ci.song.8000.json','["羽盖垂垂，玉英乱簇春光满。", "韵香清远。", "暖日烘庭院。", "露褒琼枝，脸透何郎晕。", "凝余恨。", "古人不见。", "谁与花公论。"]'),
('song-ci-565','点绛唇','王十朋','宋','宋词','song-ci','点绛唇','[]','毗舍遥遥，异香一炷驰名久。',50,'宋词/ci.song.8000.json','["毗舍遥遥，异香一炷驰名久。", "妙香稀有。", "鼻观深参透。", "问讯东来，知□谁先后。", "称仙友。", "十花为偶。", "近有江西守。"]'),
('song-ci-566','点绛唇','王十朋','宋','宋词','song-ci','点绛唇','[]','春色融融，东风吹散花千树。',50,'宋词/ci.song.8000.json','["春色融融，东风吹散花千树。", "雪香飘处。", "寒食江村暮。", "左掖看花，多少词人赋。", "花无语。", "一枝春雨。", "惟有香山句。"]'),
('song-ci-567','点绛唇','王十朋','宋','宋词','song-ci','点绛唇','[]','秀色娟娟，最宜雨沐风梳际。',50,'宋词/ci.song.8000.json','["秀色娟娟，最宜雨沐风梳际。", "径幽香细。", "草滴青襟袂。", "一日才无，便觉生尘态。", "轩窗外。", "数竿相对。", "不减王猷爱。"]'),
('song-ci-568','点绛唇','王十朋','宋','宋词','song-ci','点绛唇','[]','丝蕊垂垂，嫣然一笑新妆就。',50,'宋词/ci.song.8000.json','["丝蕊垂垂，嫣然一笑新妆就。", "锦亭前后。", "燕子来时候。", "谁恨无香，试把花枝嗅。", "风微透。", "细熏锦袖。", "不止嘉州有。"]'),
('song-ci-569','点绛唇','王十朋','宋','宋词','song-ci','点绛唇','["\u897f\u6e56"]','十里西湖，淡妆浓抹如西子。',50,'宋词/ci.song.8000.json','["十里西湖，淡妆浓抹如西子。", "藕花簪水。", "清净香无比。", "记得曾游，短棹红云里。", "聊相拟。", "一盆池水。", "十里西湖似。"]'),
('song-ci-570','点绛唇','王十朋','宋','宋词','song-ci','点绛唇','[]','畏日炎炎，梵香一炷熏亭院。',50,'宋词/ci.song.8000.json','["畏日炎炎，梵香一炷熏亭院。", "鼻根充满。", "好利心殊浅。", "贝叶书名，名义谁能辨。", "西风远。", "胜鬟不见。", "喜见琼花面。"]'),
('song-ci-571','点绛唇','王十朋','宋','宋词','song-ci','点绛唇','[]','南国名花，向人无语长含笑。',50,'宋词/ci.song.8000.json','["南国名花，向人无语长含笑。", "缘香囊小。", "不肯全开了。", "花笑何人，鹤相诗词好。", "须知道。", "一经品藻。", "又压前诗倒。"]'),
('song-ci-572','点绛唇','王十朋','宋','宋词','song-ci','点绛唇','[]','蜡换梅姿，天然香韵初非俗。',50,'宋词/ci.song.8000.json','["蜡换梅姿，天然香韵初非俗。", "蝶驰蜂逐。", "蜜在花梢熟。", "岩壑深藏，几载甘幽独。", "因坡谷。", "一标题目。", "高价掀兰菊。"]'),
('song-ci-573','点绛唇','王十朋','宋','宋词','song-ci','点绛唇','[]','清夜沈沈，携来深院柔枝小。',50,'宋词/ci.song.8000.json','["清夜沈沈，携来深院柔枝小。", "俪兰开巧。", "雪里乘风袅。", "温室寒祛，旖旎仙姿早。", "看成好。", "花仙欢笑。", "不管年华老。"]'),
('song-ci-574','点绛唇','王十朋','宋','宋词','song-ci','点绛唇','[]','落木萧萧，琉璃叶下琼葩吐。',50,'宋词/ci.song.8000.json','["落木萧萧，琉璃叶下琼葩吐。", "素香柔树。", "雅称幽人趣。", "无意争先，梅蕊休相妒。", "含春雨。", "结愁千绪。", "似忆江南主。"]'),
('song-ci-575','点绛唇','王十朋','宋','宋词','song-ci','点绛唇','[]','阑槛阴沈，紫云呈瑞馀寒凛。',50,'宋词/ci.song.8000.json','["阑槛阴沈，紫云呈瑞馀寒凛。", "卷帘猗枕。", "香逼幽人寝。", "入梦何年，庐阜闻名稔。", "风流甚。", "阿谁题品。", "唤作熏笼锦。"]'),
('song-ci-576','失调名','刘大辨','宋','宋词','song-ci','失调名','[]','凌云多少功业。',7,'宋词/ci.song.8000.json','["凌云多少功业。"]'),
('song-ci-577','长相思令・长相思','吴淑姬2','宋','宋词','song-ci','长相思令・长相思','[]','烟霏霏。',44,'宋词/ci.song.8000.json','["烟霏霏。", "雪霏霏。", "雪向梅花枝上堆。", "春从何处回。", "醉眼开。", "睡眼开。", "疏影横斜安在哉。", "从教塞管催。"]'),
('song-ci-578','锁窗寒・琐寒窗','程先','宋','宋词','song-ci','锁窗寒・琐寒窗','[]','雨洗红尘，云迷翠麓，小车难去。',119,'宋词/ci.song.8000.json','["雨洗红尘，云迷翠麓，小车难去。", "凄凉感慨，未有今年春暮。", "想曲江水边丽人，影沈香歇谁为主。", "但兔葵燕麦，风前摇荡，径花成土。", "空被多情苦。", "庆会难逢，少年几许。", "纷纷沸鼎，负了青阳百五。", "待何时、重享太平，典衣贳酒相尔汝。", "算兰亭、有此欢娱，又却悲今古。"]'),
('song-ci-579','瑞鹤仙','朱耆寿','宋','宋词','song-ci','瑞鹤仙','[]','樱桃抄乳酪。',127,'宋词/ci.song.8000.json','["樱桃抄乳酪。", "正雨厌肥梅，风忺吹箨。", "咸瞻格天阁。", "见十眉环侍，争鸣弦索。", "茶瓯试瀹。", "更良夜、沈沈细酌。", "问间生、此日为谁，曾向玉皇、案前持橐。", "龟鹤。", "从他祝寿，未比当年，阴功堪托。", "天应不错。", "教公议，细评泊。", "自和戎以来，谋国多少，萧曹卫霍。", "奈胡儿自若，惟守绍兴旧约。"]'),
('song-ci-580','西江月','石安民','宋','宋词','song-ci','西江月','[]','飞阁下临无地，层峦上出重霄。',58,'宋词/ci.song.8000.json','["飞阁下临无地，层峦上出重霄。", "重阳未到客登高。", "信是今年秋早。", "随意烟霞笑傲，多情猿鹤招邀。", "山翁笑我太丰标。", "竹杖棕鞋桐帽。"]'),
('song-ci-581','贺新郎','刘镇1','宋','宋词','song-ci','贺新郎','[]','翠葆摇新竹。',142,'宋词/ci.song.8000.json','["翠葆摇新竹。", "正榴花、枝头叶底，斗红争绿。", "谁在纱窗停针线，闲理竹西旧曲。", "又还是、兰汤新浴。", "手弄合欢双彩索，笑偎人、福寿低相祝。", "金凤亸，艾花矗。", "龙舟噀水飞相逐。", "记当年、怀沙旧恨，至今遗俗。", "雨过平芜浮天阔，画艗凌波尽簇。", "沸十里、笙歌声续。", "好是蟾钩随归棹，任欢呼、船重成颓玉。", "犹未忍，罩银烛。"]'),
('song-ci-582','天香','刘镇1','宋','宋词','song-ci','天香','[]','漠漠江皋，迢迢驿路，天教为春传信。',115,'宋词/ci.song.8000.json','["漠漠江皋，迢迢驿路，天教为春传信。", "万木丛边，百花头上，不管雪飞风紧。", "寻交访旧，惟翠竹、寒松相认。", "不意牵丝动兴，何心衬妆添晕。", "孤标最甘冷落，不许蝶亲蜂近。", "直自从来洁白，个中清韵。", "尽做重闻塞管，也何害、香销粉痕尽。", "待到和羹，才明底蕴。"]'),
('song-ci-583','失调名','魏掞之','宋','宋词','song-ci','失调名','[]','挂天师，撑著眼，直下觑。',45,'宋词/ci.song.8000.json','["挂天师，撑著眼，直下觑。", "骑个生狞大艾虎。", "闲神浪鬼，辟惵他方远方，大胆底，更敢来、上门下户。"]'),
('song-ci-584','点绛唇','曾协','宋','宋词','song-ci','点绛唇','[]','小驻征骖，一尊古寺留君住。',50,'宋词/ci.song.8000.json','["小驻征骖，一尊古寺留君住。", "六花无数。", "飞舞朝天路。", "上苑繁华，却似词章富。", "春将暮。", "玉鞭凝伫。", "总是经行处。"]'),
('song-ci-585','点绛唇','曾协','宋','宋词','song-ci','点绛唇','[]','乱叠香罗，玉纤微把燕支污。',50,'宋词/ci.song.8000.json','["乱叠香罗，玉纤微把燕支污。", "靓妆无数。", "十里扬州路。", "怨绿啼红，总道春归去。", "君知否。", "画阑幽处。", "留得韶光住。"]'),
('song-ci-586','浣溪沙','曾协','宋','宋词','song-ci','浣溪沙','[]','昼漏新来一倍长。',48,'宋词/ci.song.8000.json','["昼漏新来一倍长。", "众宾沾醉尚传觞。", "浓云遮日惜红妆。", "应是主人归凤沼，为传芳讯到黄堂。", "腰围恰恰束金黄。"]'),
('song-ci-587','秦楼月・忆秦娥','曾协','宋','宋词','song-ci','秦楼月・忆秦娥','[]','清秋月。',56,'宋词/ci.song.8000.json','["清秋月。", "长空万里烟华白。", "烟华白。", "江云收尽，楚天一色。", "莼丝惹起思归客。", "清光正好伤离别。", "伤离别。", "五湖烟水，伴人愁绝。"]'),
('song-ci-588','桃源忆故人','曾协','宋','宋词','song-ci','桃源忆故人','[]','野亭问柳今朝试。',56,'宋词/ci.song.8000.json','["野亭问柳今朝试。", "更访小园开未。", "月下山横空际。", "两两修眉对。", "骚人对此增高致。", "意入笔端清邃。", "投分周郎心醉。", "真解消人意。"]'),
('song-ci-589','踏莎行','曾协','宋','宋词','song-ci','踏莎行','[]','柳眼传情，花心蹙恨。',68,'宋词/ci.song.8000.json','["柳眼传情，花心蹙恨。", "春风处处关方寸。", "朱帘卷尽画屏间，云鬟半亸罗衣褪。", "燕语莺啼，日长人困。", "鱼沈雁断无音信。", "琵琶声乱篆烟斜，寸肠欲断无人问。"]'),
('song-ci-590','凤栖梧・蝶恋花','曾协','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','柳弄轻黄花泣露。',70,'宋词/ci.song.8000.json','["柳弄轻黄花泣露。", "万叠春山，不记尘寰路。", "日射霜林烟罩素。", "长空不著纤云污。", "历历远村明可数。", "绿涨前溪，渺渺迷津渡。", "客子光阴能几许。", "画图拟卷晴川去。"]'),
('song-ci-591','祝英台・祝英台近','曾协','宋','宋词','song-ci','祝英台・祝英台近','[]','放花开，催花谢，谁解东君意。',95,'宋词/ci.song.8000.json','["放花开，催花谢，谁解东君意。", "要遣花王，独占花蹊邃。", "且看玉镜台前，霞觞新举，红玉软、晓妆慵试。", "好风味。", "须信金屋中人，谁堪并娇媚。", "隐约微潮，应向尊前醉。", "最怜纹锦搴帷，青罗飞盖，尘土外、轻盈相倚。"]'),
('song-ci-592','水调歌头','曾协','宋','宋词','song-ci','水调歌头','[]','今日复何日，欢动楚江滨。',114,'宋词/ci.song.8000.json','["今日复何日，欢动楚江滨。", "紫泥来自天上，优诏起元臣。", "想见傅岩梦断，记得金瓯名在，却念佩兰人。", "永昼通明殿，曾听话经纶。", "促归装，趋北阙，觐严宸。", "玉阶陈迹如故，天笑一番新。", "好借食间前箸，尽吐胸中奇计，指顾静烟尘。", "九万云霄路，飞走趁新春。"]'),
('song-ci-593','水调歌头','曾协','宋','宋词','song-ci','水调歌头','[]','日永向槐夏，绕屋树扶疏。',114,'宋词/ci.song.8000.json','["日永向槐夏，绕屋树扶疏。", "麦秋天气清润，设帨记生初。", "新拜小君佳号，更过诸郎官舍，仍玩掌中珠。", "乐事似今少，一笑倒双壶。", "列山肴，烹野蔌，且欢娱。", "鹿门远引，平生此志与君俱。", "终向苕溪烟水，携手云庄风月，不践利名区。", "功业看儿辈，相对老江湖。"]'),
('song-ci-594','酹江月・念奴娇','曾协','宋','宋词','song-ci','酹江月・念奴娇','[]','一年好处，是霜轻尘敛，山川如洗。',120,'宋词/ci.song.8000.json','["一年好处，是霜轻尘敛，山川如洗。", "晚菊留花供燕赏，金缕宝衣销地。", "旧观初还，层楼相望，重见升平际。", "小春时节，绮罗丛里人醉。", "此日武帐贤侯，六年仁政，浃长淮千里。", "欲入鹓行仍缓带，聊抚竹西歌吹。", "紫塞烟清，玉关人老，宜趣朝天骑。", "香尘归路，旧游回首应记。"]'),
('song-ci-595','酹江月・念奴娇','曾协','宋','宋词','song-ci','酹江月・念奴娇','[]','苕溪古岸，有朱门初建，落成华屋。',120,'宋词/ci.song.8000.json','["苕溪古岸，有朱门初建，落成华屋。", "对启园林随杖履，迤逦柳蹊相属。", "好是危亭，片峰迎面，独立清溪曲。", "芜城低远，一尘不碍游目。", "公子豪饮方酣，夜堂深静，隐隐鸣丝竹。", "却尽春寒宾满座，深酌葡萄新绿。", "密户储香，广庭留月，待得清欢足。", "纷纷沾醉，四筵倒尽群玉。"]'),
('song-ci-596','酹江月・念奴娇','曾协','宋','宋词','song-ci','酹江月・念奴娇','[]','一年好处，是满城红药，留连□□。',120,'宋词/ci.song.8000.json','["一年好处，是满城红药，留连□□。", "十里扬州应费了，多少春工妆饰。", "弱质敧风，芳心带露，酒困娇无力。", "园林绿暗，粉光低占丛碧。", "谁与千载声名，翻阶高咏，出文章仙伯。", "阅尽繁华芳意歇，初识倾城风格。", "双脸晞红，春衫挽并，天巧终难敌。", "十千沽酒，算应花畔消得。"]'),
('song-ci-597','水龙吟','曾协','宋','宋词','song-ci','水龙吟','[]','楚乡菰黍初尝，马蹄偶踏扬州路。',125,'宋词/ci.song.8000.json','["楚乡菰黍初尝，马蹄偶踏扬州路。", "莼丝向老，江鲈堪脍，催人归去。", "秋气萧骚，月华如洗，一天风露。", "望重重烟水，吴淞万顷，曾约旧时鸥鹭。", "惆怅别离无奈，整孤帆、依然回顾。", "玉龙节底，故人情重，欲行犹驻。", "敛散功多，澄清志遂，好回高步。", "看归鞍稳上，文鸳班里，五云深处。"]'),
('song-ci-598','水调歌头','郑庶','宋','宋词','song-ci','水调歌头','[]','千古钓台下，老尽去来人。',114,'宋词/ci.song.8000.json','["千古钓台下，老尽去来人。", "倚空绝壁，朝暮秀色只如春。", "高挂瀑泉千尺，洗到云根山骨，无处著风尘。", "秋尽玉壶冷，别是一乾坤。", "问当日，中兴将，汉功臣。", "云台何在，寂寞谁复记丹青。", "争似先生标致，长共清风明月，不减旧精神。", "无限兴亡意，舒卷在丝纶。"]'),
('song-ci-599','好事近','曾逮','宋','宋词','song-ci','好事近','[]','满树叶繁枝重，缀青黄千百。',13,'宋词/ci.song.8000.json','["满树叶繁枝重，缀青黄千百。"]'),
('song-ci-600','菩萨蛮','王炎1','宋','宋词','song-ci','菩萨蛮','[]','远风江急潮来晚。',52,'宋词/ci.song.8000.json','["远风江急潮来晚。", "晚来潮急江风远。", "横岸断山青。", "青山断岸横。", "寄书无雁系。", "系雁无书寄。", "归梦只江西。", "西江只梦归。"]'),
('song-ci-601','梅花引','王炎1','宋','宋词','song-ci','梅花引','[]','裁征衣。',70,'宋词/ci.song.8000.json','["裁征衣。", "寄征衣。", "万里征人音信稀。", "朝相思。", "暮相思。", "滴尽真珠，如今无泪垂。", "闺中幼妇红颜少。", "应是玉关人更老。", "几时归。", "几时归。", "开尽牡丹，看看到荼䕷。"]'),
('song-ci-602','水调歌头','毛并','宋','宋词','song-ci','水调歌头','[]','襟带大江左，平望见三州。',114,'宋词/ci.song.8000.json','["襟带大江左，平望见三州。", "凿空遗迹，千古奇胜米公楼。", "太守中朝耆旧，别乘当今豪逸，人物眇应刘。", "此地一尊酒，歌吹拥貔貅。", "楚山晓，淮月夜，海门秋。", "登临无尽，须信诗眼不供愁。", "恨我相望千里，空想一时高唱，零落几人收。", "妙赏频回首，谁复继风流。"]'),
('song-ci-603','水调歌头','毛并','宋','宋词','song-ci','水调歌头','[]','春意满南国，花动雪明楼。',114,'宋词/ci.song.8000.json','["春意满南国，花动雪明楼。", "千坊万井，此时灯火隘追游。", "十里寒星相照，一轮明月斜挂，缥缈映红球。", "共嬉不禁夜，光彩遍飞浮。", "艳神仙，轰鼓吹，引遨头。", "文章太守，此时宾从敌应刘。", "回首生平旧事，未减当年风月，一醉为君酬。", "明日朝天去，空复想风流。"]'),
('song-ci-604','水调歌头','毛并','宋','宋词','song-ci','水调歌头','[]','小筑百年计，雅志几人成。',114,'宋词/ci.song.8000.json','["小筑百年计，雅志几人成。", "乱山深处，烟雨面面对萦青。", "巾屦方安吾土，花木仍供真赏，邻有阮嵇生。", "岁月抛身外，尘事更无营。", "鸟知归，云出岫，两忘情。", "从渠华屋，回首烟草吊颓倾。", "何似生涯才足，敧枕南窗北牖，醉梦落樵声。", "更喜濯缨处，门外一江清。"]'),
('song-ci-605','水调歌头','毛并','宋','宋词','song-ci','水调歌头','[]','汉代李元礼，江左管夷吾。',114,'宋词/ci.song.8000.json','["汉代李元礼，江左管夷吾。", "英姿雅望，凛凛玉立冠中都。", "礧磈胸中千丈，不肯低回青禁，引去卧江湖。", "更学鸱夷子，一舸下东吴。", "送公别，杯酒尽，少踌躇。", "旧棠阴下，几人临路拥行车。", "归近云天尺五，梦想经纶贤业，谈笑取单于。", "为问苕溪水，留得此翁无。"]'),
('song-ci-606','水调歌头','毛并','宋','宋词','song-ci','水调歌头','[]','十载刘夫子，名过庾兰成。',114,'宋词/ci.song.8000.json','["十载刘夫子，名过庾兰成。", "人人争看，角犀今喜试丰盈。", "倾耳新诗千首，妙处端须击节，金石破虫声。", "此士难复得，黄口闹如羹。", "忆年少，游侠窟，戏荆卿。", "结交投分，驰心千里剧摇旌。", "我老公方豪健，傥许相从晚岁，慷慨激中情。", "洗眼功名会，一箭取辽城。"]'),
('song-ci-607','秋蕊香','毛并','宋','宋词','song-ci','秋蕊香','[]','荡暖花风满路。',56,'宋词/ci.song.8000.json','["荡暖花风满路。", "织翠柳阴和雾。", "曲池斗草旧游处。", "忆试春衫白苎。", "暗惊节意朱弦柱。", "送春去。", "晓来一阵扫花雨。", "惆怅蔷薇在否。"]'),
('song-ci-608','满庭芳','毛并','宋','宋词','song-ci','满庭芳','[]','世事难穷，人生无定，偶然蓬转萍浮。',118,'宋词/ci.song.8000.json','["世事难穷，人生无定，偶然蓬转萍浮。", "为谁教我，从宦到东州。", "还似翩翩海燕，乘春至、归及凉秋。", "回头笑，浑家数口，又泛五湖舟。", "悠悠。", "当此去，黄童白叟，莫漫相留。", "但溪山好处，深负重游。", "珍重诸公送我，临岐泪、欲语先流。", "应须记，从今风月，相忆在南楼。"]'),
('song-ci-609','满庭芳','毛并','宋','宋词','song-ci','满庭芳','[]','五十年来，追思畴曩，佳时去若云浮。',118,'宋词/ci.song.8000.json','["五十年来，追思畴曩，佳时去若云浮。", "依然重见，感涕话西州。", "幸喜灵光不改，空自笑、蒲柳先秋。", "成何事，风波末路，险畏有沈舟。", "别愁。", "都几许，相从未斁，我去公留。", "况狂直平生，谁念遨游。", "月夕风天正好，还惊怅、失此诗流。", "江南岸，明朝更远，回首仲宣楼。"]'),
('song-ci-610','满庭芳','毛并','宋','宋词','song-ci','满庭芳','[]','濩落难容，崎岖堪笑，一年陆走川浮。',118,'宋词/ci.song.8000.json','["濩落难容，崎岖堪笑，一年陆走川浮。", "又携妻子，两度过神州。", "紫蟹鲈鱼正美，凉天气、恰傍中秋。", "今宵意，无人伴我，快泻玉双舟。", "功名，聊尔耳，千金聘楚，万户封留。", "又争如物外，闲旷优游。", "好在东阡北陌，相从有、诸老风流。", "家山近，归休去也，不上望京楼。"]'),
('song-ci-611','渔家傲','毛并','宋','宋词','song-ci','渔家傲','[]','极目丹枫迎霁晓。',72,'宋词/ci.song.8000.json','["极目丹枫迎霁晓。", "山明水净新霜早。", "燕去鸿归无事了。", "天渺渺。", "风吹平野低寒草。", "渐过初冬时节好。", "寻梅踏雪城南道。", "追忆旧游人已老。", "欢更少。", "孤怀拟共谁倾倒。"]'),
('song-ci-612','好事近','毛并','宋','宋词','song-ci','好事近','[]','飞盖满南园，想见八仙遥集。',53,'宋词/ci.song.8000.json','["飞盖满南园，想见八仙遥集。", "几树海棠开遍，正新晴天色。", "休辞一醉任扶还，衣上酒痕湿。", "便恐岁华催去，听秋虫相泣。"]'),
('song-ci-613','贺新郎','毛并','宋','宋词','song-ci','贺新郎','[]','风雨连朝夕。',142,'宋词/ci.song.8000.json','["风雨连朝夕。", "最惊心、春光晼晚，又过寒食。", "落尽一番新桃李，芳草南园似积。", "但燕子、归来幽寂。", "况是单栖饶惆怅，尽无聊、有梦寒犹力。", "春意远，恨虚掷。", "东君自是人间客。", "暂时来、匆匆却去，为谁留得。", "走马插花当年事，池畹空馀旧迹。", "奈老去、流光堪惜。", "杳隔天涯人千里，念无凭、寄此长相忆。", "回首处，暮云碧。"]'),
('song-ci-614','念奴娇','毛并','宋','宋词','song-ci','念奴娇','[]','层栏飞栋，压孤城临瞰，并吞空阔。',120,'宋词/ci.song.8000.json','["层栏飞栋，压孤城临瞰，并吞空阔。", "千古吴京佳丽地，一览江山奇绝。", "天际归舟，云中行树，鹭点汀洲雪。", "三山无际，眇然相望溟渤。", "凤么遗响悲凉，故台今不见，苍烟芜没。", "千骑重来初起废，缅想六朝人物。", "岘首他年，羊公终在，笑几人磨灭。", "一时尊俎，且须同赋风月。"]'),
('song-ci-615','念奴娇','毛并','宋','宋词','song-ci','念奴娇','[]','少年奇志，笑功名画虎，文章刻鹄。',120,'宋词/ci.song.8000.json','["少年奇志，笑功名画虎，文章刻鹄。", "永夜漫漫悲昼短，难挽苍龙衔烛。", "飞藿飘零，浮云迁变，过眼邮传速。", "昔人真意，眇然千载谁属。", "犹喜二子当年，诸公籍甚，赏云和孤竹。", "翰墨流传知几许，遗响宫商相续。", "梦里京华，不须惊叹，春草年年绿。", "赤霄归去，更看奔电喷玉。"]'),
('song-ci-616','念奴娇','毛并','宋','宋词','song-ci','念奴娇','[]','十年湖海，叹潘郎憔悴，无心云阁。',120,'宋词/ci.song.8000.json','["十年湖海，叹潘郎憔悴，无心云阁。", "强起登临惊暮序，目极清霜摇落。", "散发层阿，振衣千仞，浩荡穷林壑。", "泬寥无际，镜天收尽云脚。", "长啸声落悲风，想沧州万里，当年归约。", "回首区中无限事，此意谁同商略。", "欲驾飞鸿，翩然独往，汗漫期相诺。", "滞留何事，坐令双鬓如鹤。"]'),
('song-ci-617','念奴娇','毛并','宋','宋词','song-ci','念奴娇','[]','丽谯春晚，望东南千里，湖山佳色。',120,'宋词/ci.song.8000.json','["丽谯春晚，望东南千里，湖山佳色。", "画戟门前清似水，时节初过灯夕。", "封井年登，京华日近，每报平安驿。", "满城花柳，正须千骑寻觅。", "忆我年少追游，叨兔园客右，多惭英识。", "今日怀人无限意，老泪尊前重滴。", "赋咏空传，雄豪谁在，鬓点吴霜白。", "招呼一醉，幸公时慰愁寂。"]'),
('song-ci-618','念奴娇','毛并','宋','宋词','song-ci','念奴娇','[]','倚风含露，似轻颦微笑，盈盈脉脉。',121,'宋词/ci.song.8000.json','["倚风含露，似轻颦微笑，盈盈脉脉。", "染素匀红，知费尽，多少东君心力。", "国艳酣晴，天香融暖，画手争传得。", "绿窗朱户，晓妆谁见凝寂。", "独占三月芳菲，千花百卉，算难争春色。", "欲寄朝云无限意，回首京尘犹隔。", "舞破霓裳，一枝浑似，醉倚香亭北。", "旧欢如梦，老怀那更追惜。"]'),
('song-ci-619','念奴娇','毛并','宋','宋词','song-ci','念奴娇','[]','王孙老去，算无地倾倒，胸中豪逸。',120,'宋词/ci.song.8000.json','["王孙老去，算无地倾倒，胸中豪逸。", "小筑三间便席卷，多少江山风月。", "万壑回流，千峰输秀，人境成三绝。", "登临佳处，鸟飞不尽空阔。", "追念辋水斜川，有风流千载，渊明摩诘。", "何必斯人聊一笑，俯仰今犹前日。", "只恐东州，催成棠阴，又作三年别。", "赏心难继，莫教辜负华发。"]'),
('song-ci-620','念奴娇','毛并','宋','宋词','song-ci','念奴娇','[]','阿环家住阆风顶，绛阙瑶台相接。',119,'宋词/ci.song.8000.json','["阿环家住阆风顶，绛阙瑶台相接。", "翳凤乘鸾人不见，隐隐霓裳云衱。", "秀骨贞风，长眉翠浅，映白喉红颊。", "非烟深处，渺然云浪千叠。", "一笑徐福扁舟，春风空老尽，当时童妾。", "骨冷魂清惊梦到，同看碧桃千叶。", "寄语青童，何时丹就，为我留穷笈。", "天鸡催晓，却愁吹堕尘劫。"]'),
('song-ci-621','念奴娇','毛并','宋','宋词','song-ci','念奴娇','[]','素秋新霁，风露洗寥廓，珠宫琼阙。',120,'宋词/ci.song.8000.json','["素秋新霁，风露洗寥廓，珠宫琼阙。", "帘幕生寒人未定，鹊羽惊飞林樾。", "河汉无声，微云收尽，相映寒光发。", "三千银界，一时无此奇绝。", "正是老子南楼，多情孤负了，十分佳节。", "起舞徘徊谁为我，倾倒杯中明月。", "欲揽姮娥，扁舟沧海，戏濯凌波袜。", "漏残钟断，坐愁人世超忽。"]'),
('song-ci-622','满江红','毛并','宋','宋词','song-ci','满江红','[]','东马严徐，名籍甚、西京人物。',115,'宋词/ci.song.8000.json','["东马严徐，名籍甚、西京人物。", "谁不羡、伏蒲忠鲠，演纶词笔。", "雅意中朝今小试，二年东郡弦风迹。", "数中兴、循吏两三人，公居一。", "温诏趣，还丹阙。", "倾睿相，方前席。", "看云台登践，论思密勿。", "超览堂中遗爱在，几人同恋津亭别。", "顾倦游、云路仆登仙，心如失。"]'),
('song-ci-623','满江红','毛并','宋','宋词','song-ci','满江红','[]','回首吾庐，思归去、石溪樵谷。',115,'宋词/ci.song.8000.json','["回首吾庐，思归去、石溪樵谷。", "临玩有、门前流水，乱松疏竹。", "幽草春馀荒井迳，鸣禽日在窥墙屋。", "但等闲、凭几看南山，云相逐。", "家酿美，招邻曲。", "朝饭饱，随耕牧。", "况东皋二顷，岁时都足。", "鳞阁功名身外事，墙阴不驻流光促。", "更休论、一枕梦中惊，黄粱熟。"]'),
('song-ci-624','水龙吟','毛并','宋','宋词','song-ci','水龙吟','["\u592a\u6e56"]','渺然震泽东来，太湖望极平无际。',126,'宋词/ci.song.8000.json','["渺然震泽东来，太湖望极平无际。", "三吴风月，一江烟浪，古今绝致。", "羽化蓬莱，胸吞云梦，不妨如此。", "看垂虹千丈，斜阳万顷，尽倒影、青奁里。", "追想扁舟去后，对汀洲、白苹风起。", "只今谁会，水光山色，依然西子。", "安得超然，相从物外，此生终矣。", "念素心空在，徂年易失，泪如铅水。"]'),
('song-ci-625','渔家傲','毛并','宋','宋词','song-ci','渔家傲','[]','杨子津头风色暮。',72,'宋词/ci.song.8000.json','["杨子津头风色暮。", "孤舟渺渺江南去。", "忆得佳人临别处。", "愁返顾。", "青山几点斜阳树。", "可忍归期无定据。", "天涯已听边鸿度。", "昨夜乡心留不住。", "无驿数。", "梦中行了来时路。"]'),
('song-ci-626','江城子','毛并','宋','宋词','song-ci','江城子','[]','神仙楼观梵王宫。',86,'宋词/ci.song.8000.json','["神仙楼观梵王宫。", "月当中。", "望难穷。", "坐听三通，谯鼓报笼铜。", "还忆当年京辇旧，车马会，五门东。", "华堂歌舞间笙钟。", "夕香濛。", "度花风。", "翠袖传杯，争劝紫髯翁。", "归去不堪春梦断，烟雨晓，乱山重。"]'),
('song-ci-627','江城子','毛并','宋','宋词','song-ci','江城子','[]','倚墙高树落惊禽。',86,'宋词/ci.song.8000.json','["倚墙高树落惊禽。", "小窗深。", "夜沈沈。", "酒醒灯昏，人静更愁霖。", "惆怅行云留不住，携手处，却分襟。", "悠悠风月两关心。", "拥孤衾。", "恨难禁。", "何况一春，憔悴到如今。", "最苦清宵无寐极，相见梦，也难寻。"]'),
('song-ci-628','画堂春','毛并','宋','宋词','song-ci','画堂春','[]','华灯收尽雪初残。',55,'宋词/ci.song.8000.json','["华灯收尽雪初残。", "踏青还尔游盘。", "落梅强半已飞翻。", "划地春寒。", "多病故人日远，几时双燕来还。", "可怜楼上一凭栏。", "不见长安。"]'),
('song-ci-629','风流子','毛并','宋','宋词','song-ci','风流子','[]','新禽初弄舌，东郊外、催尔踏青期。',135,'宋词/ci.song.8000.json','["新禽初弄舌，东郊外、催尔踏青期。", "渐晴滟翠漪，惠风骀荡，暖蒸红雾，淑景辉迟。", "粉墙外，杏花无限笑，杨柳不胜垂。", "闲里岁华，但惊萧索，老来心赏，尤惜芳菲。", "平生歌酒地，空回首，惆怅触绪沾衣。", "谁见素琴翻恨，青镜留悲。", "念千里云遥，暮天长短，十年人杳，流水东西。", "惟有寄情芳草，依旧萋萋。"]'),
('song-ci-630','浪淘沙','毛并','宋','宋词','song-ci','浪淘沙','[]','帘幕燕双飞。',64,'宋词/ci.song.8000.json','["帘幕燕双飞。", "春共人归。", "东风恻恻雨霏霏。", "水满西池花满地，追惜芳菲。", "回首昔游非。", "别梦依稀。", "一成春瘦不胜衣。", "无限楼前伤远意，芳草斜晖。"]'),
('song-ci-631','醉落魄・一斛珠','毛并','宋','宋词','song-ci','醉落魄・一斛珠','[]','暮寒凄冽。',67,'宋词/ci.song.8000.json','["暮寒凄冽。", "春风探绕南枝发。", "更无人处增清绝。", "冷蕊孤香，竹外朦胧月。", "西洲昨梦凭谁说。", "攀翻剩忆经年别。", "新愁怅望催华发。", "雀啅江头，一树垂垂雪。"]'),
('song-ci-632','眼儿媚','毛并','宋','宋词','song-ci','眼儿媚','[]','小溪微月淡无痕。',58,'宋词/ci.song.8000.json','["小溪微月淡无痕。", "残雪拥孤村。", "攀条弄蕊，春愁相值，寂默无言。", "忍寒宜主何人见，应怯过黄昏。", "朝阳梦断，熏残沈水，谁为招魂。"]'),
('song-ci-633','谒金门','毛并','宋','宋词','song-ci','谒金门','[]','春已半。',53,'宋词/ci.song.8000.json','["春已半。", "芳草池塘绿遍。", "山北山南花烂熳。", "日长蜂蝶乱。", "闲掩屏山六扇。", "梦好强教惊断。", "愁对画梁双语燕。", "故心人不见。"]'),
('song-ci-634','谒金门','毛并','宋','宋词','song-ci','谒金门','[]','伤离索。',53,'宋词/ci.song.8000.json','["伤离索。", "犹记并肩池阁。", "病起绿窗闲倚薄。", "一秋天气恶。", "玉臂都宽金约。", "歌舞新来忘却。", "回首故人天一角。", "半江枫又落。"]'),
('song-ci-635','玉楼春','毛并','宋','宋词','song-ci','玉楼春','[]','日长澹澹光风转。',64,'宋词/ci.song.8000.json','["日长澹澹光风转。", "小尾黄蜂随早燕。", "行寻香迳不逢人，惟有落红千万片。", "酒成憔悴花成怨。", "闲杀羽觞难会面。", "可堪春事已无多，新笋遮墙苔满院。"]'),
('song-ci-636','玉楼春','毛并','宋','宋词','song-ci','玉楼春','[]','曲房小院匆匆过。',64,'宋词/ci.song.8000.json','["曲房小院匆匆过。", "急鼓疏钟催又去。", "来如春梦几多时，去似朝云无觅处。", "金瓶落井翻相误。", "可惜馨香随手故。", "锦囊空有断肠书，彩笔不传长恨句。"]'),
('song-ci-637','蝶恋花','毛并','宋','宋词','song-ci','蝶恋花','[]','罗袜匆匆曾一遇。',70,'宋词/ci.song.8000.json','["罗袜匆匆曾一遇。", "乌鹊归来，怨感流年度。", "别袖空看啼粉污。", "相思待倩谁分付。", "残雪江村回马路。", "袅袅春寒，帘晚空凝伫。", "人在梅花深处住。", "梅花落尽愁无数。"]'),
('song-ci-638','薄幸','毛并','宋','宋词','song-ci','薄幸','[]','柳桥南畔。',132,'宋词/ci.song.8000.json','["柳桥南畔。", "驻骢马、寻春几遍。", "自见了、生尘罗袜，尔许娇波流盼。", "为感郎、松柏深心，西陵已约平生愿。", "记别袖频招，斜门相送，小立钗横鬓乱。", "恨暗写、如蚕纸，空目断、高城人远。", "奈当时消息，黄姑织女，又成王谢堂前燕。", "托琴心怨。", "怕娇云弱雨，东风蓦地轻吹散。", "伤春病也，狼藉飞花满院。"]'),
('song-ci-639','应天长令・应天长','毛并','宋','宋词','song-ci','应天长令・应天长','[]','曲栏十二闲亭沼。',58,'宋词/ci.song.8000.json','["曲栏十二闲亭沼。", "履迹双沈人悄悄。", "被池寒，香炉小。", "梦短女墙莺唤晓。", "柳风轻袅袅。", "门外落花多少。", "日日离愁萦绕。", "不知春过了。"]'),
('song-ci-640','点绛唇','毛并','宋','宋词','song-ci','点绛唇','[]','夜色侵霜，萧萧络纬啼金井。',50,'宋词/ci.song.8000.json','["夜色侵霜，萧萧络纬啼金井。", "梦寒初惊。", "一倍铜壶永。", "无限思量，展转愁重省。", "熏炉冷。", "起来人静。", "窗外梧桐影。"]'),
('song-ci-641','瑞鹤仙','毛并','宋','宋词','song-ci','瑞鹤仙','[]','柳风清昼溽。',126,'宋词/ci.song.8000.json','["柳风清昼溽。", "山樱晚，一树高红争熟。", "轻纱睡初足。", "悄无人、猗枕虚檐鸣玉。", "南园秉烛。", "叹流光、容易过目。", "送春归去，有无数弄禽，满径新竹。", "闲记追欢寻胜，杏栋西厢，粉墙南曲。", "别长会促。", "成何计，奈幽独。", "纵湘弦难寄，韩香终在，屏山蝶梦断续。", "对沿阶、细草萋萋，为谁自绿。"]'),
('song-ci-642','满江红','毛并','宋','宋词','song-ci','满江红','[]','泼水初收，秋千外、轻烟漠漠。',115,'宋词/ci.song.8000.json','["泼水初收，秋千外、轻烟漠漠。", "春渐远、绿杨芳草，燕飞池阁。", "已著单衣寒食后，夜来还是东风恶。", "对空山、寂寂杜鹃啼，梨花落。", "伤别恨，闲情作。", "十载事，惊如昨。", "向花前月下，共谁行乐。", "飞盖低迷南苑路，湔裙怅望东城约。", "但老来、憔悴惜春心，年年觉。"]'),
('song-ci-643','燕山亭','毛并','宋','宋词','song-ci','燕山亭','[]','暖霭辉迟，雨过夜来，帘外春风徐转。',121,'宋词/ci.song.8000.json','["暖霭辉迟，雨过夜来，帘外春风徐转。", "霞散锦舒，密映窥，亭亭万枝开遍。", "一笑嫣然，犹记有、画图曾见。", "无伴。", "初睡起，昭阳弄妆日晚。", "长是相趁佳期，有寻旧流莺，贪新双燕。", "惆怅共谁，细绕花阴，空怀紫箫凄怨。", "银烛光中，且更待、夜深重看。", "留恋。", "愁酒醒、霏千片。"]'),
('song-ci-644','调笑・调笑令','洪适','宋','宋词','song-ci','调笑・调笑令','[]','南土。',45,'宋词/ci.song.8000.json','["南土。", "贤铜虎。", "黄木湾头腾好语。", "骑羊执穗神仙五。", "拭目摩肩争睹。", "无双治行今犹古。", "嘉瑞流传乐府。"]'),
('song-ci-645','调笑・调笑令','洪适','宋','宋词','song-ci','调笑・调笑令','[]','寒食。',45,'宋词/ci.song.8000.json','["寒食。", "人如织。", "藉草临流罗饮席。", "阳春有脚森双戟。", "和气欢声洋溢。", "洲边药灶成陈迹。", "九曜摩挲奇石。"]'),
('song-ci-646','调笑・调笑令','洪适','宋','宋词','song-ci','调笑・调笑令','[]','奇货。',45,'宋词/ci.song.8000.json','["奇货。", "归帆过。", "击鼓吹箫相应和。", "楼前高浪风掀簸。", "渔唱一声山左。", "胡床邀月轻云破。", "玉麈飞谈惊座。"]'),
('song-ci-647','调笑・调笑令','洪适','宋','宋词','song-ci','调笑・调笑令','[]','名世。',45,'宋词/ci.song.8000.json','["名世。", "花无二。", "高压闍提倾末利。", "素丝缕缕联芳蕊。", "一片云生宝髻。", "屑沈碎麝香肌细。", "剩馥熏成心字。"]'),
('song-ci-648','调笑・调笑令','洪适','宋','宋词','song-ci','调笑・调笑令','[]','音乐。',45,'宋词/ci.song.8000.json','["音乐。", "传佳作。", "盖海旌幢开观阁。", "绮霞飞渡青油幕。", "好是登临行乐。", "当时朝汉心倾藿。", "望断长安城郭。"]'),
('song-ci-649','调笑・调笑令','洪适','宋','宋词','song-ci','调笑・调笑令','[]','弱水。',45,'宋词/ci.song.8000.json','["弱水。", "天无际。", "相去扶胥知几里。", "高亭东望阳乌起。", "杲杲晨光初洗。", "蓬莱欲住宁无计。", "一展弥天鹏翅。"]'),
('song-ci-650','调笑・调笑令','洪适','宋','宋词','song-ci','调笑・调笑令','[]','佳节。',45,'宋词/ci.song.8000.json','["佳节。", "初春月。", "飞盖倾城尊俎列。", "安期驾鹤朝金阙。", "丹灶分留岩穴。", "山中花笑秦皇拙。", "祠殿荒凉虚设。"]'),
('song-ci-651','调笑・调笑令','洪适','宋','宋词','song-ci','调笑・调笑令','[]','饮器。',45,'宋词/ci.song.8000.json','["饮器。", "贪泉水。", "山乳涓涓甘似醴。", "怀金嗜宝随人意。", "枉受恶名难洗。", "真清方伯端无比。", "未使吴君专美。"]'),
('song-ci-652','调笑・调笑令','洪适','宋','宋词','song-ci','调笑・调笑令','[]','深浦。',45,'宋词/ci.song.8000.json','["深浦。", "停舟处。", "只恐越装相染污。", "奇香一见如泥土。", "投著水中归去。", "令公早晚回朝著。", "无物迟留鸣橹。"]'),
('song-ci-653','调笑・调笑令','洪适','宋','宋词','song-ci','调笑・调笑令','[]','明月。',45,'宋词/ci.song.8000.json','["明月。", "舟初歇。", "三峡重过惊久别。", "玉环留与人间说。", "诗罢离肠千结。", "相思朝暮流泉咽。", "雾锁青山愁绝。"]'),
('song-ci-654','调笑・调笑令','洪适','宋','宋词','song-ci','调笑・调笑令','[]','南海。',90,'宋词/ci.song.8000.json','["南海。", "繁华最。", "城郭山川雄岭外。", "遗踪嘉话垂千载。", "竹帛班班俱在。", "元戎好古新声改。", "调笑花前分队。", "高会。", "尊罍对。", "笑眼茸茸回盼睐。", "蹋筵低唱眉弯黛。", "翔凤惊鸾多态。", "清风不用一钱买。", "醉客何妨倒载。"]'),
('song-ci-655','渔家傲引・渔家傲','洪适','宋','宋词','song-ci','渔家傲引・渔家傲','[]','正月东风初解冻。',72,'宋词/ci.song.8000.json','["正月东风初解冻。", "渔人撒网波纹动。", "不识雕梁并绮栋。", "扁舟重。", "眠鸥浴雁相迎送。", "溪北画桥弯螮蝀。", "溪南古岸添青葑。", "长把鱼钱寻酒瓮。", "春一梦。", "起来拈笛成三弄。"]'),
('song-ci-656','渔家傲引・渔家傲','洪适','宋','宋词','song-ci','渔家傲引・渔家傲','[]','二月垂杨花糁地。',72,'宋词/ci.song.8000.json','["二月垂杨花糁地。", "荻芽迸绿春无际。", "细雨斜风浑不避。", "青笠底。", "三三两两鸣桹起。", "新妇矶边云接袂。", "女儿浦口山堆髻。", "一拥河豚千百尾。", "摇食指。", "城中虚却鱼虾市。"]'),
('song-ci-657','渔家傲引・渔家傲','洪适','宋','宋词','song-ci','渔家傲引・渔家傲','[]','三月愁霖多急雨。',72,'宋词/ci.song.8000.json','["三月愁霖多急雨。", "桃江绿浪迷洲渚。", "西塞山边飞白鹭。", "烟横素。", "一声欸乃山深处。", "红雨缤纷因水去。", "行行寻得神仙侣。", "楼阁五云心不住。", "分凤侣。", "重来翻恨花相误。"]'),
('song-ci-658','渔家傲引・渔家傲','洪适','宋','宋词','song-ci','渔家傲引・渔家傲','[]','四月圆荷钱学铸。',72,'宋词/ci.song.8000.json','["四月圆荷钱学铸。", "鳞鳞波暖鸳鸯语。", "无数燕雏来又去。", "鱼未取。", "钓丝直上蜻蜓聚。", "风弄碧漪摇岛屿。", "奇云蘸影千峰舞。", "骑马官人江上驻。", "天且暮。", "借舟送过沧波渡。"]'),
('song-ci-659','渔家傲引・渔家傲','洪适','宋','宋词','song-ci','渔家傲引・渔家傲','[]','五月河中菱荇遍。',72,'宋词/ci.song.8000.json','["五月河中菱荇遍。", "丝纶欲下相萦绊。", "却掉船来芳草岸。", "呼侣伴。", "蓑衣不把金章换。", "碧落云高星烂烂。", "波心举网星光乱。", "跃出鲤鱼长尺半。", "回首看。", "孤灯一点风吹散。"]'),
('song-ci-660','渔家傲引・渔家傲','洪适','宋','宋词','song-ci','渔家傲引・渔家傲','["\u957f\u6c5f"]','六月长江无暑气。',72,'宋词/ci.song.8000.json','["六月长江无暑气。", "怒涛漱壑侵沙觜。", "飐飐轻舟随浪起。", "何不畏。", "从来惯作风波计。", "别溆藕花舒锦绮。", "采莲三五谁家子。", "问我买鱼相调戏。", "飘芰制。", "笑声咭咭花香里。"]'),
('song-ci-661','渔家傲引・渔家傲','洪适','宋','宋词','song-ci','渔家傲引・渔家傲','[]','七月凛秋飞叶响。',72,'宋词/ci.song.8000.json','["七月凛秋飞叶响。", "长吟杳杳澄江上。", "秃尾槎头添一网。", "丝自纺。", "新炊菰饭更相饷。", "渡口青烟藏叠嶂。", "岸旁红蓼翻轻浪。", "鸂鶒沈浮双漾漾。", "闻鸣桨。", "高飞拍拍穿林莽。"]'),
('song-ci-662','渔家傲引・渔家傲','洪适','宋','宋词','song-ci','渔家傲引・渔家傲','[]','八月紫莼浮绿水。',72,'宋词/ci.song.8000.json','["八月紫莼浮绿水。", "细鳞巨口鲈鱼美。", "画舫问渔篙暂舣。", "欣然喜。", "金齑顷刻尝珍味。", "涌雾驱云天似洗。", "静看星斗迎蟾桂。", "枕棹眠蓑清不睡。", "无名利。", "谁人分得逍遥意。"]'),
('song-ci-663','渔家傲引・渔家傲','洪适','宋','宋词','song-ci','渔家傲引・渔家傲','[]','九月芦香霜旦旦。',72,'宋词/ci.song.8000.json','["九月芦香霜旦旦。", "丹枫落尽吴江岸。", "长濑黄昏张蟹断。", "灯火乱。", "圆沙惊起行行雁。", "半夜系船桥北岸。", "三杯睡著无人唤。", "睡觉只疑桥不见。", "风已变。", "缆绳吹断船头转。"]'),
('song-ci-664','渔家傲引・渔家傲','洪适','宋','宋词','song-ci','渔家傲引・渔家傲','[]','十月橘洲长鼓枻。',72,'宋词/ci.song.8000.json','["十月橘洲长鼓枻。", "潇湘一片尘缨洗。", "斩得钓竿斑染泪。", "中夜里。", "时闻鼓瑟湘妃至。", "白发垂纶孙又子。", "得钱沽酒长长醉。", "小艇短篷真活计。", "家云水。", "更无王役并田税。"]'),
('song-ci-665','渔家傲引・渔家傲','洪适','宋','宋词','song-ci','渔家傲引・渔家傲','[]','子月水寒风又烈。',72,'宋词/ci.song.8000.json','["子月水寒风又烈。", "巨鱼漏网成虚设。", "圉圉从它归丙穴。", "谋自拙。", "空归不管旁人说。", "昨夜醉眠西浦月。", "今宵独钓南溪雪。", "妻子一船衣百结。", "长欢悦。", "不知人世多离别。"]'),
('song-ci-666','渔家傲引・渔家傲','洪适','宋','宋词','song-ci','渔家傲引・渔家傲','[]','腊月行舟冰凿罅。',72,'宋词/ci.song.8000.json','["腊月行舟冰凿罅。", "潜鳞透暖偏堪射。", "岁岁年年篷作舍。", "三冬夜。", "牛衣自暖何须借。", "滕六晚来方命驾。", "千山绝影飞禽怕。", "江上雪如花片下。", "宜入画。", "一蓑披著归来也。"]'),
('song-ci-667','调笑・调笑令','洪适','宋','宋词','song-ci','调笑・调笑令','[]','渔父饮时花作荫。',146,'宋词/ci.song.8000.json','["渔父饮时花作荫。", "羹鱼煮蟹无它品。", "世代太平除酒禁。", "渔父饮。", "绿蓑藉地胜如锦。", "渔父醉时收钓饵。", "鱼梁晒翅闲乌鬼。", "白浪撼船眠不起。", "渔父醉。", "滩声无尽清双耳。", "渔父醒时清夜永。", "澄澜过尽征鸿影。", "略略风来敧舴艋。", "渔父醒。", "月高露下衣裳冷。", "渔父笑时莺未老。", "提鱼入市归来早。", "一叶浮家生计了。", "渔父笑。", "笑中起舞《渔家傲》。"]'),
('song-ci-668','鹧鸪天','洪适','宋','宋词','song-ci','鹧鸪天','[]','报答风光思更新。',64,'宋词/ci.song.8000.json','["报答风光思更新。", "安排好语续阳春。", "罗胸玉藻英华别，信手银钩点画匀。", "歌妙曲，想光尘。", "相望尺五叹参辰。", "曲终强对红颜笑，欠我高谈惊座人。"]'),
('song-ci-669','生查子','洪适','宋','宋词','song-ci','生查子','[]','廉纤小雨来，噤瘆轻寒乍。',48,'宋词/ci.song.8000.json','["廉纤小雨来，噤瘆轻寒乍。", "丝竹送迎时，灯火阑珊夜。", "铜壶漏故迟，银烛花频灺。", "怀我独醒人，健笔方飞洒。"]'),
('song-ci-670','蝶恋花','洪适','宋','宋词','song-ci','蝶恋花','[]','漠漠水田飞白鹭。',70,'宋词/ci.song.8000.json','["漠漠水田飞白鹭。", "夏木阴阴，巧啭黄鹂语。", "金匮诗人新得句。", "江山应道来何暮。", "好向金门联步武。", "何事双旌，却为丹丘驻。", "琼斝十分须一举。", "看看紫诏催归去。"]'),
('song-ci-671','减字木兰花','洪适','宋','宋词','song-ci','减字木兰花','[]','藩车容裔。',52,'宋词/ci.song.8000.json','["藩车容裔。", "挺挺风流追两地。", "粲斗分星。", "诗句当年汗简青。", "疏帘披绣。", "共看横云晴出岫。", "新月如钩。", "来照琼彝醉小楼。"]'),
('song-ci-672','好事近','洪适','宋','宋词','song-ci','好事近','[]','风细晚轩凉，妙句初挥新墨。',53,'宋词/ci.song.8000.json','["风细晚轩凉，妙句初挥新墨。", "绿水池中宾佐，对嫩荷擎绿。", "坐看微月上云头，清臂映寒玉。", "只恐朝来酒醒，有文书羁束。"]'),
('song-ci-673','虞美人','洪适','宋','宋词','song-ci','虞美人','[]','芭蕉滴滴窗前雨。',66,'宋词/ci.song.8000.json','["芭蕉滴滴窗前雨。", "望断江南路。", "乱云重叠几多山。", "不似倦飞鸥鹭、便知还。", "角声更听谯门弄。", "夜夜思归梦。", "鄱江楼下水含漪。", "孤负钓滩烟艇、绿蓑衣。"]'),
('song-ci-674','卜算子','洪适','宋','宋词','song-ci','卜算子','[]','修竹拂疏棂，淡月侵凉榭。',52,'宋词/ci.song.8000.json','["修竹拂疏棂，淡月侵凉榭。", "四畔青山进好风，金鸭香煤灺。", "宝唾粲珠玑，长袖飘兰麝。", "莫问更楼夜若何，且结高阳社。"]'),
('song-ci-675','江城子','洪适','宋','宋词','song-ci','江城子','[]','冥冥云屿两经秋。',86,'宋词/ci.song.8000.json','["冥冥云屿两经秋。", "落霞收。", "断烟留。", "小阁凉生，清馥凝金虬。", "乘兴开颜那草草，烦玉腕，举琼舟。", "明年此日楚江头。", "极层楼。", "望丹丘。", "只恐溪山，千里碍凝眸。", "重倚阑干相忆处，寻过雁，作书邮。"]'),
('song-ci-676','减字木兰花','洪适','宋','宋词','song-ci','减字木兰花','[]','使君情素。',52,'宋词/ci.song.8000.json','["使君情素。", "念我明朝行县去。", "一醉相留。", "和气欢声到小楼。", "暂时南北。", "莫唱渭城朝雨曲。", "此去农郊。", "收拾童儿五裤谣。"]'),
('song-ci-677','浣溪沙','洪适','宋','宋词','song-ci','浣溪沙','[]','邦伯今推第一流。',48,'宋词/ci.song.8000.json','["邦伯今推第一流。", "几因歌席负诗筹。", "一时文采说台州。", "雨脚渐收风入牖，云心初破月窥楼。", "翠眉相映晚山秋。"]'),
('song-ci-678','望海潮','洪适','宋','宋词','song-ci','望海潮','[]','重溟倒影，五芝含笑，神仙今古台州。',129,'宋词/ci.song.8000.json','["重溟倒影，五芝含笑，神仙今古台州。", "山拥黄堂，烟披画戟，双岩瑞气长浮。", "前事记鳌头。", "有百年台榭，千室嬉游。", "墨宝凄凉，风凌雨蠹尽悠悠。", "规恢共仰贤侯。", "当政成五月，景对三秋。", "飞栋干云，虚檐受露，放怀不减南楼。", "宾燕奉觥筹。", "妙绮笺琼藻，声度歌喉。", "只恐棠阴成后，趣去侍凝旒。"]'),
('song-ci-679','好事近','洪适','宋','宋词','song-ci','好事近','[]','小阁过重阳，愁对轻篁团色。',53,'宋词/ci.song.8000.json','["小阁过重阳，愁对轻篁团色。", "喜得蛮笺新唱，似夜光明月。", "萸房菊蕊定相怜，酩酊误蕉叶。", "犹记去年今夜，听歌声清切。"]'),
('song-ci-680','清平乐','洪适','宋','宋词','song-ci','清平乐','[]','风鬟飞乱。',54,'宋词/ci.song.8000.json','["风鬟飞乱。", "寒入秦筝雁。", "情似云阴浑未展。", "雨脚更飘银线。", "横枝有意先开。", "玉尘欲伴金斝。", "何日舞裀歌扇，后堂重到惟梅。"]'),
('song-ci-681','选冠子','洪适','宋','宋词','song-ci','选冠子','[]','雨脚报晴，云容成瑞，夜雪萦盈连昼。',138,'宋词/ci.song.8000.json','["雨脚报晴，云容成瑞，夜雪萦盈连昼。", "千岩曳缟，万瓦堆琼，稍稍冷侵怀袖。", "鹤氅神仙，兔园宾客，高会坐移清漏。", "想灞陵桥畔，苦吟缓辔，耸肩寒瘦。", "向此际、色映堂阴，香传梅影，寒力更欺尊酒。", "左符词伯，蛮笺巧思，不道起风飞柳。", "舞态弓弯，一声低唱，蛾笑绿分烟岫。", "任杯行潋滟，为公沈醉，莫教停手。"]'),
('song-ci-682','好事近','洪适','宋','宋词','song-ci','好事近','[]','缥酒颂青春，不减宜城桑落。',53,'宋词/ci.song.8000.json','["缥酒颂青春，不减宜城桑落。", "楼下玉人凝笑，散万英千萼。", "绣衣当日帝王州，横飞看雕鹗。", "闻道赐环书下，向金门持橐。"]'),
('song-ci-683','鹧鸪天','洪适','宋','宋词','song-ci','鹧鸪天','[]','领客携尊花底开。',64,'宋词/ci.song.8000.json','["领客携尊花底开。", "薄寒初送雨声来。", "一声未弄林间笛，几片低飞阁下梅。", "酬的皪，少迟回。", "不妨春雪撒银杯。", "玉肌莫放清香散，更待晴时赏一回。"]'),
('song-ci-684','浣溪沙','洪适','宋','宋词','song-ci','浣溪沙','[]','整顿春衫欲跨鞍。',48,'宋词/ci.song.8000.json','["整顿春衫欲跨鞍。", "一杯相属少开颜。", "愁眉不似旧时弯。", "未见两星添柳宿，忍教三叠唱阳关。", "相思空望会稽山。"]'),
('song-ci-685','浣溪沙','洪适','宋','宋词','song-ci','浣溪沙','[]','报道倾城出洞房。',48,'宋词/ci.song.8000.json','["报道倾城出洞房。", "水边疏影弄清香。", "风流更有小鸳鸯。", "蝉鬓半含花下笑，蛾眉相映醉时妆。", "梦魂不到白云乡。"]'),
('song-ci-686','浣溪沙','洪适','宋','宋词','song-ci','浣溪沙','[]','玉颊微醺怯晚寒。',48,'宋词/ci.song.8000.json','["玉颊微醺怯晚寒。", "可怜凝笑整双翰。", "枝头一点为谁酸。", "只恐轻飞烟树里，好教斜插鬓云边。", "淡妆仍向醉中看。"]'),
('song-ci-687','浣溪沙','洪适','宋','宋词','song-ci','浣溪沙','[]','忆得熙春晓立班。',48,'宋词/ci.song.8000.json','["忆得熙春晓立班。", "使星曾入紫微垣。", "归来小饮友芝兰。", "投辖风流今复见，开尊礼数自来宽。", "更看宝唾写乌阑。"]'),
('song-ci-688','清平乐','洪适','宋','宋词','song-ci','清平乐','[]','轻红淡白。',54,'宋词/ci.song.8000.json','["轻红淡白。", "蓬阆神仙谪。", "魏紫姚黄夸异色。", "到得海边初识。", "玉阑不语如颦。", "虚教春尽三分。", "却问檀心谁向，多情更属东君。"]'),
('song-ci-689','生查子','洪适','宋','宋词','song-ci','生查子','[]','桃疏蝶惜香，柳困莺惊絮。',48,'宋词/ci.song.8000.json','["桃疏蝶惜香，柳困莺惊絮。", "日影过帘旌，多少愁情绪。", "红惨武陵溪，绿暗章台路。", "春色似行人，无意花间住。"]'),
('song-ci-690','思佳客','洪适','宋','宋词','song-ci','思佳客','[]','花信今无一半风。',64,'宋词/ci.song.8000.json','["花信今无一半风。", "芙蓉出水几时红。", "看成弱柳阴阴绿，自在迁莺巧语中。", "风傍户，月留空。", "金尊相对醉珠栊。", "归鞭欲指江南去，回首霞标忆旧峰。"]'),
('song-ci-691','朝中措','洪适','宋','宋词','song-ci','朝中措','[]','当年召父治南阳。',57,'宋词/ci.song.8000.json','["当年召父治南阳。", "千室颂慈祥。", "今代天台太守，声名已达岩廊。", "风流闲暇，胡床乘兴，燕寝凝香。", "好去花砖视草，珠庭喜见微黄。"]'),
('song-ci-692','朝中措','洪适','宋','宋词','song-ci','朝中措','[]','江西文派有新图。',57,'宋词/ci.song.8000.json','["江西文派有新图。", "诗律嗣东湖。", "十首齐安书事，君王曾问相如。", "牙签翻架，银钩落纸，美玉明珠。", "见说诏岁金匮，后来天下浑无。"]'),
('song-ci-693','朝中措','洪适','宋','宋词','song-ci','朝中措','[]','青云垂下不争程。',57,'宋词/ci.song.8000.json','["青云垂下不争程。", "绣斧记澄清。", "黄木湾头人闹，耳边都是欢声。", "仙家咫尺，波涵渤澥，路挹蓬瀛。", "十日东君不老，一星南极长明。"]'),
('song-ci-694','朝中措','洪适','宋','宋词','song-ci','朝中措','[]','斗南楼阁舞祥云。',57,'宋词/ci.song.8000.json','["斗南楼阁舞祥云。", "为寿几多人。", "有酒恰如东海，年年为满金尊。", "无双治行，儿童咏德，草木沾仁。", "只把空虚三院，亦须笑傲千春。"]'),
('song-ci-695','朝中措','洪适','宋','宋词','song-ci','朝中措','[]','西崑当日下云骈。',57,'宋词/ci.song.8000.json','["西崑当日下云骈。", "采藻奉苏仙。", "玉节荣看棠棣，斑衣笑俯芝兰。", "寿觞争举，歌萦蛾绿，香袅龙涎。", "须与寄声鸾鹤，飞来岁岁年年。"]'),
('song-ci-696','朝中措','洪适','宋','宋词','song-ci','朝中措','[]','嘉禾一别十经春。',57,'宋词/ci.song.8000.json','["嘉禾一别十经春。", "清泖记垂纶。", "今日天涯沦落，跫然一见佳人。", "酒浮重碧，声低云叶，香趁霞裙。", "准拟魁星归去，它时相会金门。"]'),
('song-ci-697','浣溪沙','洪适','宋','宋词','song-ci','浣溪沙','[]','占得登高一日先。',48,'宋词/ci.song.8000.json','["占得登高一日先。", "跨云来作地行仙。", "天将黄菊助长年。", "健笔已凌枚叟赋，高怀欲著祖生鞭。", "骎骎彯组向甘泉。"]'),
('song-ci-698','临江仙','洪适','宋','宋词','song-ci','临江仙','[]','向日鹓行瞻凤彩，共期直上金銮。',70,'宋词/ci.song.8000.json','["向日鹓行瞻凤彩，共期直上金銮。", "却来持节海云边。", "身兼三使者，名是一仙官。", "汉室中兴高密冠，千年苗裔蝉联。", "左弧嘉庆舞祥烟。", "橘中招四老，同醉酒如泉。"]'),
('song-ci-699','临江仙','洪适','宋','宋词','song-ci','临江仙','[]','北斗南头云送喜，人间快睹魁星。',70,'宋词/ci.song.8000.json','["北斗南头云送喜，人间快睹魁星。", "向来平步到蓬瀛。", "如何天上客，来佐海边城。", "方伯娱宾香作穗，风随歌扇凉生。", "且须滟滟引瑶觥。", "十年迟凤诏，万里寄鹏程。"]'),
('song-ci-700','临江仙','洪适','宋','宋词','song-ci','临江仙','[]','钓濑怀珠山韫玉，谪仙至自蓬莱。',70,'宋词/ci.song.8000.json','["钓濑怀珠山韫玉，谪仙至自蓬莱。", "它年勋业上云台。", "棣华开幕府，莲沼屈英才。", "南极逢秋光烂烂，门阑香雾萦回。", "须将寿卉荐琼杯。", "篱东明日菊，借取一枝来。"]'),
('song-ci-701','临江仙','洪适','宋','宋词','song-ci','临江仙','[]','烟凑横岚霞抱日，望中衰草稠稠。',70,'宋词/ci.song.8000.json','["烟凑横岚霞抱日，望中衰草稠稠。", "西风吹恨著扁舟。", "马卿多病后，方寸不禁秋。", "颇念银壶行绿醑，共听渔子清讴。", "梦魂飞过海山楼。", "人随秋易老，情寄水东流。"]'),
('song-ci-702','临江仙','洪适','宋','宋词','song-ci','临江仙','[]','干吕青云垂宝露，结邻恰挂初弦。',70,'宋词/ci.song.8000.json','["干吕青云垂宝露，结邻恰挂初弦。", "瑞光腾踊杂非烟。", "骑箕瞻鼻祖，孕昴控胎仙。", "勋业子卿全汉节，壮怀久寄林泉。", "举觞低唱脸舒莲。", "寿高人七十，果熟岁三千。"]'),
('song-ci-703','临江仙','洪适','宋','宋词','song-ci','临江仙','[]','瓜瓞绵绵储庆远，闲平代有名人。',70,'宋词/ci.song.8000.json','["瓜瓞绵绵储庆远，闲平代有名人。", "一襦五裤说朱轮。", "云逵鸳缀近，雷社虎符新。", "正是泗滨浮磬日，潘舆一粲欣欣。", "鸾歌飞起杏梁尘。", "巢莲龟问岁，介寿酒融春。"]'),
('song-ci-704','临江仙','洪适','宋','宋词','song-ci','临江仙','[]','远驾星屏临百粤，康沂户户歌功。',70,'宋词/ci.song.8000.json','["远驾星屏临百粤，康沂户户歌功。", "使君五马去乘骢。", "卖刀无旷土，赠扇有仁风。", "莫唱渭城朝雨曲，片帆时暂西东。", "促归行拜紫泥封。", "九霄先步武，三接未央宫。"]'),
('song-ci-705','江城子','洪适','宋','宋词','song-ci','江城子','[]','当年提笔上词坛。',86,'宋词/ci.song.8000.json','["当年提笔上词坛。", "琢琅玕。", "涌波澜。", "晁董声名，一日满人间。", "底事远烦骐骥足，梅岭外，砚台边。", "元戎倾盖有馀欢。", "酒杯宽。", "语离难。", "只恐江边，明日起青翰。", "暂去平分风与月，迎细札，步金銮。"]'),
('song-ci-706','江城子','洪适','宋','宋词','song-ci','江城子','[]','江如罗带抱山青。',86,'宋词/ci.song.8000.json','["江如罗带抱山青。", "好风轻。", "五云横。", "北斗南边，烨烨使华星。", "两路平反多少事，培吉德，赍长生。", "当年乌府振冠缨。", "稔英声。", "起鹏程。", "垂上丹霄，回首志澄清。", "雪片深深梅著子，归路近，看和羹。"]'),
('song-ci-707','醉蓬莱','洪适','宋','宋词','song-ci','醉蓬莱','[]','正中秋初过，重阳相近，金茎多露。',120,'宋词/ci.song.8000.json','["正中秋初过，重阳相近，金茎多露。", "玉燕开祥，喜气浮庭户。", "览凤千峰，骖鸾八桂，未展青云步。", "碧玉篸边，红莲池上，羽仙旁午。", "少日声名，珠玑黼黻，晔煜分符，喧轰持斧。", "带缓裘轻，足远人襦裤。", "唇注樱桃，腰欺杨柳，歌舞新蛮素。", "满酌金船，寿公千岁，东台西府。"]'),
('song-ci-708','满庭芳','洪适','宋','宋词','song-ci','满庭芳','[]','昴宿光芒，德星家世，当时飞舞华旗。',118,'宋词/ci.song.8000.json','["昴宿光芒，德星家世，当时飞舞华旗。", "风清玉宇，珠露缀瑶枝。", "八桂苍苍耸壑，问椿木、同数秋期。", "黄堂上，油幢转影，美酒注金卮。", "英躔，名誉早，青箱传学，黄绢摛辞。", "说江东治行，召杜肩齐。", "畏爱双行五管，收绣斧、却把旌麾。", "欢声沸，明年此日，公在凤凰池。"]'),
('song-ci-709','千秋岁','洪适','宋','宋词','song-ci','千秋岁','[]','颜朱鬓绿。',87,'宋词/ci.song.8000.json','["颜朱鬓绿。", "天与穰穰福。", "旄钺贵，崇汤沐。", "华轩鱼映锦，紫诰鸾回幅。", "为寿处，玻璃凿落斟醽醁。", "瑞雾蟠华屋。", "露浥秋兰馥。", "香篆起，歌裾簇。", "衣斑丹穴凤，色润东床玉。", "鸾共鹤，年年来听神仙曲。"]'),
('song-ci-710','眼儿媚','洪适','宋','宋词','song-ci','眼儿媚','[]','黄堂风转碧幢开。',58,'宋词/ci.song.8000.json','["黄堂风转碧幢开。", "笙鹤九天来。", "三冬爱日，一方惠露，人在春台。", "持杯多赞松乔喜，低唱列金钗。", "明年此日，紫微垣里，光应中台。"]'),
('song-ci-711','鹧鸪天','洪适','宋','宋词','song-ci','鹧鸪天','[]','月上初弦映左弧。',64,'宋词/ci.song.8000.json','["月上初弦映左弧。", "葭吹六琯转璇枢。", "日边远近瞻新渥，天下中庸系两都。", "犀献角，蚌回珠。", "皇皇星节烛扶胥。", "满斟北海尊中酒，请寿安期涧底蒲。"]'),
('song-ci-712','长相思','洪适','宋','宋词','song-ci','长相思','[]','朝思归。',44,'宋词/ci.song.8000.json','["朝思归。", "暮思归。", "塞雁三年不见飞。", "断肠天一涯。", "千思归。", "万思归。", "梦到窗前拂淡眉。", "觉来双泪垂。"]'),
('song-ci-713','长相思','洪适','宋','宋词','song-ci','长相思','[]','柳青青。',44,'宋词/ci.song.8000.json','["柳青青。", "酒清清。", "雨脚涔涔忆渭城。", "一尊和泪倾。", "山青青。", "水清清。", "水阔山重不计程。", "愁堆长短亭。"]'),
('song-ci-714','好事近','洪适','宋','宋词','song-ci','好事近','[]','柳岸碧漪深，底事催人行色。',53,'宋词/ci.song.8000.json','["柳岸碧漪深，底事催人行色。", "无计曲留情话，只别愁如织。", "小蛮樊素两倾城，几度醉狂客。", "明日扁舟西去，听歌声不得。"]'),
('song-ci-715','点绛唇','洪适','宋','宋词','song-ci','点绛唇','[]','天末相逢，醉中不讶车茵污。',50,'宋词/ci.song.8000.json','["天末相逢，醉中不讶车茵污。", "一声鸣橹。", "惊散眠沙鹭。", "我是行人，却送行人去。", "听金缕。", "莫辞甘醑。", "别泪飞寒雨。"]'),
('song-ci-716','南歌子','洪适','宋','宋词','song-ci','南歌子','[]','云拂山腰过，风吹雨点来。',62,'宋词/ci.song.8000.json','["云拂山腰过，风吹雨点来。", "田园好处有池台。", "记著相逢时节、海棠开。", "蝴蝶那无梦，鸳鸯亦有媒。", "藏钩解佩两三杯。", "明日水边沙际、首空回。"]'),
('song-ci-717','好事近','洪适','宋','宋词','song-ci','好事近','[]','烂漫海棠花，多谢东君留得。',53,'宋词/ci.song.8000.json','["烂漫海棠花，多谢东君留得。", "眉寿堂边风景，与蓬瀛咫尺。", "桃红李白竞争妍，绿野尽春色。", "只欠樱唇清唱，怕行云南北。"]'),
('song-ci-718','生查子','洪适','宋','宋词','song-ci','生查子','[]','带郭得盘洲，胜处双溪水。',48,'宋词/ci.song.8000.json','["带郭得盘洲，胜处双溪水。", "月榭间风亭，叠嶂横空翠。", "团栾情话时，三径参差是。", "听我一年词，对景休辞醉。"]'),
('song-ci-719','生查子','洪适','宋','宋词','song-ci','生查子','[]','正月到盘洲，解冻东风至。',48,'宋词/ci.song.8000.json','["正月到盘洲，解冻东风至。", "便有浴鸥飞，时见潜鳞起。", "高柳送青来，春在长林里。", "绿萼一枝梅，端是花中瑞。"]'),
('song-ci-720','生查子','洪适','宋','宋词','song-ci','生查子','[]','二月到盘洲，繁缬盈千萼。',48,'宋词/ci.song.8000.json','["二月到盘洲，繁缬盈千萼。", "恰恰早莺啼，一羽黄金落。", "花边自在行，临水还寻壑。", "步步肯相随，独有苍梧鹤。"]'),
('song-ci-721','生查子','洪适','宋','宋词','song-ci','生查子','[]','三月到盘洲，九曲清波聚。',48,'宋词/ci.song.8000.json','["三月到盘洲，九曲清波聚。", "修竹荫流觞，秀叶题佳句。", "红紫渐阑珊，恋恋莺花主。", "芍药拥芳蹊，未放春归去。"]'),
('song-ci-722','生查子','洪适','宋','宋词','song-ci','生查子','[]','四月到盘洲，长是黄梅雨。',48,'宋词/ci.song.8000.json','["四月到盘洲，长是黄梅雨。", "屐齿满莓苔，避湿开新路。", "极望绿阴成，不见乌飞处。", "云采列奇峰，绝胜看庐阜。"]'),
('song-ci-723','生查子','洪适','宋','宋词','song-ci','生查子','[]','五月到盘洲，照眼红巾蹙。',48,'宋词/ci.song.8000.json','["五月到盘洲，照眼红巾蹙。", "句引石榴裙，一唱仙翁曲。", "藕步进新船，斗楫飞云速。", "此际独醒难，一一金锺覆。"]'),
('song-ci-724','生查子','洪适','宋','宋词','song-ci','生查子','[]','六月到盘洲，水阁盟鸥鹭。',48,'宋词/ci.song.8000.json','["六月到盘洲，水阁盟鸥鹭。", "面面纳清风，不受人间暑。", "彩舫下垂杨，深入荷花去。", "浅笑擘莲蓬，去却中心苦。"]'),
('song-ci-725','生查子','洪适','宋','宋词','song-ci','生查子','[]','七月到盘洲，枕簟新凉早。',48,'宋词/ci.song.8000.json','["七月到盘洲，枕簟新凉早。", "岸曲侧黄葵，沙际排红蓼。", "团团歌扇疏，整整炉烟袅。", "环坐待横参，要乞珠丝巧。"]'),
('song-ci-726','生查子','洪适','宋','宋词','song-ci','生查子','[]','八月到盘洲，柳外寒蝉懒。',48,'宋词/ci.song.8000.json','["八月到盘洲，柳外寒蝉懒。", "一掬木犀花，泛泛玻璃盏。", "蟾桂十分明，远近秋毫见。", "举酒劝嫦娥，长使清光满。"]'),
('song-ci-727','生查子','洪适','宋','宋词','song-ci','生查子','[]','九月到盘洲，华发惊霜叶。',48,'宋词/ci.song.8000.json','["九月到盘洲，华发惊霜叶。", "缓步绕东篱，香蕊金重叠。", "橘绿又橙黄，四老相迎接。", "好处不宜休，莫放清尊歇。"]'),
('song-ci-728','生查子','洪适','宋','宋词','song-ci','生查子','[]','十月到盘洲，小小阳春节。',48,'宋词/ci.song.8000.json','["十月到盘洲，小小阳春节。", "晚菊自争妍，谁管人心别。", "木末簇芙蓉，禁得霜如雪。", "心赏四时同，不与痴人说。"]'),
('song-ci-729','生查子','洪适','宋','宋词','song-ci','生查子','[]','子月到盘洲，日影长添线。',48,'宋词/ci.song.8000.json','["子月到盘洲，日影长添线。", "水退露溪痕，风急寒芦战。", "终日倚枯藤，细看浮云变。", "洲畔有圆沙，招尽云边雁。"]'),
('song-ci-730','生查子','洪适','宋','宋词','song-ci','生查子','[]','腊月到盘洲，寒重层冰结。',48,'宋词/ci.song.8000.json','["腊月到盘洲，寒重层冰结。", "试去探梅花，休把南枝折。", "顷刻暗同云，不觉红炉热。", "隐隐绿蓑翁，独钓寒江雪。"]'),
('song-ci-731','生查子','洪适','宋','宋词','song-ci','生查子','[]','一岁会盘洲，月月生查子。',48,'宋词/ci.song.8000.json','["一岁会盘洲，月月生查子。", "弟劝复兄酬，举案灯花喜。", "曲终人半酣，添酒留罗绮。", "车马不须喧，且听三更未。"]'),
('song-ci-732','阮郎归','洪适','宋','宋词','song-ci','阮郎归','[]','澄清阁下藕如船。',56,'宋词/ci.song.8000.json','["澄清阁下藕如船。", "扁舟曾采莲。", "向来辛苦叠青钱。", "而今知几年。", "人去也，客凄然。", "酒泉添泪泉。", "一杯今夜且留连。", "断肠芳草边。"]'),
('song-ci-733','浣溪沙','洪适','宋','宋词','song-ci','浣溪沙','[]','丹桂飘香已四番。',48,'宋词/ci.song.8000.json','["丹桂飘香已四番。", "杖藜携手自今难。", "黯淡离恨满江干。", "壁上两冠元是谶，花前双韵几时弹。", "中秋后夜与谁看。"]'),
('song-ci-734','满江红','洪适','宋','宋词','song-ci','满江红','[]','暮雨萧萧，飞败叶、增添秋色。',115,'宋词/ci.song.8000.json','["暮雨萧萧，飞败叶、增添秋色。", "登高会、痴风吹散，山居佳客。", "人世难逢开口笑，老来便觉流年迫。", "到如今、黄菊满园开，无人摘。", "珠履凑，铢衣窄。", "萦翠袖，催牙拍。", "索松儿添半，战酣相吓。", "橘绿橙黄时节好，舞停歌罢门墙隔。", "酒醒时、枕上一声鸡，东方白。"]'),
('song-ci-735','满江红','洪适','宋','宋词','song-ci','满江红','[]','累月愁霖，知今夕、是何天色。',115,'宋词/ci.song.8000.json','["累月愁霖，知今夕、是何天色。", "秋老矣、芙蓉遮道，黄花留客。", "长有霜螯来左右，谁言枥马能煎迫。", "眄高穹、重叠起顽云，星难摘。", "罗绮盛，轩窗窄。", "心已醉，肩须拍。", "更十分行酒，再三相吓。", "凤诏十行归路近，桂华千里明年隔。", "趁闲时、楼上共凝眸，芦花白。"]'),
('song-ci-736','临江仙','洪适','宋','宋词','song-ci','临江仙','[]','两载绣衣频驻节，金莲曾印青苔。',70,'宋词/ci.song.8000.json','["两载绣衣频驻节，金莲曾印青苔。", "匆匆归去寿琼杯。", "曲终挥别泪，江上片帆开。", "记得秋宵山吐月，酒酣同上层台。", "杖藜何日解重来。", "相思凭过雁，飞送一枝梅。"]'),
('song-ci-737','浣溪沙','洪适','宋','宋词','song-ci','浣溪沙','[]','举目霜林叶叶黄。',48,'宋词/ci.song.8000.json','["举目霜林叶叶黄。", "使星归骑未须忙。", "烟鬟千叠弄残妆。", "内殿恩光承雨露，外台风力挟冰霜。", "应怀三径杂花香。"]'),
('song-ci-738','浣溪沙','洪适','宋','宋词','song-ci','浣溪沙','[]','不见丹丘三十年。',48,'宋词/ci.song.8000.json','["不见丹丘三十年。", "青山碧水想依然。", "自惊绿鬓已苍颜。", "月在柳梢曾径醉，雨荒院菊有谁怜。", "绣衣归与古人言。"]'),
('song-ci-739','生查子','洪适','宋','宋词','song-ci','生查子','[]','碧涧有神龟，千岁游莲叶。',48,'宋词/ci.song.8000.json','["碧涧有神龟，千岁游莲叶。", "七十古来稀，寿母杯频接。", "绣衣牵彩衣，喜庆相重叠。", "龟紫看孙曾，鹤发何须镊。"]'),
('song-ci-740','生查子','洪适','宋','宋词','song-ci','生查子','[]','贪看端木花，难办销金帐。',48,'宋词/ci.song.8000.json','["贪看端木花，难办销金帐。", "庭下舞琼瑶，飞到须眉上。", "衰病不禁寒，对景频惆怅。", "梦寐到凌风，倚著青藜杖。"]'),
('song-ci-741','鹧鸪天','洪适','宋','宋词','song-ci','鹧鸪天','[]','莫问甘醪浊与清。',64,'宋词/ci.song.8000.json','["莫问甘醪浊与清。", "试将一酌破愁城。", "海棠过后荼蘼发，堪叹人间不再生。", "心已老，眼重明。", "嫣然国色带朝酲。", "耳边听得兰亭曲，一咏流觞已有名。"]'),
('song-ci-742','鹧鸪天','洪适','宋','宋词','song-ci','鹧鸪天','[]','两塾弦歌日日春。',64,'宋词/ci.song.8000.json','["两塾弦歌日日春。", "不容坐席更凝尘。", "常思芳桂攀燕窦，未见童乌继子云。", "流庆泽，仰家尊。", "救荒阴德过于门。", "从师已是平原客，毛遂怀绷作弄孙。"]'),
('song-ci-743','好事近','洪适','宋','宋词','song-ci','好事近','[]','春意渐盈盈，窗外小桃堪折。',53,'宋词/ci.song.8000.json','["春意渐盈盈，窗外小桃堪折。", "若问得人怜处，是轻颦时节。", "主人特地出红妆，不要云心月。", "三径虽然冷淡，有采莲舟楫。"]'),
('song-ci-744','满江红','洪适','宋','宋词','song-ci','满江红','[]','春色匆匆，三分过、二分光景。',115,'宋词/ci.song.8000.json','["春色匆匆，三分过、二分光景。", "吾老矣，坡轮西下，可堪弄影。", "曲水流觞时节好，茂林修竹池台永。", "望前村、绿柳荫茅檐，云封岭。", "蜂蝶闹，烟花整。", "百年梦，如俄顷。", "这回头陈迹，漫劳深省。", "吹竹弹丝谁不爱，焚琴煮鹤人何肯。", "尽三觥、歌罢酒来时，风吹醒。"]'),
('song-ci-745','满江红','洪适','宋','宋词','song-ci','满江红','[]','雨过春深，溪水涨、绿波溶溢。',115,'宋词/ci.song.8000.json','["雨过春深，溪水涨、绿波溶溢。", "年年是、杨花吹絮，草茵凝碧。", "驹隙光阴身易老，槐安梦幻醒难觅。", "算六分、春色五分休，才留一。", "雁鹜静，文书毕。", "尘外趣，壶中日。", "喜兰亭修禊，郊坰忺出。", "合璧连珠同啸咏，怒猊渴骥尤清逸。", "酒酣时、梁上暗尘飞，无痕迹。"]'),
('song-ci-746','满江红','洪适','宋','宋词','song-ci','满江红','[]','衰老贪春，春又老、尊罍交溢。',115,'宋词/ci.song.8000.json','["衰老贪春，春又老、尊罍交溢。", "凝目处、清漪拍岸，四山堆碧。", "白也论文情最厚，维摩示病心难觅。", "到盘洲、车骑太匆匆，觞浮一。", "春再见，官期毕。", "归路近，长安日。", "奉清时明诏，迭回更出。", "上殿风霜生颊齿，元龟献替图无逸。", "记而今、杖策过溪桥，留行迹。"]'),
('song-ci-747','满江红','洪适','宋','宋词','song-ci','满江红','[]','燕寝香凝，官事了、诗情充溢。',115,'宋词/ci.song.8000.json','["燕寝香凝，官事了、诗情充溢。", "归后院、花容争媚，柳眉添碧。", "老子胡床常自叹，轻裾长袖从何觅。", "探城楼、此际夜如何，更筹一。", "人已老，春将毕。", "临曲水，才旬日。", "快朝来雨过，鱼儿争出。", "淡酒一杯空酩酊，黄堂千骑真安逸。", "问朱轓、何日到丘园，联綦迹。"]'),
('song-ci-748','满江红','洪适','宋','宋词','song-ci','满江红','[]','百计留春，春不住、愁怀填溢。',115,'宋词/ci.song.8000.json','["百计留春，春不住、愁怀填溢。", "争如对、宝梳压鬓，翠环铺碧。", "紫绶金章都是梦，云庐花坞如何觅。", "劝金杯、浅笑傍宾筵，须均一。", "前夜月，新离毕。", "收歰雨，呈红日。", "荷主人情厚，五云齐出。", "一颗樱桃天付与，数声水调人飘逸。", "叹荒园、三月百花残，无踪迹。"]'),
('song-ci-749','南歌子','洪适','宋','宋词','song-ci','南歌子','[]','闰岁饶光景，中旬始打春。',62,'宋词/ci.song.8000.json','["闰岁饶光景，中旬始打春。", "拥炉看雪酒催人。", "梁上不曾飞落、去年尘。", "未暇巾车出，何妨举盏频。", "斜川日月已成陈。", "想得前村仙子、晚妆匀。"]'),
('song-ci-750','南歌子','洪适','宋','宋词','song-ci','南歌子','[]','多病都缘老，寒阴可惜春。',62,'宋词/ci.song.8000.json','["多病都缘老，寒阴可惜春。", "栽桃种竹怕因循。", "移转蓝舆藤杖、未开门。", "真率须如约，安排欲效颦。", "莫将筝笛损精神。", "自有啼莺舞鹤、解随人。"]'),
('song-ci-751','南歌子','洪适','宋','宋词','song-ci','南歌子','[]','顽健输村老，嬉游付后生。',62,'宋词/ci.song.8000.json','["顽健输村老，嬉游付后生。", "七旬才有五清明。", "须趁良辰美景、绕园行。", "云意将飞雪，天心未肯晴。", "难将性命作人情。", "只合拥炉清坐、阅医经。"]'),
('song-ci-752','南歌子','洪适','宋','宋词','song-ci','南歌子','[]','住得如筛雪，方欣有脚春。',62,'宋词/ci.song.8000.json','["住得如筛雪，方欣有脚春。", "谁云三尺不须循。", "若是诗僧月下、许敲门。", "钜竹多中断，残梅竞小颦。", "畦丁说与主林神。", "扫洒板桥前径、待吾人。"]'),
('song-ci-753','南歌子','洪适','宋','宋词','song-ci','南歌子','[]','强作千年调，难逾五度春。',62,'宋词/ci.song.8000.json','["强作千年调，难逾五度春。", "脊令继踵漫相循。", "休要关心药裹、也扃门。", "蕙帐银杯化，纱窗翠黛颦。", "烧香试问紫姑神。", "一岁四并三乐、几多人。"]'),
('song-ci-754','南歌子','洪适','宋','宋词','song-ci','南歌子','[]','南浦山罗列，东湖水渺弥。',62,'宋词/ci.song.8000.json','["南浦山罗列，东湖水渺弥。", "主人好客过当时。", "斗转参横时候、醉如泥。", "莫管莺声老，从它柳絮飞。", "野园春色别无奇。", "船上有花多酒、未须归。"]'),
('song-ci-755','好事近','洪适','宋','宋词','song-ci','好事近','[]','睡足淡梳妆，喜见诗人元白。',53,'宋词/ci.song.8000.json','["睡足淡梳妆，喜见诗人元白。", "不学艳红妖紫，环花仙标格。", "须知玉骨本天然，不是借人力。", "准拟小春重看，望秋灰无射。"]'),
('song-ci-756','卜算子','洪适','宋','宋词','song-ci','卜算子','[]','五凤望中仙，五马人间贵。',52,'宋词/ci.song.8000.json','["五凤望中仙，五马人间贵。", "舞态歌声尽出群，乌鹊巡檐喜。", "昨夜值狂风，痛饮全无味。", "说与谯门漫打更，却怕催归骑。"]'),
('song-ci-757','满庭芳','洪适','宋','宋词','song-ci','满庭芳','[]','华发苍头，年年更变，白雪轻犯双眉。',118,'宋词/ci.song.8000.json','["华发苍头，年年更变，白雪轻犯双眉。", "六旬过四，七十古来稀。", "问柳寻花兴懒，拈筇杖、闲绕园池。", "尊中有，青州从事，无意唤琼彝。", "人生，何处乐，楼台院落，吹竹弹丝。", "奈壮怀销铄，病费医治。", "漫道琴弦绿绮，游鱼听、山水谁知。", "盘洲怨，盟鸥闲阔，痍鹤立新碑。"]'),
('song-ci-758','满庭芳','洪适','宋','宋词','song-ci','满庭芳','[]','风搅花间，雨悭柳下，人人懒拂愁眉。',118,'宋词/ci.song.8000.json','["风搅花间，雨悭柳下，人人懒拂愁眉。", "年荒省事，投辖井中稀。", "架上舞衣尘积，弦索断、筝雁差池。", "南柯梦，转头陈迹，饥鼠穴空彝。", "新年，官事少，秋蛇春蚓，重叠乌丝。", "更出奇花判，百病都治。", "报道行厨办也，乌鹊喜、龟鹤前知。", "更书近，鹓行浸远，长对去思碑。"]'),
('song-ci-759','满庭芳','洪适','宋','宋词','song-ci','满庭芳','[]','殢酒销愁，逢场作戏，何曾择地伸眉。',118,'宋词/ci.song.8000.json','["殢酒销愁，逢场作戏，何曾择地伸眉。", "诗筒来往，如我与君稀。", "喜得青春有闰，添日月、款曲临池。", "洲盘有，山肴野蔌，安用设鸡彝。", "老来，空自笑，一头梳雪，两鬓吹丝。", "便常逢社饮，聋不堪治。", "曾就新年真率，花神报、蜂蝶皆知。", "东风恶，江梅欲尽，荐福莫轰碑。"]'),
('song-ci-760','满庭芳','洪适','宋','宋词','song-ci','满庭芳','[]','柳径花台，熙熙春动，游人珥堕簪遗。',118,'宋词/ci.song.8000.json','["柳径花台，熙熙春动，游人珥堕簪遗。", "枯藤到处，绿刺惹冠衣。", "雪后园林更好，琼作佩、香满横枝。", "巡檐久，留连一笑，不管午阴移。", "盘洲，今雅集，皇华飞盖，挥麈迟迟。", "觉龟鱼增价，草木生辉。", "梁上不教尘落，谈文字、酒散星稀。", "明年好，玉津随驾，回首记襟期。"]'),
('song-ci-761','满庭芳','洪适','宋','宋词','song-ci','满庭芳','[]','同病相怜，冻吟谁伴，漫怀举案齐眉。',118,'宋词/ci.song.8000.json','["同病相怜，冻吟谁伴，漫怀举案齐眉。", "槐安梦境，一笑自来稀。", "未到斜川见雪，春欲半、尚压铜池。", "今思古，拊盆击筑，虿鼎闲夔彝。", "何时。", "天意解，并游花坞，旋扫蛛丝。", "对壶中闲日，冗牍休治。", "四坐同盟情话，飞玉麈、万事多知。", "杯盘省，浅斟随意，真率视前碑。"]'),
('song-ci-762','满庭芳','洪适','宋','宋词','song-ci','满庭芳','[]','蝴蝶梦魂，芭蕉身世，几人得到庞眉。',118,'宋词/ci.song.8000.json','["蝴蝶梦魂，芭蕉身世，几人得到庞眉。", "十分如意，天赋古今稀。", "昼日猥叨三接，摩鹏翼、曾化鲲池。", "槐阴下，深惭房魏，那敢作封彝。", "雁行，争接翅，北门矩烛，西掖纶丝。", "幸归来半世，园路先治。", "渔唱樵歌不到，莺燕语、何畏人知。", "编花史，修篁千亩，封植具穹碑。"]'),
('song-ci-763','满庭芳','洪适','宋','宋词','song-ci','满庭芳','[]','春入花畦，雪迷筠坞，柳梢未肯低眉。',118,'宋词/ci.song.8000.json','["春入花畦，雪迷筠坞，柳梢未肯低眉。", "泥深路滑，车马往来稀。", "平地琼琚盈尺，冰冻解、檐水如池。", "皇华喜，增添泉货，不铸尚方彝。", "光阴，驹过隙，髭髯如戟，容易成丝。", "把诗盟长讲，酒病休治。", "两两垂螺舞彻，藏羌管、人已潜知。", "樯乌转，钱流地上，褒诏便刊碑。"]'),
('song-ci-764','满庭芳','洪适','宋','宋词','song-ci','满庭芳','[]','当国无功，归田有分，四山浓抹烟眉。',118,'宋词/ci.song.8000.json','["当国无功，归田有分，四山浓抹烟眉。", "春云多变，清昼惠风稀。", "欲踵兰亭故事，溪水涨、簪盍鹅池。", "临修竹，一觞一咏，考古到辛彝。", "当时。", "龙衮侧，亲闻胪句，天语如丝。", "谩三年博士，局冗争治。", "底事绣衣留滞，青天瑞、奴隶皆知。", "迎归诏，鸾台凤阁，名记壁间碑。"]'),
('song-ci-765','满庭芳','洪适','宋','宋词','song-ci','满庭芳','[]','草阁烟横，花蹊雨润，伤春谁画鸦眉。',118,'宋词/ci.song.8000.json','["草阁烟横，花蹊雨润，伤春谁画鸦眉。", "药囊未减，尊酒自然稀。", "堪叹云和挂壁，弦半绝、鼠啮龙池。", "投壶罢，凭阑玩古，罗列父丁彝。", "龟巢，添绿皱，残梅片片，新柳丝丝。", "恨风狂折竹，鹤病谁治。", "自信年衰景短，甘冷淡、应也天知。", "埙篪奏，清歌醉墨，一一上圭碑。"]'),
('song-ci-766','满庭芳','洪适','宋','宋词','song-ci','满庭芳','[]','雨洗花林，春回柳岸，窗间列岫横眉。',118,'宋词/ci.song.8000.json','["雨洗花林，春回柳岸，窗间列岫横眉。", "老来光景，生怕聚谈稀。", "何事扁舟西去，收杖屦、契阔鱼池。", "流觞近，诗筒暂歇，焉用虎文彝。", "良辰，怀旧事，海棠花下，笑摘垂丝。", "叹五年一别，万病难治。", "几处绣衣尘迹，歌舞地、乌鹊曾知。", "君今去，珠帘暮卷，山雨拂崇碑。"]'),
('song-ci-767','满庭芳','洪适','宋','宋词','song-ci','满庭芳','[]','旧日盘洲，藏钩卜夜，松儿笑拣双眉。',118,'宋词/ci.song.8000.json','["旧日盘洲，藏钩卜夜，松儿笑拣双眉。", "老人好静，此乐数年稀。", "尚记乘舟西溯，楼卷雪、曾到雷池。", "今非惜，畏寒闭户，弃掷夏商彝。", "入春，逾两月，轻烟非雾，细雨如丝。", "任风颓花架，不惮装治。", "想得醉吟滕阁，家园事、争解详知。", "归来好，猿惊鹤怨，孤负辋川碑。"]'),
('song-ci-768','望江南・忆江南','洪适','宋','宋词','song-ci','望江南・忆江南','[]','嗟故岁，夏旱复秋阳。',64,'宋词/ci.song.8000.json','["嗟故岁，夏旱复秋阳。", "十雨五风皆定数，千方百计为灾伤。", "小郡怎禁当。", "劳拊字，惠露洽丁黄。", "田舍炊烟常蔽野，居民安堵不离乡。", "祖道免赍粮。"]'),
('song-ci-769','望江南・忆江南','洪适','宋','宋词','song-ci','望江南・忆江南','[]','倾盖侣，古语诵邹阳。',64,'宋词/ci.song.8000.json','["倾盖侣，古语诵邹阳。", "曲水一觞今意懒，阳关三叠重情伤。", "离恨落花当。", "人截镫，归骑莫仓黄。", "谁肯甘心迷簿领，不如袖手傲家乡。", "高枕熟黄粱。"]'),
('song-ci-770','西江月','洪适','宋','宋词','song-ci','西江月','[]','小室坐毡重叠，红炉兽炭交加。',58,'宋词/ci.song.8000.json','["小室坐毡重叠，红炉兽炭交加。", "一卮村酒吸流霞。", "窗外寒威可怕。", "心在盘洲种柳，眼看密雪飞花。", "银杯缟带不随车。", "江上渔蓑难画。"]'),
('song-ci-771','西江月','洪适','宋','宋词','song-ci','西江月','[]','席上酒杯难减，鼎中药味频加。',58,'宋词/ci.song.8000.json','["席上酒杯难减，鼎中药味频加。", "老人争得脸如霞。", "镜里衰容人怕。", "檐溜尽成冰柱，前村变却梅花。", "琼瑶破碎为行车。", "冻雀盈枝堪画。"]'),
('song-ci-772','眼儿媚','洪适','宋','宋词','song-ci','眼儿媚','[]','瀛仙好客过当时。',58,'宋词/ci.song.8000.json','["瀛仙好客过当时。", "锦幌出蛾眉。", "体轻飞燕，歌欺樊素，压尽芳菲。", "花前一盼嫣然媚，滟滟举金卮。", "断肠狂客，只愁径醉，银漏催归。"]'),
('song-ci-773','六州歌头','洪适','宋','宋词','song-ci','六州歌头','[]','严更永，今夕是何年。',163,'宋词/ci.song.8000.json','["严更永，今夕是何年。", "玉衡正，钩陈灿，天字起祥烟。", "协风应、江海安澜。", "重规仍叠矩，圣主乘乾。", "尧授舜、盛事光前。", "称寿玉卮边。", "三年亲祀，一阳回律，八乡承宇，觚陛紫为坛。", "仰天颜。", "斋居寂，诚心肃，礼容专。", "存锺石，约舆卫，五辂不求全。", "听金钥、虎旅无眠。", "俨千官。", "须期显。", "相嘉笾。", "一人俭德动天渊。", "费减大农钱。", "神示格，宗祧燕。", "人民悦，祉福正绵绵。"]'),
('song-ci-774','十二时・忆少年','洪适','宋','宋词','song-ci','十二时・忆少年','[]','庭有燎，叠鼓鸣鼍。',160,'宋词/ci.song.8000.json','["庭有燎，叠鼓鸣鼍。", "更问夜如何。", "信星彪列，天象森罗。", "虞旦閟宫毕，觞清庙，浆柘尊牺继猗那。", "嘉颂可同科。", "卮圣万肩摩。", "饬躬三宿，泰畤缛仪多。", "丘泽合，岳渎从曦娥。", "神光烛、云车风马，芝作盖，玉为珂。", "奉瑄成礼，燔柴竣事，休嘉砰，隐丹阙，湛恩波。", "共愿乾坤隤祉，边鄙投戈。", "覆盂连瀚海，洗甲挽天河。", "欣欣喜色，长遇六龙过。", "奏云和。", "三春荐嘉禾。"]'),
('song-ci-775','奉礼歌','洪适','宋','宋词','song-ci','奉礼歌','[]','吹葭缇龠气潜分。',173,'宋词/ci.song.8000.json','["吹葭缇龠气潜分。", "云采宜书壤效珍。", "长日至，一阳新。", "四时玉烛和匀。", "物欣欣。", "造化转洪钧。", "郊之祭，孤竹管，六变舞云门。", "自古严禋。", "牺牲具，粢盛洁，豆笾陈。", "衮龙陟降，币玉纷纶。", "彻高阍。", "灵之斿，神哉沛，排历昆仑。", "九歌毕，盈郊瞻槱燎，斗转参横将旦，天开地辟如春。", "清跸移轮。", "阗然鼓吹相闻。", "籋祥云。", "欢胪八陛，厘逆三神。", "圣矣吾君。", "华封祝、慈宫万寿，椒掖多男，六合同文。"]'),
('song-ci-776','降仙台','洪适','宋','宋词','song-ci','降仙台','[]','漏残柝静鸡声远，到高燎。',120,'宋词/ci.song.8000.json','["漏残柝静鸡声远，到高燎。", "入层霄。", "云裘蟠瑞霭，天步下嘉坛，旗旆飘摇。", "黄麾列仗貔貅整，气压江潮。", "导前从后盛官僚。", "玉佩间金貂。", "望扶桑，日渐高。", "阴霾霜雪，底处不潜消。", "辇路祥飙。", "披拂绛纱袍。", "云间瑞阙仰岹嶢。", "播春泽、喜浃黎苗。", "礼成大庆，鳌三抃、受昕朝。"]'),
('song-ci-777','导引','洪适','宋','宋词','song-ci','导引','[]','重华天子，长至奉神虞。',59,'宋词/ci.song.8000.json','["重华天子，长至奉神虞。", "九奏会轩朱。", "星晖云润东方晓，拜贶竹宫初。", "归来千乘护皇舆。", "瑞景集金铺。", "鸡竿高唱恩书下，惠露匝中区。"]'),
('song-ci-778','点绛唇','韩元吉','宋','宋词','song-ci','点绛唇','[]','木落霜浓，探春只道梅花未。',50,'宋词/ci.song.8000.json','["木落霜浓，探春只道梅花未。", "嫩红相倚。", "灼灼新妆腻。", "莫问仙源，且问花前事。", "休辞醉。", "想君园□。", "总是生春地。"]'),
('song-ci-779','浣溪沙','韩元吉','宋','宋词','song-ci','浣溪沙','[]','莫惜清尊领客同。',48,'宋词/ci.song.8000.json','["莫惜清尊领客同。", "已无花伴舞衣红。", "强歌归去莫匆匆。", "细雨弄烟烟弄日，断云黏水水黏空。", "酴醿飞下晚来风。"]'),
('song-ci-780','霜天晓角','韩元吉','宋','宋词','song-ci','霜天晓角','[]','倚天绝壁。',53,'宋词/ci.song.8000.json','["倚天绝壁。", "直下江千尺。", "天际两蛾凝黛，愁与恨、几时极。", "怒潮风正急。", "酒醒闻塞笛。", "试问谪仙何处，青天外、远烟碧。"]'),
('song-ci-781','霜天晓角','韩元吉','宋','宋词','song-ci','霜天晓角','[]','几声残角。',53,'宋词/ci.song.8000.json','["几声残角。", "月照梅花薄。", "花下有人同醉，风满槛、波明阁。", "夜寂香透幕。", "酒深寒未著。", "莫把玉肌相映，愁花见、也羞落。"]'),
('song-ci-782','菩萨蛮','韩元吉','宋','宋词','song-ci','菩萨蛮','[]','春残日日风和雨。',52,'宋词/ci.song.8000.json','["春残日日风和雨。", "烟江目断春无处。", "山路有黄鹂。", "背人相唤飞。", "解鞍宿酒醒。", "敧枕残香冷。", "梦想小亭东。", "蔷薇何似红。"]'),
('song-ci-783','菩萨蛮','韩元吉','宋','宋词','song-ci','菩萨蛮','[]','江南雪里花如玉。',52,'宋词/ci.song.8000.json','["江南雪里花如玉。", "风流越样新装束。", "恰恰缕金裳。", "浓熏百和香。", "分明篱菊艳。", "却作妆梅面。", "无处奈君何。", "一枝春更多。"]'),
('song-ci-784','菩萨蛮','韩元吉','宋','宋词','song-ci','菩萨蛮','[]','薄云卷雨凉成阵。',52,'宋词/ci.song.8000.json','["薄云卷雨凉成阵。", "雨晴陡觉荷香润。", "波影澹寒星。", "水边镫火明。", "白苹洲上路。", "几度来还去。", "敧枕恨茫茫。", "笛声依夜长。"]'),
('song-ci-785','菩萨蛮','韩元吉','宋','宋词','song-ci','菩萨蛮','[]','诏书昨夜先春到。',52,'宋词/ci.song.8000.json','["诏书昨夜先春到。", "留公一共梅花笑。", "青琐凤凰池。", "十年归已迟。", "灵溪霜后水。", "的的清无比。", "比似使君清。", "要知清更明。"]'),
('song-ci-786','菩萨蛮','韩元吉','宋','宋词','song-ci','菩萨蛮','[]','墙根新笋看成竹。',52,'宋词/ci.song.8000.json','["墙根新笋看成竹。", "青梅老尽樱桃熟。", "幽墙几多花。", "落红成暮霞。", "闭门风又雨。", "只道春归去。", "媚脸笑持杯。", "却惊春思回。"]'),
('song-ci-787','菩萨蛮','韩元吉','宋','宋词','song-ci','菩萨蛮','[]','梧桐叶上秋萧瑟。',52,'宋词/ci.song.8000.json','["梧桐叶上秋萧瑟。", "画阑桂树攒金碧。", "花底最风流。", "相逢不上楼。", "数枝添宝髻。", "滴滴香沾袂。", "杯到莫留残。", "雾窗疑广寒。"]'),
('song-ci-788','减字木兰花','韩元吉','宋','宋词','song-ci','减字木兰花','[]','壶中春早。',52,'宋词/ci.song.8000.json','["壶中春早。", "翦刻工夫天自巧。", "雨转风斜。", "吹作千林到处花。", "瑶池清浅。", "璧月琼枝朝暮见。", "莫上扁舟。", "且醉仙家白玉楼。"]'),
('song-ci-789','减字木兰花','韩元吉','宋','宋词','song-ci','减字木兰花','[]','风梳雨洗。',52,'宋词/ci.song.8000.json','["风梳雨洗。", "玉阙琼楼何处是。", "万里秋容。", "唤起嫦娥酒未中。", "相逢且醉。", "忙里偷闲知有几。", "况自丰年。", "须信金华别是天。"]'),
('song-ci-790','诉衷情','韩元吉','宋','宋词','song-ci','诉衷情','[]','疏疏密密未开时。',54,'宋词/ci.song.8000.json','["疏疏密密未开时。", "装点最繁枝。", "分明占断秋思，一任晓风吹。", "金屡细，翠绡垂。", "画阑西。", "嫦娥也道，一种幽香，几处相宜。"]'),
('song-ci-791','谒金门','韩元吉','宋','宋词','song-ci','谒金门','[]','春尚浅。',53,'宋词/ci.song.8000.json','["春尚浅。", "谁把玉英裁翦。", "尽道梅梢开未遍。", "卷帘花满院。", "楼上酒融歌暖。", "楼下水平烟远。", "却似涌金门外见。", "絮飞波影乱。"]'),
('song-ci-792','谒金门','韩元吉','宋','宋词','song-ci','谒金门','[]','幽槛暑。',53,'宋词/ci.song.8000.json','["幽槛暑。", "又是一年重午。", "猎猎风蒲吹翠羽。", "楚天梅熟雨。", "往事潇湘南浦。", "魂断画船箫鼓。", "双叶石榴红半吐。", "倩君聊寄与。"]'),
('song-ci-793','好事近','韩元吉','宋','宋词','song-ci','好事近','[]','华屋翠云深，云外晚山千叠。',53,'宋词/ci.song.8000.json','["华屋翠云深，云外晚山千叠。", "眼底无穷春事，对杨枝桃叶。", "老来沈醉为花狂，霜鬓未须镊。", "几许夜阑清梦，任翻成胡蝶。"]'),
('song-ci-794','好事近','韩元吉','宋','宋词','song-ci','好事近','[]','秋意满芙蓉，红映小园丛竹。',53,'宋词/ci.song.8000.json','["秋意满芙蓉，红映小园丛竹。", "风里凤箫声扬，有新妆明玉。", "诗翁相对两悠然，一醉绕黄菊。", "目尽晚山横处，共修眉争绿。"]'),
('song-ci-795','秦楼月・忆秦娥','韩元吉','宋','宋词','song-ci','秦楼月・忆秦娥','[]','莺声寂。',56,'宋词/ci.song.8000.json','["莺声寂。", "春风欲去难踪迹。", "难踪迹。", "几枝红叶，万金消得。", "青铜镜里朱阑侧。", "照人也似倾城色。", "倾城色。", "一尊莫负，赏心良夕。"]'),
('song-ci-796','朝中措','韩元吉','宋','宋词','song-ci','朝中措','[]','危亭崛起卧苍龙。',57,'宋词/ci.song.8000.json','["危亭崛起卧苍龙。", "绝景画图中。", "便作龙山高会，千年乐事能同。", "使君宴处，丹枫影澹，黄花香浓。", "不惜归鞍照月，直教破帽吹风。"]'),
('song-ci-797','贺圣朝','韩元吉','宋','宋词','song-ci','贺圣朝','[]','斜阳只向花梢驻。',58,'宋词/ci.song.8000.json','["斜阳只向花梢驻。", "似愁君西去。", "清歌也便做阳关，更朝来风雨。", "佳人莫道，一杯须近，总眉峰偷聚。", "明年归诏上鸾台，记别离难处。"]'),
('song-ci-798','西江月','韩元吉','宋','宋词','song-ci','西江月','[]','一度难逢佳节，今年两度重阳。',58,'宋词/ci.song.8000.json','["一度难逢佳节，今年两度重阳。", "菊花犹折御衣黄。", "莫惜危亭更上。", "况有飞觞滟玉，从教醉帽吹香。", "兴来相与共清狂。", "频把新词细唱。"]'),
('song-ci-799','西江月','韩元吉','宋','宋词','song-ci','西江月','[]','山路冥冥雨暗，溪桥阵阵花飞。',58,'宋词/ci.song.8000.json','["山路冥冥雨暗，溪桥阵阵花飞。", "一年寂寂又春归。", "白发自惊尘世。", "不惜障泥渡水，且寻团扇题诗。", "杜鹃休绕暮烟啼。", "我欲风前重醉。"]'),
('song-ci-800','燕归梁','韩元吉','宋','宋词','song-ci','燕归梁','[]','凉月圆时翠帐深。',62,'宋词/ci.song.8000.json','["凉月圆时翠帐深。", "锁非雾沈沈。", "广寒宫里未归人。", "共结屋、住黄金。", "繁枝未老秋光澹，好风露、总关心。", "天香不奈远相寻。", "更翦巧、上瑶簪。"]'),
('song-ci-801','南柯子・南歌子','韩元吉','宋','宋词','song-ci','南柯子・南歌子','[]','急雨朝来过，浓云晚半收。',62,'宋词/ci.song.8000.json','["急雨朝来过，浓云晚半收。", "荷香便傍酒尊浮。", "极目澹烟斜照、满芳洲。", "消尽人间暑，翻成一段秋。", "使星南楚转东瓯。", "只恐禁林归诏、未容留。"]'),
('song-ci-802','南柯子・南歌子','韩元吉','宋','宋词','song-ci','南柯子・南歌子','[]','野杏抟枝熟，戎葵抱叶开。',62,'宋词/ci.song.8000.json','["野杏抟枝熟，戎葵抱叶开。", "村村箫鼓画船回。", "客里不知时节、又相催。", "角黍堆冰碗，兵符点翠钗。", "去年今日共传杯。", "应拈榴花独立、望归来。"]'),
('song-ci-803','浪淘沙','韩元吉','宋','宋词','song-ci','浪淘沙','[]','席地赏残红。',64,'宋词/ci.song.8000.json','["席地赏残红。", "少驻孤蓬。", "一春不奈风和雨。", "雨自无情风有恨，花片西东。", "云澹远峰浓。", "绿遍高桐。", "神仙知在此山中。", "万古消凝多少事，目尽晴空。"]'),
('song-ci-804','浪淘沙','韩元吉','宋','宋词','song-ci','浪淘沙','[]','倦客怕离歌。',64,'宋词/ci.song.8000.json','["倦客怕离歌。", "春已无多。", "闲愁须倩酒消磨。", "风雨才晴今夜月，不醉如何。", "玉笋滟金荷。", "情在双蛾。", "二年能得几经过。", "花满碧蹊归棹远，回首烟波。"]'),
('song-ci-805','浪淘沙','韩元吉','宋','宋词','song-ci','浪淘沙','[]','鶗鴂怨花残。',64,'宋词/ci.song.8000.json','["鶗鴂怨花残。", "谁道春阑。", "多情红药待君看。", "浓澹晓妆新意态，独占西园。", "风叶万枝繁。", "犹记平山。", "五云楼映玉成盘。", "二十四桥明月下，谁凭朱阑。"]'),
('song-ci-806','鹧鸪天','韩元吉','宋','宋词','song-ci','鹧鸪天','[]','山绕江城腊又残。',64,'宋词/ci.song.8000.json','["山绕江城腊又残。", "朔风垂地雪成团。", "莫将带雨梨花认，且作临风柳絮看。", "烟杳渺，路弥漫。", "千林犹待月争寒。", "凭君细酌羔儿酒，倚遍琼楼十二阑。"]'),
('song-ci-807','鹧鸪天','韩元吉','宋','宋词','song-ci','鹧鸪天','[]','不惜黄花插满头。',64,'宋词/ci.song.8000.json','["不惜黄花插满头。", "花应却为老人羞。", "年年九日常拚醉，处处登高莫浪愁。", "酬美景，驻清秋。", "绿橙香嫩酒初浮。", "多情雨后双溪水，红满斜阳自在流。"]'),
('song-ci-808','鹧鸪天','韩元吉','宋','宋词','song-ci','鹧鸪天','[]','老去休惊节物催。',64,'宋词/ci.song.8000.json','["老去休惊节物催。", "菊花端的为君开。", "携壶幸有齐山客，怀古还如单父台。", "松掩映，水萦回。", "使君强健得重来。", "不须细把茱萸看，且尽丰年酒一杯。"]'),
('song-ci-809','虞美人','韩元吉','宋','宋词','song-ci','虞美人','[]','西风斜日兰皋路。',66,'宋词/ci.song.8000.json','["西风斜日兰皋路。", "碧嶂连红树。", "天公也有惜君行。", "小雨霏霏特地、不成晴。", "满城桃李春来处。", "我老君宜住。", "莫惊华发笑相扶。", "记取他年同姓、两尚书。"]'),
('song-ci-810','虞美人','韩元吉','宋','宋词','song-ci','虞美人','[]','登临自古骚人事。',66,'宋词/ci.song.8000.json','["登临自古骚人事。", "惨栗天涯意。", "金华峰顶做重阳。", "月地千寻风里、万枝香。", "相君携客相应记。", "几处容狂醉。", "双溪明月乱山青。", "飞梦时时犹在、最高亭。"]'),
('song-ci-811','虞美人','韩元吉','宋','宋词','song-ci','虞美人','[]','烟霄脉脉停机杼。',66,'宋词/ci.song.8000.json','["烟霄脉脉停机杼。", "双鹊飞来语。", "踏歌声转玉钩斜。", "好是满天风露、一池花。", "离多会少从来有。", "不似人间久。", "欢情谁道隔年迟。", "须信仙家日月、未多时。"]'),
('song-ci-812','虞美人','韩元吉','宋','宋词','song-ci','虞美人','[]','诏书昨夜催春到。',66,'宋词/ci.song.8000.json','["诏书昨夜催春到。", "绿野花争早。", "几枝先见海棠开。", "全胜陇头冲雪、寄江梅。", "破寒滴滴娇如醉。", "不比春饶睡。", "万红千紫莫嫌迟。", "看取满城花送、衮衣归。"]'),
('song-ci-813','夜行船','韩元吉','宋','宋词','song-ci','夜行船','[]','极目高亭横远岫。',68,'宋词/ci.song.8000.json','["极目高亭横远岫。", "拂新晴、黛蛾依旧。", "策马重来，秋光如画，霜满翠梧高柳。", "菊美橙香还封酒。", "欢情似、那时重九。", "楼上清风，溪头明月，不道沈郎消瘦。"]'),
('song-ci-814','南乡子','韩元吉','宋','宋词','song-ci','南乡子','[]','江路木犀天。',66,'宋词/ci.song.8000.json','["江路木犀天。", "梨枣吹风树树悬。", "只道荔枝无驿使，依然。", "赢得骊珠万颗传。", "香露滴芳鲜。", "并蒂连枝照绮筵。", "惊走梧桐双睡鹊，应怜。", "腰底黄金作弹圆。"]'),
('song-ci-815','南乡子','韩元吉','宋','宋词','song-ci','南乡子','[]','细雨弄中秋。',66,'宋词/ci.song.8000.json','["细雨弄中秋。", "雨歇烟霄玉镜流。", "唤起佳人横玉笛，凝眸。", "收拾风光上小楼。", "烂醉拚扶头。", "明日阴晴且漫愁。", "二十四桥何处是，悠悠。", "忍对嫦娥说旧游。"]'),
('song-ci-816','醉落魄・一斛珠','韩元吉','宋','宋词','song-ci','醉落魄・一斛珠','[]','楼头晚鼓。',67,'宋词/ci.song.8000.json','["楼头晚鼓。", "佳人莫唱黄金缕。", "良宵镫火还三五。", "肠断扁舟，明日江南去。", "离觞欲醉谁能许。", "风前蝶闹蜂儿舞。", "明年此夜知何处。", "且插梅花，同听画檐雨。"]'),
('song-ci-817','醉落魄・一斛珠','韩元吉','宋','宋词','song-ci','醉落魄・一斛珠','[]','菊花又折。',67,'宋词/ci.song.8000.json','["菊花又折。", "今年真是龙山客。", "杯行潋滟新醅白。", "一醉相欢，莫便话离恻。", "从教破帽频敧侧。", "楼头霜树明秋色。", "凭高待把疏星摘。", "天近风情，不怕暮云隔。"]'),
('song-ci-818','一翦梅','韩元吉','宋','宋词','song-ci','一翦梅','[]','竹里疏枝总是梅。',72,'宋词/ci.song.8000.json','["竹里疏枝总是梅。", "月白霜清，犹未全开。", "相逢聊与著诗催。", "要趁金波，满泛金杯。", "多病渐非作赋才。", "醉到花前，探得春回。", "明年公已在鸾台。", "看取春风，丹诏重来。"]'),
('song-ci-819','临江仙','韩元吉','宋','宋词','song-ci','临江仙','[]','记得年时离别夜，都门强半清秋。',70,'宋词/ci.song.8000.json','["记得年时离别夜，都门强半清秋。", "今年想望只邻州。", "星连南极动，月满大江流。", "芸阁老仙多妙语，云阶清梦曾游。", "屐声还认庾公楼。", "金波摇酒面，河影堕帘钩。"]'),
('song-ci-820','临江仙','韩元吉','宋','宋词','song-ci','临江仙','[]','自古文章贤太守，江南只数苏州。',70,'宋词/ci.song.8000.json','["自古文章贤太守，江南只数苏州。", "而今太守更风流。", "熏香开画阁，迎月上西楼。", "见说宫妆高髻拥，司空却是遨头。", "五湖莫便具扁舟。", "玉堂红蕊在，还胜百花洲。"]'),
('song-ci-821','江神子・江城子','韩元吉','宋','宋词','song-ci','江神子・江城子','[]','十年此地看花时。',86,'宋词/ci.song.8000.json','["十年此地看花时。", "醉题诗。", "夜弹棋。", "湖海相逢，曾共惜芳菲。", "前度刘郎今度客，嗟老矣，鬓成丝。", "江梅吹尽柳桥西。", "雪纷飞。", "画船移。", "满眼青山，依旧带寒溪。", "往事如云无处问，云外月、也应知。"]'),
('song-ci-822','江神子・江城子','韩元吉','宋','宋词','song-ci','江神子・江城子','[]','金银楼阁认蓬莱。',86,'宋词/ci.song.8000.json','["金银楼阁认蓬莱。", "晓烟开。", "上崔嵬。", "风引孤帆，谁道却船回。", "鹏翼倚天鳌背稳，惊浪起，雪成堆。", "翩翩黄鹤为谁来。", "醉持杯。", "共徘徊。", "四面江声，脚底隐晴雷。", "织女机头凭借问，何处更、有琼台。"]'),
('song-ci-823','满江红','韩元吉','宋','宋词','song-ci','满江红','[]','梅欲开时，君欲去、花谁同折。',115,'宋词/ci.song.8000.json','["梅欲开时，君欲去、花谁同折。", "应怅望、江津千树，晚烟明雪。", "花似故人相见好，人如塞雁多离别。", "待留君、重看水边花，花边月。", "台城路，山如阙。", "追往事，伤时节。", "但春风春雨，古人愁绝。", "多少扬州诗兴在，直须清梦翻胡蝶。", "问他年、谁记饮中仙，花应说。"]'),
('song-ci-824','满江红','韩元吉','宋','宋词','song-ci','满江红','[]','寂寞山城，春已半、好花都折。',115,'宋词/ci.song.8000.json','["寂寞山城，春已半、好花都折。", "无奈向、阴晴不定，冷烟寒食。", "莫问花残风又雨，且须烂醉酬春色。", "叹使君、华发又重来，人应识。", "丹井畔，山桥侧。", "空翠里，烟如织。", "便直教马上，醉巾沾湿。", "丞相车茵端未惜，孟公好客聊无客。", "算明年、溪路海棠开，还应忆。"]'),
('song-ci-825','满江红','韩元吉','宋','宋词','song-ci','满江红','[]','江绕层城，重楼迥、依然山色。',115,'宋词/ci.song.8000.json','["江绕层城，重楼迥、依然山色。", "□□有、佳人犹记，旧家离别。", "把酒只如当日醉，挥毫剩欠尊前客。", "算平林、有恨寄伤心，烟如织。", "湖平树，花连陌。", "风景是，光阴易。", "叹新声浑在，断云难觅。", "暮雨不成巫峡梦，数峰还认湘波瑟。", "但与君、同看小槽红，真珠滴。"]'),
('song-ci-826','水调歌头','韩元吉','宋','宋词','song-ci','水调歌头','[]','世事不须问，我老但宜仙。',114,'宋词/ci.song.8000.json','["世事不须问，我老但宜仙。", "南溪一曲，独对苍翠与孱颜。", "月白风清长夏。", "醉里相逢林下。", "欲辩已忘言。", "无客问生死，有竹报平安。", "少年期，功名事，觅燕然。", "如今憔悴，萧萧华发抱尘编。", "万里蓬莱归路。", "一醉瑶台风露。", "因酒得天全。", "笑指云阶梦，今夕是何年。"]'),
('song-ci-827','水调歌头','韩元吉','宋','宋词','song-ci','水调歌头','[]','江路晓来雨，残暑夜全消。',114,'宋词/ci.song.8000.json','["江路晓来雨，残暑夜全消。", "人言天上今夕，飞鹊渐成桥。", "杳杳云车何处。", "脉脉红蕖香度。", "瓜果趁良宵。", "推枕断虹卷，抚槛白鱼跳。", "无湖客，临风露，倚兰苕。", "云涛四起，极目人世有烟霄。", "我送君舟西渡。", "君望我帆南浦。", "明日恨迢迢。", "且醉吴淞月，重听浙江潮。"]'),
('song-ci-828','水调歌头','韩元吉','宋','宋词','song-ci','水调歌头','[]','明月照多景，一话九经年。',114,'宋词/ci.song.8000.json','["明月照多景，一话九经年。", "故人何在，依约蜀道倚青天。", "豪气如今谁在。", "剩对岷峨山水。", "落纸起云烟。", "应有阳台女，来寿隐中仙。", "相如赋，王褒颂，子云玄。", "兰台麟阁，早晚飞诏下甘泉。", "梦绕神州归路。", "却趁鸡鸣起舞。", "馀事勒燕然。", "白首待君老，同泛五湖船。"]'),
('song-ci-829','水调歌头','韩元吉','宋','宋词','song-ci','水调歌头','[]','潋潋桂华满，摇落楚江秋。',114,'宋词/ci.song.8000.json','["潋潋桂华满，摇落楚江秋。", "去年今夜，相望千里一扁舟。", "满目都门风露。", "离别凄凉几度。", "霜雪渐盈头。", "山水最佳处，常恨不同游。", "少年约，谈笑事，取封侯。", "田园归晚，休问适不用吾谋。", "身外功名何处。", "屈指如今老去。", "无梦到金瓯。", "剩买五湖月，吹笛下沧洲。"]'),
('song-ci-830','水调歌头','韩元吉','宋','宋词','song-ci','水调歌头','[]','今日俄重九，莫负菊花开。',114,'宋词/ci.song.8000.json','["今日俄重九，莫负菊花开。", "试寻高处，携手蹑屐上崔嵬。", "放目苍岩千仞。", "云护晓霜成阵。", "知我与君来。", "古寺倚修竹，飞槛绝纤埃。", "笑谈间，风满座，酒盈杯。", "仙人跨海，休问随处是蓬莱。", "落日平原西望。", "鼓角秋深悲壮。", "戏马但荒台。", "细把茱萸看，一醉且徘徊。"]'),
('song-ci-831','水调歌头','韩元吉','宋','宋词','song-ci','水调歌头','[]','泽国又秋晚，天际有飞鸿。',114,'宋词/ci.song.8000.json','["泽国又秋晚，天际有飞鸿。", "中原何在，极目千里暮云重。", "今古长干桥下，遗恨都随流水，西去几时东。", "斜日动歌管，萸菊舞西风。", "江南岸，淮南渡，草连空。", "石城潮落，寂寞烟树锁离宫。", "且斗尊前酒美，莫问楼头佳丽，往事有无中。", "却笑东山老，拥鼻与谁同。"]'),
('song-ci-832','水调歌头','韩元吉','宋','宋词','song-ci','水调歌头','["\u897f\u6e56"]','落日澹芳草，烟际一鸥浮。',114,'宋词/ci.song.8000.json','["落日澹芳草，烟际一鸥浮。", "西湖好处，君去千里为谁留。", "坐想敬亭山下，竹映一溪寒水，飞盖共追游。", "况有尊前客，相对两诗流。", "笑谈间，风满座，气横秋。", "平生壮志，长啸起舞看吴钩。", "红白山花开谢，半醉半醒时节，春去子规愁。", "梦绕水西寺，回首谢公楼。"]'),
('song-ci-833','醉蓬莱','韩元吉','宋','宋词','song-ci','醉蓬莱','[]','听清歌初转，翠岭云横，乍飞还驻。',120,'宋词/ci.song.8000.json','["听清歌初转，翠岭云横，乍飞还驻。", "水落秋明，正千岩呈露。", "况有宾朋，飘然才调，尽凌空鹓鹭。", "步绕西畴，同寻南涧，郊原新雨。", "好客声名，郑庄风韵，松菊栽成，故侯瓜圃。", "燕去鸿来，笑人生离聚。", "老子偷闲，爱君三径，共一尊芳醑。", "待约梅仙，他年丹就，骑鲸飞去。"]'),
('song-ci-834','念奴娇','韩元吉','宋','宋词','song-ci','念奴娇','[]','去年秋半，正都门结束，相将离别。',120,'宋词/ci.song.8000.json','["去年秋半，正都门结束，相将离别。", "潋潋双溪新雁过，重见当时明月。", "步转高楼，凄凉看镜，绿鬓纷成雪。", "晚晴烟树，傍人飞下洪叶。", "还记江浦潮生，云涛天际，涌金波一色。", "千里相望浑似梦，极目空山围碧。", "醉拍朱阑，满簪丹桂，细与姮娥说。", "倚风孤啸，恍然身在瑶阙。"]'),
('song-ci-835','念奴娇','韩元吉','宋','宋词','song-ci','念奴娇','[]','定交最早，叹西津几度，匆匆论别。',120,'宋词/ci.song.8000.json','["定交最早，叹西津几度，匆匆论别。", "世事浮云山万变，只有沧江横月。", "长忆追随，湖山好处，醉帽敧风雪。", "竹阴花径，兴来题尽桐叶。", "谁忆此地相逢，鬓毛君未白，眉添黄色。", "屈指烟霄归诏近，路入龙楼金碧。", "千载功名，一尊欢笑，会作他年说。", "倚天长剑，夜寒光透银阙。"]'),
('song-ci-836','念奴娇','韩元吉','宋','宋词','song-ci','念奴娇','[]','湖山泥影，弄晴丝、目送天涯鸿鹄。',120,'宋词/ci.song.8000.json','["湖山泥影，弄晴丝、目送天涯鸿鹄。", "春水移船花似雾，醉里题诗刻烛。", "离别经年，相逢犹健，底恨光阴速。", "壮怀浑在，浩然起舞相属。", "长记入洛声名，风流觞咏，有兰亭修竹。", "绝唱人间知不知，零落金貂谁续。", "北固烟锺，西州雪岸，且共杯中绿。", "紫台青琐，看君归上群玉。"]'),
('song-ci-837','念奴娇','韩元吉','宋','宋词','song-ci','念奴娇','[]','春来离思，正楼台灯火、香凝金戟。',120,'宋词/ci.song.8000.json','["春来离思，正楼台灯火、香凝金戟。", "扬子江头嘶骑拥，杨柳花飞留客。", "枚乘声名，谪仙风韵，更赋长相忆。", "酒阑相顾，起看月堕寒壁。", "尊前谁唱新词，平林真有恨、寒烟如织。", "燕雁横空梅蕊乱，醉里隔江闻笛。", "白发逢春，湖山好在，一笑千金直。", "待君归诏，买船重话畴昔。"]'),
('song-ci-838','水龙吟','韩元吉','宋','宋词','song-ci','水龙吟','[]','乱山深处逢春，断魂更入桃源路。',126,'宋词/ci.song.8000.json','["乱山深处逢春，断魂更入桃源路。", "双双翠羽，溅溅流水，濛濛香雾。", "花里莺啼，水边人去，落红无数。", "恨刘郎鬓点，星星华发，空回首、伤春暮。", "寂寞云间洞户。", "问当年、佳期何处。", "虹桥望断，琼楼深锁，如今谁住。", "绿满千岩，浣衣石上，倚风凝伫。", "料多情好在，也应笑我，却匆匆去。"]'),
('song-ci-839','水龙吟','韩元吉','宋','宋词','song-ci','水龙吟','[]','五溪深锁烟霞，定知不是人间世。',126,'宋词/ci.song.8000.json','["五溪深锁烟霞，定知不是人间世。", "轩然九老，排云一笑，苍颜相对。", "星斗垂空，月华随步，酒醒无寐。", "□广寒已近，嫦娥起舞，天风动、摇丹桂。", "极目层霄如洗。", "正千岩、棱棱霜气。", "飞泉半落，苍崖百仞，珠翻玉碎。", "金衲松成，葛洪丹就，如今千载。", "叹谪仙诗在，骑驴未远，且留君醉。"]'),
('song-ci-840','瑞鹤仙','韩元吉','宋','宋词','song-ci','瑞鹤仙','[]','西风吹暮雨。',126,'宋词/ci.song.8000.json','["西风吹暮雨。", "正碧树凉生，送君南浦。", "蝉声带残暑。", "满高林斜照，暝烟横渚。", "故乡路阻。", "更秋入、江城雁渡。", "怅天涯、几许闲愁，对酒共成羁旅。", "休问功名何在，绿鬓吴霜，素衣尘土。", "离觞缓举。", "收玉箸，听金缕。", "叹凌云才调，乌丝阑上，省把清诗漫与。", "见洛阳、年少交游，倩君寄语。"]'),
('song-ci-841','薄幸','韩元吉','宋','宋词','song-ci','薄幸','[]','送君南浦。',132,'宋词/ci.song.8000.json','["送君南浦。", "对烟柳、青青万缕。", "更满眼、残红吹尽，叶底黄鹂自语。", "甚动人、多少离情，楼头水阔山无数。", "记竹里题诗，花边载酒，魂断江干春暮。", "都莫问、功名事，白发渐、星星如许。", "任鸡鸣起舞，乡关何在，凭高目尽孤鸿去。", "漫留君住。", "趁酴醿香暖，持杯且醉瑶台露。", "相思记取，愁绝西窗夜雨。"]'),
('song-ci-842','临江仙','韩元吉','宋','宋词','song-ci','临江仙','[]','不恨绿阴桃李过，酴醿正向人开。',70,'宋词/ci.song.8000.json','["不恨绿阴桃李过，酴醿正向人开。", "一尊清夜月徘徊。", "花如人意好，月为此花来。", "未信人间香有许，却疑同住瑶台。", "纷纷残雪堕深杯。", "直教攀折尽，犹胜酒醒回。"]'),
('song-ci-843','南柯子・南歌子','韩元吉','宋','宋词','song-ci','南柯子・南歌子','[]','五月炎州路，千重扑地开。',62,'宋词/ci.song.8000.json','["五月炎州路，千重扑地开。", "只疑标韵是江梅。", "不道薰风庭院、雪成堆。", "宝髻琼瑶缀，仙衣翡翠裁。", "一枝长伴荔枝来。", "付与玉人和笑、插鸾钗。"]'),
('song-ci-844','醉落魄・一斛珠','韩元吉','宋','宋词','song-ci','醉落魄・一斛珠','[]','霓裳弄月。',67,'宋词/ci.song.8000.json','["霓裳弄月。", "冰肌不受人间热。", "分明密露枝枝结。", "碧树珊瑚，容易与君折。", "玉环旧事谁能说。", "迢迢驿路香风彻。", "故人莫恨东南别。", "不寄梅花，千里寄红雪。"]'),
('song-ci-845','水龙吟','韩元吉','宋','宋词','song-ci','水龙吟','[]','雨馀叠巘浮空，望中秀色仙都是。',126,'宋词/ci.song.8000.json','["雨馀叠巘浮空，望中秀色仙都是。", "洞天未锁，人间春老，玉妃曾坠。", "锦瑟繁弦，凤箫清响，九霄歌吹。", "问分香旧事，刘郎去后，知谁伴、风前醉。", "回首暝烟千里。", "但纷纷、落红如泪。", "多情易老，青鸾何许，诗成谁寄。", "斗转参横，半帘花影，一溪寒水。", "怅飞凫路杳，行云梦断，有三峰翠。"]'),
('song-ci-846','好事近','韩元吉','宋','宋词','song-ci','好事近','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','凝碧旧池头，一听管弦凄切。',53,'宋词/ci.song.8000.json','["凝碧旧池头，一听管弦凄切。", "多少梨园声在，总不堪华发。", "杏花无处避春愁，也傍野烟发。", "惟有御沟声断，似知人呜咽。"]'),
('song-ci-847','永遇乐','韩元吉','宋','宋词','song-ci','永遇乐','[]','池馆春归，帘栊昼静，清漏移箭。',128,'宋词/ci.song.8000.json','["池馆春归，帘栊昼静，清漏移箭。", "山下孤城，水边翠竹，鶗鴂声千转。", "记得年时，绮窗人去，尚有唾茸遗线。", "照珠筵、歌檀舞扇，寂寞旧家排遍。", "青云赋客，多情多病，西掖桐阴满院。", "飞絮随风，马头月在，翡翠帷空卷。", "平湖烟远，斜桥雨暗，欲寄短书双燕。", "算犹忆、兰房画烛，醉时共翦。"]'),
('song-ci-848','六州歌头','韩元吉','宋','宋词','song-ci','六州歌头','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','东风著意。',137,'宋词/ci.song.8000.json','["东风著意。", "先上小桃枝。", "红粉腻。", "娇如醉。", "倚朱扉。", "记年时。", "隐映新妆，面临水岸。", "春将半。", "云日暖。", "斜桥转。", "夹城西。", "草软莎平跋马，垂杨渡、玉勒争嘶。", "认蛾眉凝笑，脸薄拂燕支。", "绣户曾窥。", "恨依依。", "共携手处。", "香如雾。", "红随步。", "怨春迟。", "消瘦损。", "凭谁问。", "只花知。", "泪空垂。", "旧日堂前燕，和烟雨，又双飞。"]'),
('song-ci-849','水龙吟','韩元吉','宋','宋词','song-ci','水龙吟','[]','南风五月江波，使君莫袖平戎手。',126,'宋词/ci.song.8000.json','["南风五月江波，使君莫袖平戎手。", "燕然未勒，渡沪声在，宸衷怀旧。", "卧占湖山，楼横百尺，诗成千首。", "正菖蒲叶老，芙蕖香嫩，高门瑞、人知否。", "凉夜光躔牛斗。", "梦初回、长庚如昼。", "明年看取，锋旗南下，六骡西走。", "功画凌烟，万钉宝带，百壶清酒。", "便留公剩馥，蟠桃分我，作归来寿。"]'),
('song-ci-850','蓦山溪','韩元吉','宋','宋词','song-ci','蓦山溪','[]','双龙古洞，领略千岩秀。',102,'宋词/ci.song.8000.json','["双龙古洞，领略千岩秀。", "福地有真仙，来一试、调元□手。", "青春绿野，月转最高峰，星斗润，柳海新，五夜收灯后。", "诏飞天上，人倚经纶旧。", "重入辅升平，更赢得、千龄眉寿。", "功成未晚，归伴赤松游，金印重，羽衣轻，会见丹砂就。"]'),
('song-ci-851','鹊桥仙','韩元吉','宋','宋词','song-ci','鹊桥仙','[]','菊花黄后。',68,'宋词/ci.song.8000.json','["菊花黄后。", "山茶红透。", "南国小春时候。", "蓬山高处绿云间，有一个、仙宫诞秀。", "精神龟媚，骨毛鹤瘦。", "落落人中星斗。", "殷勤自折早梅芳，调一鼎、和羹为寿。"]'),
('song-ci-852','朝中措','韩元吉','宋','宋词','song-ci','朝中措','[]','清霜著柳夜来寒。',57,'宋词/ci.song.8000.json','["清霜著柳夜来寒。", "新月印湖山。", "共喜今年称寿，一尊还在长安。", "人间千载，从教鹤发，且驻朱颜。", "看取烟霄平步，何须九转神丹。"]'),
('song-ci-853','南乡子','韩元吉','宋','宋词','song-ci','南乡子','[]','新笋旋成林。',66,'宋词/ci.song.8000.json','["新笋旋成林。", "梅子枝头雨更深。", "织就彩丝犹十日，登临。", "人似江心百炼金。", "功业会相寻。", "好挹薰风和舜琴。", "鹤住千年丹九转，如今。", "门外梧桐长翠阴。"]'),
('song-ci-854','鹧鸪天','韩元吉','宋','宋词','song-ci','鹧鸪天','[]','甲子今年甫一周。',64,'宋词/ci.song.8000.json','["甲子今年甫一周。", "人间聊住八千秋。", "依依梅蕊看如雪，恰恰蟾华未上钩。", "分玉节，共南州。", "台城辇路记重游。", "相期一品归来健，兄弟华颠自献酬。"]'),
('song-ci-855','瑞鹤仙','韩元吉','宋','宋词','song-ci','瑞鹤仙','[]','好山横翠幕。',127,'宋词/ci.song.8000.json','["好山横翠幕。", "更一水流烟，嫩阴成幄。", "薰风转林薄。", "笑劳生底事，漫嗟离索。", "霞觞细酌。", "尽流年、青镜易觉。", "算芙蓉、玉井香翻，不减旧阶红药。", "寂寞。", "早玄空老，问字人稀，也胜投阁。", "骑鲸后约。", "追汗漫，记寥廓。", "便风帆高挂，云涛千里，谁道蓬壶水弱。", "任蟠桃、满路千花，自开自落。"]'),
('song-ci-856','醉落魄・一斛珠','韩元吉','宋','宋词','song-ci','醉落魄・一斛珠','[]','红蕖漾月。',67,'宋词/ci.song.8000.json','["红蕖漾月。", "薰风特地生梧叶。", "一年风月今宵别。", "隐隐笙鸾，何处有炎热。", "凤凰山下榴花发。", "一杯香露融春雪。", "幔亭有路通瑶阙。", "知我丹成，容我醉时节。"]'),
('song-ci-857','醉落魄・一斛珠','韩元吉','宋','宋词','song-ci','醉落魄・一斛珠','[]','相看半百。',67,'宋词/ci.song.8000.json','["相看半百。", "劳生等是乾坤客。", "功成一笑惊头白。", "惟有榴花，相对似颜色。", "蓬莱水浅何曾隔。", "也应待得蟠桃摘。", "我歌欲和君须拍。", "风月年年，常恨酒杯窄。"]'),
('song-ci-858','酹江月・念奴娇','黄宰','宋','宋词','song-ci','酹江月・念奴娇','[]','三光五岳，孕乾坤英彩，非金非玉。',120,'宋词/ci.song.8000.json','["三光五岳，孕乾坤英彩，非金非玉。", "赫赫岩岩真相种，来驾横空仙鹄。", "十万儿童，和丰堂下，齐指梅山祝。", "黑头难老，岁寒苍桧修竹。", "须信自家有传，中庸一卷，是长生真箓。", "借问洛阳归去后，几度桃开桃熟。", "十九年间，梦回天上，再见棠阴绿。", "相将促觐，已闻沙路新筑。"]'),
('song-ci-859','忆秦娥','朱淑真','宋','宋词','song-ci','忆秦娥','[]','弯弯曲。',56,'宋词/ci.song.8000.json','["弯弯曲。", "新年新月钩寒玉。", "钩寒玉。", "凤鞋儿小，翠眉儿蹙。", "闹蛾雪柳添妆束。", "烛龙火树争驰逐。", "争驰逐。", "元宵三五，不如初六。"]'),
('song-ci-860','浣溪纱・浣溪沙','朱淑真','宋','宋词','song-ci','浣溪纱・浣溪沙','[]','春巷夭桃吐绛英。',48,'宋词/ci.song.8000.json','["春巷夭桃吐绛英。", "春衣初试薄罗轻。", "风和烟暖燕巢成。", "小院湘帘闲不卷，曲房朱户闷长扃。", "恼人光景又清明。"]'),
('song-ci-861','生查子','朱淑真','宋','宋词','song-ci','生查子','[]','寒食不多时，几日东风恶。',48,'宋词/ci.song.8000.json','["寒食不多时，几日东风恶。", "无绪倦寻芳，闲却秋千索。", "玉减翠裙交，病怯罗衣薄。", "不忍卷帘看，寂寞梨花落。"]'),
('song-ci-862','生查子','朱淑真','宋','宋词','song-ci','生查子','[]','年年玉镜台，梅蕊宫妆困。',48,'宋词/ci.song.8000.json','["年年玉镜台，梅蕊宫妆困。", "今岁未还家，怕见江南信。", "酒从别后疏，泪向愁中尽。", "遥想楚云深，人远天涯近。"]'),
('song-ci-863','谒金门','朱淑真','宋','宋词','song-ci','谒金门','[]','春已半。',53,'宋词/ci.song.8000.json','["春已半。", "触目此情无限。", "十二阑干闲倚遍。", "愁来天不管。", "好是风和日暖。", "输与莺莺燕燕。", "满院落花帘不卷。", "断肠芳草远。"]'),
('song-ci-864','江城子','朱淑真','宋','宋词','song-ci','江城子','[]','斜风细雨作春寒。',86,'宋词/ci.song.8000.json','["斜风细雨作春寒。", "对尊前。", "忆前欢。", "曾把梨花，寂寞泪阑干。", "芳草断烟南浦路，和别泪，看青山。", "昨宵结得梦夤缘。", "水云间。", "悄无言。", "争奈醒来，愁恨又依然。", "展转衾裯空懊恼，天易见，见伊难。"]'),
('song-ci-865','减字木兰花','朱淑真','宋','宋词','song-ci','减字木兰花','[]','独行独坐。',52,'宋词/ci.song.8000.json','["独行独坐。", "独倡独酬还独卧。", "伫立伤神。", "无奈轻寒著摸人。", "此情谁见。", "泪洗残妆无一半。", "愁病相仍。", "剔尽寒灯梦不成。"]'),
('song-ci-866','眼儿媚','朱淑真','宋','宋词','song-ci','眼儿媚','[]','迟迟春日弄轻柔。',58,'宋词/ci.song.8000.json','["迟迟春日弄轻柔。", "花径暗香流。", "清明过了，不堪回首，云锁朱楼。", "午窗睡起莺声巧，何处唤春愁。", "绿杨影里，海棠亭畔，红杏梢头。"]'),
('song-ci-867','鹧鸪天','朱淑真','宋','宋词','song-ci','鹧鸪天','[]','独倚阑干昼日长。',64,'宋词/ci.song.8000.json','["独倚阑干昼日长。", "纷纷蜂蝶斗轻狂。", "一天飞絮东风恶，满路桃花春水香。", "当此际，意偏长。", "萋萋芳草傍池塘。", "千锺尚欲偕春醉，幸有荼蘼与海棠。"]'),
('song-ci-868','清平乐','朱淑真','宋','宋词','song-ci','清平乐','[]','风光紧急。',54,'宋词/ci.song.8000.json','["风光紧急。", "三月俄三十。", "拟欲留连计无及。", "绿野烟愁露泣。", "倩谁寄语春宵。", "城头画鼓轻敲。", "缱绻临歧嘱付，来年早到梅梢。"]'),
('song-ci-869','点绛唇','朱淑真','宋','宋词','song-ci','点绛唇','[]','黄鸟嘤嘤，晓来却听丁丁木。',50,'宋词/ci.song.8000.json','["黄鸟嘤嘤，晓来却听丁丁木。", "芳心已逐。", "泪眼倾珠斛。", "见自无心，更调离情曲。", "鸳帏独。", "望休穷目。", "回首溪山绿。"]'),
('song-ci-870','蝶恋花','朱淑真','宋','宋词','song-ci','蝶恋花','[]','楼外垂杨千万缕。',70,'宋词/ci.song.8000.json','["楼外垂杨千万缕。", "欲系青春，少住春还去。", "独自风前飘柳絮。", "随春且看归何处。", "绿满山川闻杜宇。", "便做无情，莫也愁人苦。", "把酒送春春不语。", "黄昏却下潇潇雨。"]'),
('song-ci-871','清平乐','朱淑真','宋','宋词','song-ci','清平乐','[]','恼烟撩露。',54,'宋词/ci.song.8000.json','["恼烟撩露。", "留我须臾住。", "携手藕花湖上路。", "一霎黄梅细雨。", "娇痴不怕人猜。", "随群暂遣愁怀。", "最是分携时候，归来懒傍妆台。"]'),
('song-ci-872','菩萨蛮','朱淑真','宋','宋词','song-ci','菩萨蛮','[]','秋声乍起梧桐落。',52,'宋词/ci.song.8000.json','["秋声乍起梧桐落。", "蛩吟唧唧添萧索。", "敧枕背灯眠。", "月和残梦圆。", "起来钩翠箔。", "何处寒砧作。", "独倚小阑干。", "逼人风露寒。"]'),
('song-ci-873','菩萨蛮','朱淑真','宋','宋词','song-ci','菩萨蛮','[]','山亭水榭秋方半。',52,'宋词/ci.song.8000.json','["山亭水榭秋方半。", "凤帏寂寞无人伴。", "愁闷一番新。", "双蛾只旧颦。", "起来临绣户。", "时有疏萤度。", "多谢月相怜。", "今宵不忍圆。"]'),
('song-ci-874','鹊桥仙','朱淑真','宋','宋词','song-ci','鹊桥仙','[]','巧云妆晚，西风罢暑，小雨翻空月坠。',68,'宋词/ci.song.8000.json','["巧云妆晚，西风罢暑，小雨翻空月坠。", "牵牛织女几经秋，尚多少、离肠恨泪。", "微凉入袂，幽欢生座，天上人间满意。", "如何暮暮与朝朝，更改却、年年岁岁。"]'),
('song-ci-875','菩萨蛮','朱淑真','宋','宋词','song-ci','菩萨蛮','[]','也无梅柳新标格。',52,'宋词/ci.song.8000.json','["也无梅柳新标格。", "也无桃李妖娆色。", "一味恼人香。", "群花争敢当。", "情知天上种。", "飘落深岩洞。", "不管月宫寒。", "将枝比并看。"]'),
('song-ci-876','点绛唇','朱淑真','宋','宋词','song-ci','点绛唇','[]','风劲云浓，暮寒无奈侵罗幕。',50,'宋词/ci.song.8000.json','["风劲云浓，暮寒无奈侵罗幕。", "髻鬟斜掠。", "呵手梅妆薄。", "少饮清欢，银烛花频落。", "恁萧索。", "青工已觉。", "点破香梅萼。"]'),
('song-ci-877','念奴娇','朱淑真','宋','宋词','song-ci','念奴娇','[]','冬晴无雪。',120,'宋词/ci.song.8000.json','["冬晴无雪。", "是天心未肯，化工非拙。", "不放玉花飞堕地，留在广寒宫阙。", "云欲同时，霰将集处，红日三竿揭。", "六花翦就，不知何处施设。", "应念陇首寒梅，花开无伴，对景真愁绝。", "待出和羹金鼎手，为把玉盐飘撒。", "沟壑皆平，乾坤如画，更吐冰轮洁。", "梁园燕客，夜明不怕灯灭。"]'),
('song-ci-878','念奴娇','朱淑真','宋','宋词','song-ci','念奴娇','[]','鹅毛细翦，是琼珠密洒，一时堆积。',120,'宋词/ci.song.8000.json','["鹅毛细翦，是琼珠密洒，一时堆积。", "斜倚东风浑漫漫，顷刻也须盈尺。", "玉作楼台，铅熔天地，不见遥岑碧。", "佳人作戏，碎揉些子抛掷。", "争奈好景难留，风﹀雨︽，打碎光凝色。", "总有十分轻妙态，谁似旧时怜惜。", "担阁梁吟，寂寥楚舞，笑捏狮儿只。", "梅花依旧，岁寒松竹三益。"]'),
('song-ci-879','卜算子','朱淑真','宋','宋词','song-ci','卜算子','[]','竹里一枝斜，映带林逾静。',52,'宋词/ci.song.8000.json','["竹里一枝斜，映带林逾静。", "雨后清奇画不成，浅水横疏影。", "吹彻小单于，心事思重省。", "拂拂风前度暗香，月色侵花冷。"]'),
('song-ci-880','菩萨蛮','朱淑真','宋','宋词','song-ci','菩萨蛮','[]','湿云不渡溪桥冷。',52,'宋词/ci.song.8000.json','["湿云不渡溪桥冷。", "娥寒初破东风影。", "溪下水声长。", "一枝和月香。", "人怜花似旧，花不知人瘦。", "独自倚阑干，夜深花正寒。"]'),
('song-ci-881','失调名','朱淑真','宋','宋词','song-ci','失调名','[]','王孙去后无芳草。',8,'宋词/ci.song.8000.json','["王孙去后无芳草。"]'),
('song-ci-882','西江月','朱淑真','宋','宋词','song-ci','西江月','[]','办取舞裙歌扇，赏春只怕春寒。',58,'宋词/ci.song.8000.json','["办取舞裙歌扇，赏春只怕春寒。", "卷帘无语对南山。", "已觉绿肥红浅。", "去去惜花心懒，踏青闲步江干。", "恰如飞鸟倦知还。", "澹荡梨花深院。"]'),
('song-ci-883','月华清','朱淑真','宋','宋词','song-ci','月华清','[]','雪压庭春，香浮花月，揽衣还怯单薄。',122,'宋词/ci.song.8000.json','["雪压庭春，香浮花月，揽衣还怯单薄。", "敧枕裴回，又听一声乾鹊。", "粉泪共、宿雨阑干，清梦与、寒云寂寞。", "除却。", "是江梅曾许，诗人吟作。", "长恨晓风漂泊。", "且莫遣香肌，瘦减如削。", "深杏夭桃，端的为谁零落。", "况天气、妆点清明，对美景、不妨行乐。", "拌著。", "向花时取，一杯独酌。"]'),
('song-ci-884','柳梢青','张抡','宋','宋词','song-ci','柳梢青','[]','柳色初匀。',61,'宋词/ci.song.8000.json','["柳色初匀。", "轻寒似水，纤雨如尘。", "一阵东风，縠绞微皱，碧沼鳞鳞。", "仙娥花月精神。", "奏凤管、鸾丝斗新。", "万岁声中，九霞杯里，长醉芳春。"]'),
('song-ci-885','蝶恋花','张抡','宋','宋词','song-ci','蝶恋花','[]','前日海棠犹未破。',70,'宋词/ci.song.8000.json','["前日海棠犹未破。", "点点胭脂，染就真珠颗。", "今日重来花下坐。", "乱铺宫锦春无那。", "剩摘繁枝簪几朵。", "痛惜深怜，只恐芳菲过。", "醉倒何妨花底卧。", "不须红袖来扶我。"]'),
('song-ci-886','临江仙','张抡','宋','宋词','song-ci','临江仙','[]','玉宇凉生清禁晓，丹葩色照晴空。',70,'宋词/ci.song.8000.json','["玉宇凉生清禁晓，丹葩色照晴空。", "珊瑚敲碎小玲珑。", "人间无此种，来自广寒宫。", "雕玉阑干深院静，嫣然凝笑西风。", "曲屏须占一枝红。", "且图敧醉枕，香到梦魂中。"]'),
('song-ci-887','临江仙','张抡','宋','宋词','song-ci','临江仙','[]','闻道彤庭森宝仗，霜风逐雨驱云。',70,'宋词/ci.song.8000.json','["闻道彤庭森宝仗，霜风逐雨驱云。", "六龙扶辇下青冥。", "香随鸾扇远，日射赭袍明。", "帘卷天街人隘路，满城喜望清尘。", "欢声催起岭梅春。", "欲知天意好，昨夜月华新。"]'),
('song-ci-888','西江月','张抡','宋','宋词','song-ci','西江月','[]','翦就碧云闹叶，刻成紫玉芳心。',58,'宋词/ci.song.8000.json','["翦就碧云闹叶，刻成紫玉芳心。", "浅春不怕峭寒侵。", "暧彻薰笼瑞锦。", "花里清芬独步，尊前胜韵难禁。", "飞香直到玉杯深。", "消得厌厌痛饮。"]'),
('song-ci-889','朝中措','张抡','宋','宋词','song-ci','朝中措','[]','灯花挑尽夜将阑。',57,'宋词/ci.song.8000.json','["灯花挑尽夜将阑。", "斜掩小屏山。", "一点凉蟾窥慢，钏敲玉臂生寒。", "起来无绪，炉薰烬冷，桐叶声乾。", "都把沈思幽恨，明朝分付眉端。"]'),
('song-ci-890','烛影摇红','张抡','宋','宋词','song-ci','烛影摇红','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','双阙中天，凤楼十二春寒浅。',116,'宋词/ci.song.8000.json','["双阙中天，凤楼十二春寒浅。", "去年元夜奉宸游，曾侍瑶池宴。", "玉殿珠帘尽卷。", "拥群仙、蓬壶阆苑。", "五云深处，万烛光中，揭天丝管。", "驰隙流年，恍如一瞬星霜换。", "今宵谁念泣孤臣，回首长安远。", "可是尘缘未断。", "谩惆怅、华胥梦短。", "满怀幽恨，数点寒灯，几声归雁。"]'),
('song-ci-891','浣溪沙','张抡','宋','宋词','song-ci','浣溪沙','[]','筑室峥嵘占宝峰。',48,'宋词/ci.song.8000.json','["筑室峥嵘占宝峰。", "退朝燕坐万缘空，出尘高志抗冥鸿。", "何日嘉招陪一笑，看君豪饮釂千锺。", "试凭鄙句作先容。"]'),
('song-ci-892','霜天晓角','张抡','宋','宋词','song-ci','霜天晓角','[]','晓风摇幕。',53,'宋词/ci.song.8000.json','["晓风摇幕。", "敧枕闻残角。", "霜月可窗寒影，金猊冷、翠衾薄。", "旧恨无处著。", "新愁还又作。", "夜夜单于声里，灯花共、泪珠落。"]'),
('song-ci-893','点绛唇','张抡','宋','宋词','song-ci','点绛唇','[]','何处春来，惠风初自东郊至。',50,'宋词/ci.song.8000.json','["何处春来，惠风初自东郊至。", "柳条花蕊。", "迤逦争明媚。", "造化难穷，谁晓幽微理。", "都来是。", "自然天地。", "一点冲和气。"]'),
('song-ci-894','点绛唇','张抡','宋','宋词','song-ci','点绛唇','[]','昨夜东风，又还吹遍闲花草。',50,'宋词/ci.song.8000.json','["昨夜东风，又还吹遍闲花草。", "翠轻红小。", "触处惊春早。", "草舍茅□，□□□□□。", "谁□□。", "□□丹灶。", "别有阳和□。"]'),
('song-ci-895','点绛唇','张抡','宋','宋词','song-ci','点绛唇','[]','阳气初生，万花潜动根荄暖。',50,'宋词/ci.song.8000.json','["阳气初生，万花潜动根荄暖。", "暗藏芳艳。", "未许东君见。", "恰似温温，铅鼎丹初转。", "功犹浅。", "九回烹炼。", "日月光华满。"]'),
('song-ci-896','点绛唇','张抡','宋','宋词','song-ci','点绛唇','[]','暖日迟迟，乱莺声在垂杨里。',50,'宋词/ci.song.8000.json','["暖日迟迟，乱莺声在垂杨里。", "昼眠惊起。", "花影间铺地。", "试问荣名，何似花前醉。", "陶陶地。", "任他门外。", "车驾喧朝市。"]'),
('song-ci-897','点绛唇','张抡','宋','宋词','song-ci','点绛唇','[]','花满名园，万红千翠交相映。',50,'宋词/ci.song.8000.json','["花满名园，万红千翠交相映。", "画阑幽径。", "行乐迷芳景。", "惟有幽人，不与浮华竞。", "便幽静。", "兴来独饮。", "花下风吹醒。"]'),
('song-ci-898','点绛唇','张抡','宋','宋词','song-ci','点绛唇','[]','春入山家，杖藜独步登严岫。',50,'宋词/ci.song.8000.json','["春入山家，杖藜独步登严岫。", "野花争秀。", "弄蕊香盈袖。", "对景开怀，莫遣双眉皱。", "春难久。", "乱红飞后。", "留得韶光否。"]'),
('song-ci-899','点绛唇','张抡','宋','宋词','song-ci','点绛唇','[]','气体冲融，四时长在阳春里。',50,'宋词/ci.song.8000.json','["气体冲融，四时长在阳春里。", "玉田琼蕊。", "养就灵苗异。", "堪笑□□，□□□□□。", "□□□。", "□□流水。", "半落苍□□。"]'),
('song-ci-900','点绛唇','张抡','宋','宋词','song-ci','点绛唇','[]','乐事难并，少年常恨春宵短。',50,'宋词/ci.song.8000.json','["乐事难并，少年常恨春宵短。", "万花丛畔。", "只恐金杯浅。", "方喜春来，又叹韶华晚。", "频相劝。", "且闻强健。", "莫厌花经眼。"]'),
('song-ci-901','点绛唇','张抡','宋','宋词','song-ci','点绛唇','[]','一瞬光阴，世人常被芳菲恼。',50,'宋词/ci.song.8000.json','["一瞬光阴，世人常被芳菲恼。", "玉壶频倒。", "惟恨春归早。", "何似逍遥，物外寻三岛。", "春长好。", "瑞芝瑶草。", "春又何曾老。"]'),
('song-ci-902','点绛唇','张抡','宋','宋词','song-ci','点绛唇','[]','浮世如何，问花何事花无语。',50,'宋词/ci.song.8000.json','["浮世如何，问花何事花无语。", "夜来风雨。", "已送韶华暮。", "念此堪惊，得失休思虑。", "从今去。", "醉乡深处。", "莫管流年度。"]'),
('song-ci-903','阮郎归','张抡','宋','宋词','song-ci','阮郎归','[]','亭亭槐柳午阴圆。',56,'宋词/ci.song.8000.json','["亭亭槐柳午阴圆。", "薰风拂舜弦。", "一轮红日贴中天。", "乾坤如火然。", "观上象，想丹田。", "阳精色正鲜。", "□从炼得体纯全。", "朱颜无岁年。"]'),
('song-ci-904','阮郎归','张抡','宋','宋词','song-ci','阮郎归','[]','欲如臭腐化神奇。',56,'宋词/ci.song.8000.json','["欲如臭腐化神奇。", "当观蝉蜕时。", "脱然飞上绿槐枝。", "炎炎昼景□。", "□□□，□如斯。", "□□□□迷。", "灵躯一旦脱□□。", "□□□□归。"]'),
('song-ci-905','阮郎归','张抡','宋','宋词','song-ci','阮郎归','[]','深亭邃馆锁清风。',56,'宋词/ci.song.8000.json','["深亭邃馆锁清风。", "榴花芳艳浓。", "阳光染就欲烧空。", "谁能窥化工。", "观物外，喻身中。", "灵砂别有功。", "若将一粒比花容。", "金丹色又红。"]'),
('song-ci-906','阮郎归','张抡','宋','宋词','song-ci','阮郎归','[]','炎天何处可登临。',56,'宋词/ci.song.8000.json','["炎天何处可登临。", "须於物外寻。", "松风涧水杂清音。", "空山如弄琴。", "宜散发，称披襟。", "都无烦暑侵。", "莫将城市比山林。", "山林兴味深。"]'),
('song-ci-907','阮郎归','张抡','宋','宋词','song-ci','阮郎归','[]','豪家大厦敞千楹。',56,'宋词/ci.song.8000.json','["豪家大厦敞千楹。", "风摇玉柄轻。", "金盆弄水复敲冰。", "热从何处生。", "低草舍，小茅亭。", "如何安此身。", "元来一念静无尘。", "萧然心自清。"]'),
('song-ci-908','阮郎归','张抡','宋','宋词','song-ci','阮郎归','[]','金乌玉兔最无情。',56,'宋词/ci.song.8000.json','["金乌玉兔最无情。", "驱驰不暂停。", "春光才去又朱明。", "年华只暗惊。", "须省悟，莫劳神。", "朱颜不再新。", "灭除妄想养天真。", "管无寒暑侵。"]'),
('song-ci-909','阮郎归','张抡','宋','宋词','song-ci','阮郎归','[]','动时思静暑思寒。',56,'宋词/ci.song.8000.json','["动时思静暑思寒。", "尘劳扰扰间。", "翻云复雨百千般。", "几时心地闲。", "□□□，□□难。", "将□□□然。", "自然寒暑不相□。", "□□□地仙。"]'),
('song-ci-910','阮郎归','张抡','宋','宋词','song-ci','阮郎归','[]','谁言无处避炎光。',56,'宋词/ci.song.8000.json','["谁言无处避炎光。", "山中有草堂。", "安然一枕即仙乡。", "竹风穿户凉。", "名不恋，利都忘。", "心闲日自长。", "不须辛苦觅琼浆。", "华池神水香。"]'),
('song-ci-911','阮郎归','张抡','宋','宋词','song-ci','阮郎归','[]','炎炎皦日正当中。',56,'宋词/ci.song.8000.json','["炎炎皦日正当中。", "澄潭忽此逢。", "金丹乍浴表深功。", "通明照水红。", "丹浴罢，乐无穷。", "怡然百体融。", "人间何处不清风。", "此怀谁与同。"]'),
('song-ci-912','阮郎归','张抡','宋','宋词','song-ci','阮郎归','[]','寒来暑往几时休。',56,'宋词/ci.song.8000.json','["寒来暑往几时休。", "光阴逐水流。", "浮云身世两悠悠。", "何劳身外求。", "天上月，水边楼。", "须将一醉酬。", "陶然无喜亦无忧。", "人生且自由。"]'),
('song-ci-913','醉落魄・一斛珠','张抡','宋','宋词','song-ci','醉落魄・一斛珠','[]','流光转毂。',67,'宋词/ci.song.8000.json','["流光转毂。", "乌飞兔走争相逐。", "火云方见奇峰簇。", "飒飒西风，惊堕井梧绿。", "隙驹莫叹年华速。", "新凉且喜消炎酷。", "休将闲事萦心曲。", "红滴真珠，初醡玉醅熟。"]'),
('song-ci-914','醉落魄・一斛珠','张抡','宋','宋词','song-ci','醉落魄・一斛珠','[]','红芳紫陌。',67,'宋词/ci.song.8000.json','["红芳紫陌。", "韶华□□□□□。", "□花弄□□□色。", "不比西风，吹落□□□。", "乾坤造化□□□。", "都缘一气潜相易。", "观时感事成嗟惜。", "惟有乔松，不改旧时碧。"]'),
('song-ci-915','醉落魄・一斛珠','张抡','宋','宋词','song-ci','醉落魄・一斛珠','[]','清秋夜寂。',67,'宋词/ci.song.8000.json','["清秋夜寂。", "圆蟾素影流空碧。", "都无一点浮云隔。", "河汉光微，星斗淡无色。", "日精欲炼须阴魄。", "更深犹望清宵立。", "坎离二物都收得。", "独步瀛洲，方表大丹力。"]'),
('song-ci-916','醉落魄・一斛珠','张抡','宋','宋词','song-ci','醉落魄・一斛珠','[]','秋高气肃。',67,'宋词/ci.song.8000.json','["秋高气肃。", "西风又拂盈盈菊。", "挼金弄玉香芬馥。", "桃李虽繁，其奈太粗俗。", "渊明雅兴谁能续。", "东篱千古遗高躅。", "人生所贵无拘束。", "且采芳英，潋滟泛醽醁。"]'),
('song-ci-917','醉落魄・一斛珠','张抡','宋','宋词','song-ci','醉落魄・一斛珠','[]','流年迅速。',67,'宋词/ci.song.8000.json','["流年迅速。", "君看败叶初辞木。", "若非寿有金丹续。", "石火光中，难保鬓长绿。", "区区何用争荣辱。", "百年一梦黄梁熟。", "人生要足何时足。", "赢取清闲，即是世间福。"]'),
('song-ci-918','醉落魄・一斛珠','张抡','宋','宋词','song-ci','醉落魄・一斛珠','[]','秋光莹彻。',67,'宋词/ci.song.8000.json','["秋光莹彻。", "园林□□□□□。", "如何宋玉□□切。", "作赋悲凉，草木□□□。", "□人自与□□□。", "长歌清啸无时节。", "瓮头且饮□如雪。", "不管春花，亦不管秋月。"]'),
('song-ci-919','醉落魄・一斛珠','张抡','宋','宋词','song-ci','醉落魄・一斛珠','[]','虚窗透月。',67,'宋词/ci.song.8000.json','["虚窗透月。", "寒莎败壁蛩吟切。", "沈沈永漏灯明灭。", "只为愁人，不为道人设。", "愁人对此成愁绝。", "道人终是心如铁。", "一般景趣情怀别。", "笛里西风，吹下满庭叶。"]'),
('song-ci-920','醉落魄・一斛珠','张抡','宋','宋词','song-ci','醉落魄・一斛珠','[]','光辉皎洁。',67,'宋词/ci.song.8000.json','["光辉皎洁。", "古今但赏中秋月。", "寻思岂是月华别。", "都为人间，天上气清彻。", "广寒想望峨琼阙。", "琤琤玉杵声奇绝。", "何时赐我长生诀。", "飞入蟾宫，折桂饵丹雪。"]'),
('song-ci-921','醉落魄・一斛珠','张抡','宋','宋词','song-ci','醉落魄・一斛珠','[]','湖光湛碧。',67,'宋词/ci.song.8000.json','["湖光湛碧。", "亭亭照水芙蕖拆。", "绿罗盖底争红白。", "恍若凌波，仙子步罗袜。", "如今霜落枯荷折。", "清香无处重寻觅。", "浮生似此初无别。", "及取康强，一笑对风月。"]'),
('song-ci-922','醉落魄・一斛珠','张抡','宋','宋词','song-ci','醉落魄・一斛珠','[]','秋宵露结。',67,'宋词/ci.song.8000.json','["秋宵露结。", "清晨□□□□□。", "□□润□□□冽。", "名体才分，功用□□□。", "□儿本是□□□。", "养成方见仙凡隔。", "神仙不肯分明说。", "多少迷人，海上访丹诀。"]'),
('song-ci-923','西江月','张抡','宋','宋词','song-ci','西江月','[]','有限光阴过隙，无情日月飞梭。',58,'宋词/ci.song.8000.json','["有限光阴过隙，无情日月飞梭。", "春花秋月暗消磨。", "一岁相看又过。", "逢酒须成痛饮，临风莫厌高歌。", "虚名微利两如何。", "识破方知恁麽。"]'),
('song-ci-924','西江月','张抡','宋','宋词','song-ci','西江月','[]','雪似琼花铺地，月如宝鉴当空。',58,'宋词/ci.song.8000.json','["雪似琼花铺地，月如宝鉴当空。", "光辉上下两相通。", "千古谁窥妙用。", "若悟珠生蚌腹，方知非异非同。", "阴阳相感有无中。", "恍惚已萌真种。"]'),
('song-ci-925','西江月','张抡','宋','宋词','song-ci','西江月','[]','卷地朔风凛凛，漫天瑞雪霏霏。',58,'宋词/ci.song.8000.json','["卷地朔风凛凛，漫天瑞雪霏霏。", "园林万木变枯枝。", "因甚松篁独翠。", "只为春花竞发，却教秋叶争飞。", "若无荣盛便无衰。", "悟此方名达理。"]'),
('song-ci-926','西江月','张抡','宋','宋词','song-ci','西江月','[]','密布同云万里，六飞玉糁琼铺。',58,'宋词/ci.song.8000.json','["密布同云万里，六飞玉糁琼铺。", "清歌妙舞拥红炉。", "犹恨寒侵尊俎。", "谁念山林路险，独行跣足樵夫。", "莫惊苦乐□殊途。", "阳□皆由阴注。"]'),
('song-ci-927','西江月','张抡','宋','宋词','song-ci','西江月','[]','雅士常多雅□，□□□□□怀。',58,'宋词/ci.song.8000.json','["雅士常多雅□，□□□□□怀。", "雪溪□□□舟来。", "兴尽何须见戴。", "恰似□云出岫，岂拘宇内形骸。", "超然物外远尘埃。", "到此方为自在。"]'),
('song-ci-928','西江月','张抡','宋','宋词','song-ci','西江月','[]','冬至一阳初动，鼎炉光满帘帏。',58,'宋词/ci.song.8000.json','["冬至一阳初动，鼎炉光满帘帏。", "五行造化太幽微。", "颠倒难穷妙理。", "遇此急须进火，速修犹恐迟迟。", "茫茫何处问天机。", "要悟须凭师指。"]'),
('song-ci-929','西江月','张抡','宋','宋词','song-ci','西江月','[]','一梦浮生未觉，三冬短晷堪惊。',58,'宋词/ci.song.8000.json','["一梦浮生未觉，三冬短晷堪惊。", "天高谁解挽长绳。", "系住流年光景。", "须信阴阳有定，非关岁月无情。", "若教心地湛然清。", "日在壶中自永。"]'),
('song-ci-930','西江月','张抡','宋','宋词','song-ci','西江月','[]','四序常如转毂，百年须待春风。',58,'宋词/ci.song.8000.json','["四序常如转毂，百年须待春风。", "江梅何事向严冬。", "早有清香浮动。", "只为六阴极处，一阳已肇黄宫。", "阴阳迭用事何穷。", "此是乾坤妙用。"]'),
('song-ci-931','西江月','张抡','宋','宋词','song-ci','西江月','[]','独坐闲观瑞雪，方知造化无偏。',58,'宋词/ci.song.8000.json','["独坐闲观瑞雪，方知造化无偏。", "不论林木与山川。", "白玉一时装遍。", "梁苑休寻赋客，山阴莫上溪船。", "三杯醉□意陶然。", "梦后瑶台阆苑。"]'),
('song-ci-932','西江月','张抡','宋','宋词','song-ci','西江月','[]','仙道於人不□，□□□□□□。',58,'宋词/ci.song.8000.json','["仙道於人不□，□□□□□□。", "坎离□□□无穷。", "不信浮生若梦。", "君看□□窨雪，寻常见睍消熔。", "能令新旧再相逢。", "此是如何作用。"]'),
('song-ci-933','踏莎行','张抡','宋','宋词','song-ci','踏莎行','[]','朝锁烟霏，暮凝空翠。',68,'宋词/ci.song.8000.json','["朝锁烟霏，暮凝空翠。", "千峰迥立层霄外。", "阴睛变化百千般，丹青难写天然态。", "人住山中，年华频改。", "山花落尽山长在。", "浮生一梦几多时，有谁得似青山耐。"]'),
('song-ci-934','踏莎行','张抡','宋','宋词','song-ci','踏莎行','[]','一道飞泉，来从何许。',68,'宋词/ci.song.8000.json','["一道飞泉，来从何许。", "空山积翠无人处。", "潺湲时和七弦琴，溟濛忽散千岩雨。", "不问春秋，何拘今古。", "清音一听忘千虑。", "缨尘濯尽百神间，飘然襟袖思轻举。"]'),
('song-ci-935','踏莎行','张抡','宋','宋词','song-ci','踏莎行','[]','一片闲云，山头初起。',68,'宋词/ci.song.8000.json','["一片闲云，山头初起。", "飘然直上虚空里。", "残虹收雨耸奇峰，春晴鹤舞丹霄外。", "出岫无心，为霖何意。", "都缘行止难拘系。", "幽人心已与云闲，逍遥自在谁能累。"]'),
('song-ci-936','踏莎行','张抡','宋','宋词','song-ci','踏莎行','[]','人远山深，草□□□。',68,'宋词/ci.song.8000.json','["人远山深，草□□□。", "□□□□天真性。", "□□□长在山中，肯□□□□□□。", "□似幽□，□□心尽。", "超然心□□□隐。", "□□□水作生涯，百年甘守空山静。"]'),
('song-ci-937','踏莎行','张抡','宋','宋词','song-ci','踏莎行','[]','堪笑山中，春来风景。',68,'宋词/ci.song.8000.json','["堪笑山中，春来风景。", "一声啼鸟烟林静。", "山泉风暖奏笙簧。", "山花雨过开云锦。", "短棹桃溪，瘦藤兰径。", "独来独往乘幽兴。", "韶光回首即成空，及时乐取逍遥性。"]'),
('song-ci-938','踏莎行','张抡','宋','宋词','song-ci','踏莎行','[]','人问山中，因何无暑。',68,'宋词/ci.song.8000.json','["人问山中，因何无暑。", "山堂恰在山深处。", "藤阴满地走龙蛇，泉声万壑鸣风雨。", "且弄青松，休挥白羽。", "相逢况有烟霞侣。", "长天一任火云飞，夜凉踏月相将去。"]'),
('song-ci-939','踏莎行','张抡','宋','宋词','song-ci','踏莎行','[]','秋入云山，物情潇洒。',68,'宋词/ci.song.8000.json','["秋入云山，物情潇洒。", "百般景物堪图画。", "丹枫万叶碧云边，黄花千点幽岩下。", "已喜佳辰，更怜清夜。", "一轮明月林梢挂。", "松醪常与野人期，忘形共说清闲话。"]'),
('song-ci-940','踏莎行','张抡','宋','宋词','song-ci','踏莎行','[]','雪拥群峰，静□□□。',68,'宋词/ci.song.8000.json','["雪拥群峰，静□□□。", "□□□□□居□。", "□□破壳栗黄香，柴□□□□□□。", "□□□□，□和衣倒。", "寂寥气□□君好。", "□□□贵足人争，山中恬淡能长保。"]'),
('song-ci-941','踏莎行','张抡','宋','宋词','song-ci','踏莎行','[]','割断凡缘，心安神定。',68,'宋词/ci.song.8000.json','["割断凡缘，心安神定。", "山中采药修身命。", "青松林下茯苓多，白云深处黄精盛。", "百味甘香，一身清净。", "吾生可保长无病。", "八珍五鼎不须贪，荤膻浊乱人情性。"]'),
('song-ci-942','踏莎行','张抡','宋','宋词','song-ci','踏莎行','[]','身世浮沤，利名缰锁。',68,'宋词/ci.song.8000.json','["身世浮沤，利名缰锁。", "省来万事都齐可。", "寻花时傍碧溪行，看云独倚青松坐。", "云片飞飞，花枝朵朵。", "光阴且向闲中过。", "世间萧散更何人，除非明月清风我。"]'),
('song-ci-943','朝中措','张抡','宋','宋词','song-ci','朝中措','[]','吴松江影漾清辉。',57,'宋词/ci.song.8000.json','["吴松江影漾清辉。", "山远翠光微。", "杨柳风轻日永，桃花浪暖鱼肥。", "东来西往。", "随情任性，本自无机。", "何事沙边鸥鹭，一声欸乃惊飞。"]'),
('song-ci-944','朝中措','张抡','宋','宋词','song-ci','朝中措','[]','湖光染翠□□□。',57,'宋词/ci.song.8000.json','["湖光染翠□□□。", "□□□□□。", "□爱江湖光景，不曾别做□□。", "□□□□，□□□□，□□侬家。", "醉卧水云□□，□□□□□□。"]'),
('song-ci-945','朝中措','张抡','宋','宋词','song-ci','朝中措','[]','碧波深处锦鳞游。',57,'宋词/ci.song.8000.json','["碧波深处锦鳞游。", "波面小渔舟。", "不为来贪香饵，如何赚得吞钩。", "缘蓑青箬，吾生自断，终老汀洲。", "买断一江风月，胜如千户封侯。"]'),
('song-ci-946','朝中措','张抡','宋','宋词','song-ci','朝中措','["\u6d1e\u5ead\u6e56"]','沙明波净小汀洲。',57,'宋词/ci.song.8000.json','["沙明波净小汀洲。", "枫落洞庭秋。", "红蓼白苹深处，晚风吹转船头。", "鲈鱼钓得，银丝旋鲙，白酒新篘。", "一笑月寒烟暝，人间万事都休。"]'),
('song-ci-947','朝中措','张抡','宋','宋词','song-ci','朝中措','[]','松江西畔水连空。',57,'宋词/ci.song.8000.json','["松江西畔水连空。", "霜叶舞丹枫。", "谩道金章清贵，何如蓑笠从容。", "有时独醉，无人系缆，一任斜风。", "不是芦花惹住，几回吹过桥东。"]'),
('song-ci-948','朝中措','张抡','宋','宋词','song-ci','朝中措','[]','鸣榔惊起鹭鸶飞。',57,'宋词/ci.song.8000.json','["鸣榔惊起鹭鸶飞。", "山远水弥弥。", "米贱茅柴酒美，霜清螃蟹螯肥。", "人生所贵，逍遥快意，此外皆非。", "却笑东山太傅，几曾梦见蓑衣。"]'),
('song-ci-949','朝中措','张抡','宋','宋词','song-ci','朝中措','[]','午阴多处□□□。',57,'宋词/ci.song.8000.json','["午阴多处□□□。", "杨柳□□□。", "翠羽无情飞去，红蕖有意□□。", "□□□□，□□□□，□□吾生。", "为报凌烟□□，□□□□□名。"]'),
('song-ci-950','朝中措','张抡','宋','宋词','song-ci','朝中措','[]','红尘光景事如何。',57,'宋词/ci.song.8000.json','["红尘光景事如何。", "扰扰利名多。", "若问侬家活计，扁舟小笠轻蓑。", "一尊美酒，一轮皓月，一弄山歌。", "选甚掀天白浪，未如人世风波。"]'),
('song-ci-951','朝中措','张抡','宋','宋词','song-ci','朝中措','[]','萧萧芦叶暮寒生。',57,'宋词/ci.song.8000.json','["萧萧芦叶暮寒生。", "雪厌冻云平。", "密洒一篷烟火，惊鸿飞起沙汀。", "收纶罢钓，空江有浪，短棹无声。", "便是天然图画，何须妙手丹青。"]'),
