('song-ci-992','蝶恋花','张抡','宋','宋词','song-ci','蝶恋花','[]','不假□□□□□。',70,'宋词/ci.song.8000.json','["不假□□□□□。", "□□□□，□□□□□。", "□□□□□□□。", "□□□□□□□。", "□□□□□□□。", "□□□□，□□□□□。", "□□□□□□□。", "□□□□□□□。"]'),
('song-ci-993','鹊桥仙','张抡','宋','宋词','song-ci','鹊桥仙','[]','远公连社，流传图画，千古声名独在。',68,'宋词/ci.song.8000.json','["远公连社，流传图画，千古声名独在。", "后人多少继遗踪，到我便、失惊打怪。", "西方未到，官方先到，冤我白衣吃菜。", "龙华三会愿相逢，怎敢学、他家二会。"]'),
('song-ci-994','春光好','张抡','宋','宋词','song-ci','春光好','[]','烟澹澹，雨濛濛。',51,'宋词/ci.song.8000.json','["烟澹澹，雨濛濛。", "水溶溶。", "帖水落花飞不起，小桥东。", "翩翩怨蝶愁蜂。", "绕芳丛。", "恋馀红。", "不恨无情桥下水，恨东风。"]'),
('song-ci-995','壶中天慢・念奴娇','张抡','宋','宋词','song-ci','壶中天慢・念奴娇','[]','洞天深处赏娇红，轻玉高张云幕。',119,'宋词/ci.song.8000.json','["洞天深处赏娇红，轻玉高张云幕。", "国艳天香相竞秀，琼苑风光如昨。", "露洗妖妍，风传馥郁，云雨巫山约。", "春浓如酒，五云台榭楼阁。", "圣代道洽功成，一尘不动，四境无鸣柝。", "屡有丰年天助顺，基业增隆山岳。", "两世明君，千秋万岁，永享升平乐。", "东皇呈瑞，更无一片花落。"]'),
('song-ci-996','水调歌头','侯置','宋','宋词','song-ci','水调歌头','["\u6d1e\u5ead\u6e56"]','晓雾散晴渚，秋色满湘山。',114,'宋词/ci.song.8000.json','["晓雾散晴渚，秋色满湘山。", "青鞋黄帽，忺与名士共跻攀。", "窈窕深林幽谷，诘曲危亭飞观，俯首视尘寰。", "长啸望天末，馀响下云端。", "白鹤去，荒井在，汲清寒。", "醒然毛骨，浮丘招我御风还。", "拂拭苍崖苔鲜，一写胸中豪气，渺渺洞庭宽。", "山鬼善呵护，千载照层峦。"]'),
('song-ci-997','水调歌头','侯置','宋','宋词','song-ci','水调歌头','[]','凉吹送溪雨，落日散汀鸥。',114,'宋词/ci.song.8000.json','["凉吹送溪雨，落日散汀鸥。", "暮天空阔无际，层巘绿蛾浮。", "上印初辞藩寄，拂袖欣还故里，归骑及中秋。", "倚杖饱山阁，回首翠微楼。", "一区宅，千里客，旧从游。", "甘棠空有馀荫，谁解挽公留。", "翰墨文章独步，富贵功名馀事，当代仰风流。", "暂蜡登山屐，终作济川舟。"]'),
('song-ci-998','水调歌头','侯置','宋','宋词','song-ci','水调歌头','[]','湘水照秋碧，衡岳际天高。',114,'宋词/ci.song.8000.json','["湘水照秋碧，衡岳际天高。", "绣衣玉节，清晓欢颂拥旌旄。", "本是紫庭梁栋，暂借云台耳目，驿传小游遨。", "五管与三楚，醲爱胜春醪。", "扫材枪，苏耄倪，载弓櫜。", "远民流恋，须信寰海待甄陶。", "坐享龟龄鹤算，稳佩金鱼玉带，常近赭黄袍。", "岁岁秋月底，沈醉紫檀槽。"]'),
('song-ci-999','水调歌头','侯置','宋','宋词','song-ci','水调歌头','[]','天地孕冲气，霜雪实嘉平。',114,'宋词/ci.song.8000.json','["天地孕冲气，霜雪实嘉平。", "粹然经世材具，应为圣时生。", "妙处为仁受用。", "颠倒纵横无壅。", "一笑泮春冰。", "袖手无一语，四海已倾情。", "紫岩老，游戏事，悟诚明。", "当年夷夏高仰，玉振更金声。", "家有渊骞高第。", "可但闻诗闻礼。", "衣钵要相承。", "周扆绚馀彩，商鼎味新羹。"]'),
('song-ci-0','瑞鹤仙','侯置','宋','宋词','song-ci','瑞鹤仙','[]','楚山无际碧。',127,'宋词/ci.song.9000.json','["楚山无际碧。", "湛一溪晴绿，四郊寒色。", "霜华弄初日。", "看玉明遥草，金铺平碛。", "天涯倦翼。", "更何堪、临岐送客。", "念飞蓬、断梗无踪，把酒后期难觅。", "愁寂。", "梅花憔悴，茅舍萧疏，倍添凄恻。", "维舟岸侧。", "留君饮，醉休惜。", "想柯山春晚，还家应对，菊老松坚旧宅。", "叹宦游、索寞情怀，甚时去得。"]'),
('song-ci-1','瑞鹤仙','侯置','宋','宋词','song-ci','瑞鹤仙','[]','溥天氛祲廓。',126,'宋词/ci.song.9000.json','["溥天氛祲廓。", "看庆绵鸿祚，勋昭麟阁。", "蕃宣换符钥。", "占西南襟带，遍□油幕。", "湘流绕郭。", "蔼一城、和气雾薄。", "听嘈嘈、比屋欢声，共说吏闲民乐。", "遥想芗霏凫暖，翠拥屏深，晓风传乐。", "琼腴缓酌。", "花阴淡，柳丝弱。", "任松凋鹤瘦，莲敧龟老，丹颊常如旧渥。", "趁天申、去押西班，奉觞御幄。"]'),
('song-ci-2','瑞鹤仙','侯置','宋','宋词','song-ci','瑞鹤仙','[]','春风无检束。',127,'宋词/ci.song.9000.json','["春风无检束。", "放倡条冶叶，恣情丹绿。", "□莺喧燕宿。", "似东邻北里，都无贞淑。", "高情恨蹙。", "欢何时、重见桂菊。", "又谁知、天上黄姑，扫尽晚春馀俗。", "幽独。", "铅华不御，翡翠帷深，郁金裙蔌。", "长眉了目。", "嫣然态，倚修竹。", "纵青门瓜美，江陵橘老，怎比无穷剩馥。", "最难禁、扇底横枝，恼人睡足。"]'),
('song-ci-3','满江红','侯置','宋','宋词','song-ci','满江红','[]','天阔江南，秋未老、空江澄碧。',116,'宋词/ci.song.9000.json','["天阔江南，秋未老、空江澄碧。", "江外月、飞来千丈，水天同色。", "万屋覆银清不寐，一城踏雪寒无迹。", "况楚风、连陌竞张灯，如元夕。", "山獠静，棠阴寂。", "秋稼盛，香醪直。", "听子城吹角，青楼横笛。", "君不见、苏仙翻醉墨，一篇水调锵金石。", "念良辰美景赏心时，诚难得。"]'),
('song-ci-4','满江红','侯置','宋','宋词','song-ci','满江红','[]','困顿春眠，无情思、梦魂飘泊。',115,'宋词/ci.song.9000.json','["困顿春眠，无情思、梦魂飘泊。", "檐外雨、霏霏冉冉，乍睛还落。", "山黛四围频入眼，柳丝一缕低萦阁。", "念沈郎、多感更伤春，腰如削。", "风入户，香穿箔。", "花似旧，人非昨。", "任游蜂双燕，经营拂掠。", "海阔锦鱼传不到，洞深紫凤期难约。", "谩彩笺、牙管倚西窗，题红叶。"]'),
('song-ci-5','满江红','侯置','宋','宋词','song-ci','满江红','["\u897f\u6e56"]','重到西湖，春拆信、露花酥滴。',115,'宋词/ci.song.9000.json','["重到西湖，春拆信、露花酥滴。", "倚危栏、湖山佳处，短屏著色。", "拟泛一舟苍莽岸，恐伤万里羁游客。", "赖款门、修竹有高人，留狂迹。", "倾盖意，真相得。", "诗句里，曾相识。", "看戛然飞动，笔端金石。", "照眼光浮琼液满，断肠翠拥宫靴窄。", "问多情、还肯借青鸾，通消息。"]'),
('song-ci-6','满江红','侯置','宋','宋词','song-ci','满江红','[]','老矣何堪，随处是、春衫酒滴。',115,'宋词/ci.song.9000.json','["老矣何堪，随处是、春衫酒滴。", "醉狂时、一挥千字，贝光玉色。", "失意险为湘岸鬼，浩歌又作长安客。", "且乘流、除却五侯门，无车迹。", "惊人句，天外得。", "医国手，尘中识。", "问鼎槐何似，卧云敧石。", "梦里略无轩冕念，眼前岂是江湖窄。", "拚蝇头、蜗角去来休，休姑息。"]'),
('song-ci-7','满江红','侯置','宋','宋词','song-ci','满江红','[]','甚矣吾衰，徒是苦、饥肠为孽。',115,'宋词/ci.song.9000.json','["甚矣吾衰，徒是苦、饥肠为孽。", "嗟寸禄、区区留恋，形疲心竭。", "江海一生真可羡，尘埃永昼何堪说。", "似钝刀、终岁斫空山，宁无缺。", "拚放浪，休豪杰。", "秋水涨，归期决。", "尽凫长鹤短，任渠分别。", "芒屩夜寻溪上酒，葛巾晓挂松间月。", "向丹霄、传语旧交游，慵非拙。"]'),
('song-ci-8','水龙吟','侯置','宋','宋词','song-ci','水龙吟','[]','夜来霜拂帘旌，淡云丽日开清晓。',126,'宋词/ci.song.9000.json','["夜来霜拂帘旌，淡云丽日开清晓。", "香猊金暖，冰壶玉嫩，佳辰寒早。", "橘绿橙黄，袖红裙翠，一堂欢笑。", "正梅妃月姊，雪肌粉面，争妆点、潇湘好。", "莫惜芳尊屡倒。", "拥群仙、醉游蓬岛。", "东床俊选，南溟归信，一时俱到。", "鬓影摇春，命书纡锦，子孙环绕。", "看他时归去，飞觞石涧，侍甘泉老。"]'),
('song-ci-9','多丽','侯置','宋','宋词','song-ci','多丽','[]','帝城春，玉堂深处飞烟。',173,'宋词/ci.song.9000.json','["帝城春，玉堂深处飞烟。", "想圣人、恩隆内职，左珰押赐传宣。", "彩衣明、瑶觞膝下，花昼永、锦瑟尊前。", "富贵从来，功名馀事，鼎彝勒遍笔如椽。", "向中禁、琐窗偷觑，王母语当年。", "清平世，衣冠是谁，三世甘泉。", "记年时、翘才献寿，小诗曾涴苔笺。", "望三槐、云霞交映，照五彩、衮绣相鲜。", "当日非谀，如今方信，门人称颂是师言。", "况自有、两宫醲眷，卜梦亦徒然。", "看指日，鼎新化炉，一气陶甄。"]'),
('song-ci-10','念奴娇','侯置','宋','宋词','song-ci','念奴娇','[]','沧浪万顷，厌尘缨、手掬清流频洗。',120,'宋词/ci.song.9000.json','["沧浪万顷，厌尘缨、手掬清流频洗。", "落日孤云烟渚净，鸥没澄波心里。", "一舸横秋，两桡开浪，霜竹醒烦耳。", "萧萧风露，梦回月照船尾。", "须信闲少忙多，壶觞并赋咏，莫辜云水。", "乘兴前溪溪转□，隐约归帆天际。", "红蓼丹枫，黄芦白竹，总胜春桃李。", "浮丘何在，与君共跨琴鲤。"]'),
('song-ci-11','念奴娇','侯置','宋','宋词','song-ci','念奴娇','[]','竞春台榭，媚东风、迤逦繁红成簇。',120,'宋词/ci.song.9000.json','["竞春台榭，媚东风、迤逦繁红成簇。", "方霁溪南帘绣卷，和气充盈华屋。", "金暖香彝，玉鸣舞佩，春笋调丝竹。", "乌衣宴会，远追王谢高躅。", "籍甚四海声名，林泉活计，未许翁知足。", "日日江边沙露静，人徯东来雕毂。", "八锦行持，五禽游戏，已受长生箓。", "衮衣蝉冕，最宜双鬓凝绿。"]'),
('song-ci-12','念奴娇','侯置','宋','宋词','song-ci','念奴娇','[]','衰翁憨甚，向尊前、手拈一枝寒玉。',120,'宋词/ci.song.9000.json','["衰翁憨甚，向尊前、手拈一枝寒玉。", "想见梅台花更好，一片琼田栖绿。", "短辔轻舆，大家同去，取酒偿醲馥。", "元来春晚，万包空间黄竹。", "休恨雪小云娇，出群风韵，已觉桃花俗。", "羯鼓声高回笑脸，怎得天公来促。", "江上风平，岭南人远，谁度单于曲。", "明朝酒醒，但馀诗兴天北。"]'),
('song-ci-13','风入松','侯置','宋','宋词','song-ci','风入松','["\u897f\u6e56"]','少年心醉杜韦娘。',90,'宋词/ci.song.9000.json','["少年心醉杜韦娘。", "曾格外疏狂。", "锦笺预约西湖上，共幽深、竹院松窗。", "愁夜黛眉颦翠，惜归罗帕分香。", "重来一梦觉黄梁。", "空烟水微茫。", "如今眼底无姚魏，记旧游、凝伫凄凉。", "入扇柳风残酒，点衣花雨斜阳。"]'),
('song-ci-14','风入松','侯置','宋','宋词','song-ci','风入松','[]','东楼烟重暗山光。',90,'宋词/ci.song.9000.json','["东楼烟重暗山光。", "春意堕微茫。", "小红嫩绿匀如剪，黯无言、云渡澄江。", "没处与人消遣，倚阑情寄斜阳。", "共君今夜举清觞。", "投老各殊方。", "痴儿官事何时了，恨花时、潘鬓先霜。", "唤取客帆聊住，将予同下潇湘。"]'),
('song-ci-15','风入松','侯置','宋','宋词','song-ci','风入松','[]','霏霏小雨恼春光。',90,'宋词/ci.song.9000.json','["霏霏小雨恼春光。", "烟水更弥茫。", "昨宵把酒高歌处，任一声、鸡唱清江。", "憔悴杏花如许，情怀应似东阳。", "宿酲犹在莫传觞。", "消闷苦无方。", "几时玉杵蓝桥路，约云英、同捣玄霜。", "冷落黄昏庭院，梦回家在三湘。"]'),
('song-ci-16','遥天奉翠华引','侯置','宋','宋词','song-ci','遥天奉翠华引','[]','雪消楼外山。',109,'宋词/ci.song.9000.json','["雪消楼外山。", "正秦淮、翠溢回澜。", "香梢豆蔻，红轻犹怕春寒。", "晓光浮画戟，卷绣帘、风暖玉钩间。", "紫府仙人，花园羽帔星冠。", "蓬莱阆苑，意倦游、常戏世间。", "佩麟旧都，江左襦裤歌欢。", "只恐催归觐，剩宴都、休诉酒杯宽。", "明岁应看，钧容舞袖歌鬟。"]'),
('song-ci-17','蓦山溪','侯置','宋','宋词','song-ci','蓦山溪','[]','玉麟春晚，绿遍甘棠荫。',102,'宋词/ci.song.9000.json','["玉麟春晚，绿遍甘棠荫。", "可是惜花深，旋移得、翻阶红影。", "朱帘卷处，如在古扬州，宝璎珞，玉盘盂，娇艳交相映。", "蓬莱殿里，几样春风鬓。", "生怕逐朝云，更罗幕、重重遮定。", "多情绛蜡，常见醉时容，萦舞袖，蔌歌尘，莫负良宵永。"]'),
('song-ci-18','凤皇台上忆吹箫・凤凰台上忆吹箫','侯置','宋','宋词','song-ci','凤皇台上忆吹箫・凤凰台上忆吹箫','[]','玉管灰飞，云台珥笔，东君飚驭将还。',119,'宋词/ci.song.9000.json','["玉管灰飞，云台珥笔，东君飚驭将还。", "又正是、霜花□剪，梅粉初乾。", "窈窕红窗髻影，添一线、组绣工间。", "潇湘好，雪意尚遥，绿占群山。", "应思少年壮气，贪游乐、追随玉勒雕鞍。", "更化日舒长，赢得觅醉谋欢。", "老去桑榆趁暖，任从教、潘鬓先斑。", "犹狂在，挥翰快写春寒。"]'),
('song-ci-19','凤皇台上忆吹箫・凤凰台上忆吹箫','侯置','宋','宋词','song-ci','凤皇台上忆吹箫・凤凰台上忆吹箫','[]','尘暗双凫，菊明山径，何妨倦羽知还。',120,'宋词/ci.song.9000.json','["尘暗双凫，菊明山径，何妨倦羽知还。", "最好是，诗翁醉后，瓶罄罍乾。", "一笑东风打耳，心无竞、远与春间。", "时时地，觅伴访梅，寻胜登山。", "清时俊材定用，看捧诏春郊，月露濡鞍。", "况表识、买臣贵骨，琴瑟逾欢。", "好向玉堂视草，金章映、莱子衣斑。", "山人去，蕙帐夜雨空寒。"]'),
('song-ci-20','凤皇台上忆吹箫・凤凰台上忆吹箫','侯置','宋','宋词','song-ci','凤皇台上忆吹箫・凤凰台上忆吹箫','[]','浴雪精神，倚风情态，百端邀勒春还。',120,'宋词/ci.song.9000.json','["浴雪精神，倚风情态，百端邀勒春还。", "记旧隐、溪桥日暮，驿路泥乾。", "曾伴先生蕙帐，香细细、粉瘦琼间。", "伤牢落，一夜梦回，肠断家山。", "空教映溪带月，供游客无情，折满雕鞍。", "便忘了、明窗静几，笔研同欢。", "莫向高楼喷笛，花似我、蓬鬓霜斑。", "都休说，今夜倍觉清寒。"]'),
('song-ci-21','凤皇台上忆吹箫・凤凰台上忆吹箫','侯置','宋','宋词','song-ci','凤皇台上忆吹箫・凤凰台上忆吹箫','[]','浅染霓裳，轻匀汉额，巫山行雨方还。',120,'宋词/ci.song.9000.json','["浅染霓裳，轻匀汉额，巫山行雨方还。", "最好是、肌香蜡莹，萼嫩红乾。", "曾见金钟在列，钧天罢、笋簴都间。", "妖饶似，晓镜乍开，绿沁眉山。", "休夸瘦枝疏影，湘裙窄、一钩龙麝随鞍。", "便更做、山人倦赏，畏冷无欢。", "争奈冰瓯彩笔，题诗处、珠琲斓斑。", "清宵永，相对莫放杯寒。"]'),
('song-ci-22','蝶恋花','侯置','宋','宋词','song-ci','蝶恋花','[]','雪压小桥溪路断。',70,'宋词/ci.song.9000.json','["雪压小桥溪路断。", "独立无言，雾鬓风鬟乱。", "拂拭冰霜君试看。", "一枝堪寄天涯远。", "拟向南邻寻酒伴。", "折得花归，醉著歌声缓。", "姑射梦回星斗转。", "依然月下重相见。"]'),
('song-ci-23','清平乐','侯置','宋','宋词','song-ci','清平乐','[]','缕金剪彩。',54,'宋词/ci.song.9000.json','["缕金剪彩。", "茸绾同心带。", "整整云鬟宜簇戴。", "雪柳闹蛾难赛。", "休夸结实炎州。", "且看指面纤柔。", "试问苦人滋味，何如插鬓风流。"]'),
('song-ci-24','清平乐','侯置','宋','宋词','song-ci','清平乐','[]','忍寒情味。',54,'宋词/ci.song.9000.json','["忍寒情味。", "枝染蔷薇水。", "搅照清溪花影碎。", "笑杀小桃秾李。", "一生占断春妍。", "偏宜月露娟娟。", "欲寄江南春去，乱鸦点破云笺。"]'),
('song-ci-25','玉楼春','侯置','宋','宋词','song-ci','玉楼春','[]','市桥灯火春星碎。',64,'宋词/ci.song.9000.json','["市桥灯火春星碎。", "街鼓催归人未醉。", "半嗔还笑眼回波，欲去更留眉敛翠。", "归来短烛馀红泪。", "月淡天高梅影细。", "北风休遣雁南来，断送不成今夜睡。"]'),
('song-ci-26','玉楼春','侯置','宋','宋词','song-ci','玉楼春','[]','今秋中月逢馀闰。',64,'宋词/ci.song.9000.json','["今秋中月逢馀闰。", "月姊重来风露静。", "未劳玉斧整蟾宫，又见冰轮浮桂影。", "寻常经岁睽佳景。", "阅月那知还赏咏。", "庾楼江阔碧天高，遥想飞觞清夜永。"]'),
('song-ci-27','秦楼月・忆秦娥','侯置','宋','宋词','song-ci','秦楼月・忆秦娥','[]','天一色。',56,'宋词/ci.song.9000.json','["天一色。", "玉盘冷浸潇湘碧。", "潇湘碧。", "短亭系缆，隔江闻笛。", "胡床对坐凉生腋。", "通宵说尽狂踪迹。", "狂踪迹。", "少年心事，老来难得。"]'),
('song-ci-28','新荷叶','侯置','宋','宋词','song-ci','新荷叶','[]','柳幄飞绵，风池暖泛新萍。',100,'宋词/ci.song.9000.json','["柳幄飞绵，风池暖泛新萍。", "燕垒泥香，玉麟堂外春深。", "晴云丽日，花浓处、蜂蝶纷纷。", "偿春一醉，管弦声里欢声。", "况是清时，锦衣重到台城。", "故国江山，向人依旧多情。", "趁闲行乐，休辜负、冶叶繁英。", "彤庭归觐，恁时难驻前旌。"]'),
('song-ci-29','菩萨蛮','侯置','宋','宋词','song-ci','菩萨蛮','[]','楼前曲浪归桡急。',52,'宋词/ci.song.9000.json','["楼前曲浪归桡急。", "楼中细雨春风湿。", "终日倚危阑。", "故人湖上山。", "高情浑似旧。", "只枉东阳瘦。", "薄晚去来休。", "装成一段愁。"]'),
('song-ci-30','菩萨蛮','侯置','宋','宋词','song-ci','菩萨蛮','[]','东风吹梦春酲恶。',52,'宋词/ci.song.9000.json','["东风吹梦春酲恶。", "琐窗淡淡花阴薄。", "一夜曲池平。", "小窗云样明。", "绿轻眉懒晕。", "香浅罗衣润。", "未见海棠开。", "卷帘双燕来。"]'),
('song-ci-31','菩萨蛮','侯置','宋','宋词','song-ci','菩萨蛮','[]','江风漠漠寒山碧。',52,'宋词/ci.song.9000.json','["江风漠漠寒山碧。", "孤鸿声里霜花白。", "画舸且停桡。", "有人魂欲销。", "相从能几日。", "总是天涯客。", "尺素好频裁。", "休言无雁来。"]'),
('song-ci-32','菩萨蛮','侯置','宋','宋词','song-ci','菩萨蛮','[]','东君管尽闲花草。',52,'宋词/ci.song.9000.json','["东君管尽闲花草。", "红红白白知多少。", "末后一奁香。", "绿庭春昼长。", "道人心似海。", "梦冷屏山里。", "莫剪最长条。", "从教玉步摇。"]'),
('song-ci-33','菩萨蛮','侯置','宋','宋词','song-ci','菩萨蛮','[]','东风卷尽欺花雨。',52,'宋词/ci.song.9000.json','["东风卷尽欺花雨。", "月明皎纸庭前路。", "月底且论诗。", "从教露湿衣。", "明朝愁入绪。", "各自东归去。", "后夜月明中。", "绿尊谁与同。"]'),
('song-ci-34','菩萨蛮','侯置','宋','宋词','song-ci','菩萨蛮','[]','绿帷剪剪黄金碎。',52,'宋词/ci.song.9000.json','["绿帷剪剪黄金碎。", "西风庭院清如水。", "月姊更多情。", "与人无际明。", "浓阴遮玉砌。", "桂影冰壶里。", "灭烛且徜徉。", "夜深应更香。"]'),
('song-ci-35','菩萨蛮','侯置','宋','宋词','song-ci','菩萨蛮','[]','靓妆金翠盈盈晚。',52,'宋词/ci.song.9000.json','["靓妆金翠盈盈晚。", "凝情有恨无人管。", "何处一帘风。", "故人天际逢。", "从教香扑鬓。", "只怕繁华尽。", "牢落正悲秋。", "非□谁解愁。"]'),
('song-ci-36','菩萨蛮','侯置','宋','宋词','song-ci','菩萨蛮','[]','江梅占尽江头雪。',52,'宋词/ci.song.9000.json','["江梅占尽江头雪。", "忍寒玉骨夸清绝。", "不似杜秋娘。", "婆娑秋水傍。", "波光涵晚日。", "照影从教密。", "隐隐认遥黄。", "隔溪十里香。"]'),
('song-ci-37','菩萨蛮','侯置','宋','宋词','song-ci','菩萨蛮','[]','黄昏曾见凌波步。',52,'宋词/ci.song.9000.json','["黄昏曾见凌波步。", "无端暝色催人去。", "一夜露华浓。", "香销兰菊丛。", "缕金衣易湿。", "莫对西风泣。", "洗尽夜来妆。", "温泉初赐汤。"]'),
('song-ci-38','菩萨蛮','侯置','宋','宋词','song-ci','菩萨蛮','[]','休文多病疏杯酌。',52,'宋词/ci.song.9000.json','["休文多病疏杯酌。", "被花恼得心情恶。", "碧树又惊秋。", "追欢怀旧游。", "与君聊一醉。", "醉倒花阴里。", "斜日下阑干。", "满身金屑寒。"]'),
('song-ci-39','菩萨蛮','侯置','宋','宋词','song-ci','菩萨蛮','[]','交刀剪碎琉璃碧。',52,'宋词/ci.song.9000.json','["交刀剪碎琉璃碧。", "深黄一穗珑松色。", "玉蕊纵妖娆。", "恐无能样娇。", "绿窗初睡起。", "堕马慵梳髻。", "斜插紫鸾钗。", "香从鬓底来。"]'),
('song-ci-40','菩萨蛮','侯置','宋','宋词','song-ci','菩萨蛮','[]','黄姑青女交相忌。',52,'宋词/ci.song.9000.json','["黄姑青女交相忌。", "眼看尘土占芳蕊。", "急埽满阑金。", "小奁熏水沈。", "博山银叶透。", "浓馥穿罗袖。", "犹欲问鸿都。", "太真安稳无。"]'),
('song-ci-41','菩萨蛮','侯置','宋','宋词','song-ci','菩萨蛮','[]','午庭栩栩花间蝶。',52,'宋词/ci.song.9000.json','["午庭栩栩花间蝶。", "翅添金粉穿琼叶。", "曾见羽衣黄。", "瑶台淡薄妆。", "醒来魂欲断。", "掺掺芳英满。", "梦里尚偷香。", "何堪秋夜长。"]'),
('song-ci-42','菩萨蛮','侯置','宋','宋词','song-ci','菩萨蛮','[]','霓裳舞罢难留住。',52,'宋词/ci.song.9000.json','["霓裳舞罢难留住。", "湘裙缓若轻烟去。", "动是隔年期。", "生绡傅艳姿。", "精神浑似旧。", "碧暗黄金瘦。", "永夜对西窗。", "何缘襟袖香。"]'),
('song-ci-43','菩萨蛮','侯置','宋','宋词','song-ci','菩萨蛮','[]','揉香嗅蕊朝还暮。',52,'宋词/ci.song.9000.json','["揉香嗅蕊朝还暮。", "无端却被西风误。", "底死欲留伊。", "金尘蔌蔌飞。", "茂陵头已白。", "新聘谁相得。", "耐久莫相思。", "年年秋与期。"]'),
('song-ci-44','西江月','侯置','宋','宋词','song-ci','西江月','[]','金鼎香销沈麝，碧梧影转阑干。',58,'宋词/ci.song.9000.json','["金鼎香销沈麝，碧梧影转阑干。", "可庭明月绮窗闲。", "帘幕低垂不卷。", "一自高唐人去，秋风几许摧残。", "拂檐修竹韵珊珊。", "梦断山长水远。"]'),
('song-ci-45','西江月','侯置','宋','宋词','song-ci','西江月','[]','豆蔻梢头年纪，芙蓉水上精神。',58,'宋词/ci.song.9000.json','["豆蔻梢头年纪，芙蓉水上精神。", "幼云娇玉两眉春。", "京洛当时风韵。", "金缕深深劝客，雕梁蔌蔌飞尘。", "主人从得董双成。", "应忘瑶池宴饮。"]'),
('song-ci-46','青玉案','侯置','宋','宋词','song-ci','青玉案','[]','东风一夜吹晴雨。',80,'宋词/ci.song.9000.json','["东风一夜吹晴雨。", "小园里、春如许。", "桃李无言情难诉。", "阳关车马，灞桥风月，移入江天暮。", "双旌明日留难住。", "今夕清觞且频举。", "咫尺清明三月暮。", "寻芳宾客，对花杯酌，回首西江路。"]'),
('song-ci-47','青玉案','侯置','宋','宋词','song-ci','青玉案','[]','年年寓屋称觞处。',80,'宋词/ci.song.9000.json','["年年寓屋称觞处。", "陪彩绶、尊前舞。", "牢落潇湘归去未。", "蜡梅开遍，冰蟾圆后，梦断灵溪路。", "长年厚福天分付。", "算四海、今独步。", "涧竹岩花如旧否。", "与翁相伴，岁寒庭户，尽占闲中趣。"]'),
('song-ci-48','青玉案','侯置','宋','宋词','song-ci','青玉案','[]','三年牢落荒江路。',80,'宋词/ci.song.9000.json','["三年牢落荒江路。", "忍明日、轻帆去。", "冉冉年光真暗度。", "江山无助，风波有险，不是留君处。", "梅花万里伤迟暮。", "驿使来时望佳句。", "我拚归休心已许。", "短篷孤棹，绿蓑青笠，稳泛潇湘雨。"]'),
('song-ci-49','昭君怨','侯置','宋','宋词','song-ci','昭君怨','[]','晴日烘香花睡。',48,'宋词/ci.song.9000.json','["晴日烘香花睡。", "花艳浮杯人醉。", "杨柳绿丝风。", "水溶溶。", "留恋芳丛深处。", "懒上锦鞯归去。", "待得牡丹开。", "更同来。"]'),
('song-ci-50','四犯令','侯置','宋','宋词','song-ci','四犯令','[]','月破轻云淡注。',59,'宋词/ci.song.9000.json','["月破轻云淡注。", "夜悄花无语。", "莫听阳关牵离绪。", "拚酩酊、花深处。", "明日江郊芳草路。", "春逐行人去。", "不似酴醿开独步。", "能著意、留春住。"]'),
('song-ci-51','鹧鸪天','侯置','宋','宋词','song-ci','鹧鸪天','[]','万点胭脂落日烘。',64,'宋词/ci.song.9000.json','["万点胭脂落日烘。", "坐间酒面散微红。", "谁教艳质撩潘鬓，生怕朝云逐楚风。", "寻画烛，照芳容。", "夜深两行锦灯笼。", "朱唇翠袖休凝伫，几许春情睡思中。"]'),
('song-ci-52','鹧鸪天','侯置','宋','宋词','song-ci','鹧鸪天','[]','蜀锦吴绫剪染成。',64,'宋词/ci.song.9000.json','["蜀锦吴绫剪染成。", "东皇花令一番新。", "风帘不碍寻巢燕，雨叶偏禁斗草人。", "非病酒，不关春。", "恨如芳草思连云。", "西楼角畔双桃树，几许浓苞等露匀。"]'),
('song-ci-53','鹧鸪天','侯置','宋','宋词','song-ci','鹧鸪天','[]','梦想当年姚魏家。',64,'宋词/ci.song.9000.json','["梦想当年姚魏家。", "尊前重见旧时花。", "双檠分焰交红影，四座春回粲晚霞。", "杯潋滟，帽敧斜。", "夜深绝艳愈清佳。", "天明恐逐行云去，更著重重翠幕遮。"]'),
('song-ci-54','鹧鸪天','侯置','宋','宋词','song-ci','鹧鸪天','["\u897f\u6e56"]','只有梅花是故人。',64,'宋词/ci.song.9000.json','["只有梅花是故人。", "岁寒情分更相亲。", "红鸾跨碧江头路，紫府分香月下身。", "君既去，我离群。", "天涯白发怕逢春。", "西湖苍莽烟波里，来岁梅时痛忆君。"]'),
('song-ci-55','朝中措','侯置','宋','宋词','song-ci','朝中措','[]','翻阶红药竞芬芳。',57,'宋词/ci.song.9000.json','["翻阶红药竞芬芳。", "著意巧成双。", "须信扬州国艳，旧时曾在昭阳。", "盈盈背立，同心对绾，联萼飞香。", "牢贮深沈金屋，任教蝶困蜂忙。"]'),
('song-ci-56','朝中措','侯置','宋','宋词','song-ci','朝中措','[]','漏云初见六花开。',57,'宋词/ci.song.9000.json','["漏云初见六花开。", "惊巧妒江梅。", "飘洒元戎小队，玉妆旌旆归来。", "恩同化手，春回陇亩，欢到尊罍。", "记取明朝登览，绿漪惟有秦淮。"]'),
('song-ci-57','朝中措','侯置','宋','宋词','song-ci','朝中措','[]','露英云萼一般清。',57,'宋词/ci.song.9000.json','["露英云萼一般清。", "揉雪更雕琼。", "预喜重阳登览，大家插帽浮觥。", "分香减翠，殷勤远寄，珍重多情。", "不似绮窗双艳，向人解语倾城。"]'),
('song-ci-58','朝中措','侯置','宋','宋词','song-ci','朝中措','[]','依微春绿遍江干。',57,'宋词/ci.song.9000.json','["依微春绿遍江干。", "烟水小屏寒。", "惆怅雁行南北，新词不忍拈看。", "从今寄取，临风把酒，役梦忘飧。", "飞絮落花时候，扁舟也到孤山。"]'),
('song-ci-59','朝中措','侯置','宋','宋词','song-ci','朝中措','[]','风帘交翠篆香飘。',57,'宋词/ci.song.9000.json','["风帘交翠篆香飘。", "却暑卷轻绡。", "最好佳辰相近，寿觞对饮连宵。", "仙翁未老，云中跨凤，台上吹箫。", "看取他年荣事，鱼轩入侍涂椒。"]'),
('song-ci-60','朝中措','侯置','宋','宋词','song-ci','朝中措','[]','年来玉帐罢兵筹。',57,'宋词/ci.song.9000.json','["年来玉帐罢兵筹。", "灯市小迟留。", "花外香随金勒，酒边人倚红楼。", "沙堤此去，传柑侍宴，天上风流。", "还记月华小队，春风十里潭州。"]'),
('song-ci-61','朝中措','侯置','宋','宋词','song-ci','朝中措','[]','年年重午近佳辰。',57,'宋词/ci.song.9000.json','["年年重午近佳辰。", "符艾一番新。", "满酌九霞奇酝，寿君两鬓长春。", "闺中秀美，何如赋得，林下精神。", "早办荆钗布袖，共为云水闲人。"]'),
('song-ci-62','点绛唇','侯置','宋','宋词','song-ci','点绛唇','[]','春日迟迟，柳丝金淡东风软。',50,'宋词/ci.song.9000.json','["春日迟迟，柳丝金淡东风软。", "绿娇红浅。", "帘幕飞新燕。", "玉帐优游，赢得花间宴。", "香尘远。", "暂停歌扇。", "□醉深深院。"]'),
('song-ci-63','点绛唇','侯置','宋','宋词','song-ci','点绛唇','[]','约莫香来，倚阑低瞰花如雪。',50,'宋词/ci.song.9000.json','["约莫香来，倚阑低瞰花如雪。", "怨深愁绝。", "瘦似年时节。", "岁一相逢，常是匆匆别。", "歌壶缺。", "又还吹彻。", "笛里关山月。"]'),
('song-ci-64','苏武慢','侯置','宋','宋词','song-ci','苏武慢','[]','暗雨收梅，晴波摇柳，万顷水精宫冷。',138,'宋词/ci.song.9000.json','["暗雨收梅，晴波摇柳，万顷水精宫冷。", "桥森画栋，岸列红楼，两岸翠帘交映。", "天上行舟，鉴中开户，人在蕊珠仙境。", "况吟烟啸月，弹丝吹竹，太平歌咏。", "人尽说、铜虎分贤，银潢储秀，巩固行都藩屏。", "棠阴散暑，鼎篆凝香，永日一庭虚静。", "红袖持觞，彩笺挥翰，适意酒豪诗俊。", "看飞云丹诏，行沙金勒，待公归觐。"]'),
('song-ci-65','阮郎归','侯置','宋','宋词','song-ci','阮郎归','[]','莫欺骑省鬓边华。',56,'宋词/ci.song.9000.json','["莫欺骑省鬓边华。", "曾眠苏小家。", "彩丝萦腕剪轻霞。", "菖蒲酒更嘉。", "人别后，叹飞花。", "云山和梦遮。", "吴笺小字写流沙。", "几行秋雁斜。"]'),
('song-ci-66','阮郎归','侯置','宋','宋词','song-ci','阮郎归','[]','美人小字称春娇。',55,'宋词/ci.song.9000.json','["美人小字称春娇。", "云鬟玉步摇。", "淡妆浓态楚宫腰。", "梅枝雪未消。", "拚恼乱，尽妖娆。", "微窝生脸潮。", "算来虚度怜宵。", "醉魂谁与招。"]'),
('song-ci-67','阮郎归','侯置','宋','宋词','song-ci','阮郎归','[]','薰风吹尽不多云。',56,'宋词/ci.song.9000.json','["薰风吹尽不多云。", "晓天如水清。", "哦松庭院忽闻笙。", "帘疏香篆明。", "兰玉盛，凤和鸣。", "家声留汉庭。", "狨鞍长傍九重城。", "年年双鬓青。"]'),
('song-ci-68','浪淘沙','侯置','宋','宋词','song-ci','浪淘沙','["\u6d1e\u5ead\u6e56"]','晓日掠轻云。',64,'宋词/ci.song.9000.json','["晓日掠轻云。", "霜瓦鳞鳞。", "六朝山色俨如新。", "家在洞庭南畔住，身在江滨。", "华发照乌巾。", "无意寻春。", "空将两袖拂飞尘。", "可惜梅花开近路，恼尽行人。"]'),
('song-ci-69','踏莎行','侯置','宋','宋词','song-ci','踏莎行','[]','元夕风光，中兴时候。',68,'宋词/ci.song.9000.json','["元夕风光，中兴时候。", "东风著意催梅柳。", "谁家银字小笙簧，倚阑度曲黄昏后。", "拨雪张灯，解衣贳酒。", "觚稜金碧闻依旧。", "明年何处看升平，景龙门下灯如昼。"]'),
('song-ci-70','踏莎行','侯置','宋','宋词','song-ci','踏莎行','[]','雪意初浓，云情已厚。',68,'宋词/ci.song.9000.json','["雪意初浓，云情已厚。", "黄昏散尽扶头酒。", "不知墙外夜来梅，忍寒添得疏花否。", "休更熏香，且同携手。", "从教策策轻寒透。", "亭儿直下玉生烟，暗香归去沾襟袖。"]'),
('song-ci-71','浣溪沙','侯置','宋','宋词','song-ci','浣溪沙','[]','客里忽忽梦帝州。',48,'宋词/ci.song.9000.json','["客里忽忽梦帝州。", "故人相遇一杯休。", "疏梅些子最清幽。", "双绾香螺春意浅，缓歌金缕楚云留。", "不知妆镜若为俦。"]'),
('song-ci-72','浣溪沙','侯置','宋','宋词','song-ci','浣溪沙','[]','倚醉怀春翠黛长。',48,'宋词/ci.song.9000.json','["倚醉怀春翠黛长。", "肉红衫子半窥墙。", "兰汤浴困嫩匀妆。", "应为长年餐绛雪，故教丹颊耐清霜。", "弄晴飞馥笑冯唐。"]'),
('song-ci-73','浣溪沙','侯置','宋','宋词','song-ci','浣溪沙','[]','春梦惊回谢氏塘。',48,'宋词/ci.song.9000.json','["春梦惊回谢氏塘。", "箧中消尽旧家香。", "休文多病怯秋光。", "空对金盘承瑞露，竟无玉杵碎玄霜。", "醉魂飞度月宫凉。"]'),
('song-ci-74','眼儿媚','侯置','宋','宋词','song-ci','眼儿媚','[]','花信风高雨又收。',58,'宋词/ci.song.9000.json','["花信风高雨又收。", "风雨互迟留。", "无端燕子，怯寒归晚，闲损帘钩。", "弹棋打马心都懒，撺掇上春愁。", "推书就枕，凫烟淡淡，蝶梦悠悠。"]'),
('song-ci-75','渔家傲','侯置','宋','宋词','song-ci','渔家傲','[]','过尽百花芳草满。',72,'宋词/ci.song.9000.json','["过尽百花芳草满。", "柳丝舞困阑干暖。", "柳外秋千裙影乱。", "人逐伴。", "旧家心性如今懒。", "斗帐宝香凝不散。", "黄昏院落莺声晚。", "红叶不来音信断。", "疏酒盏。", "东阳瘦损无人管。"]'),
('song-ci-76','渔家傲','侯置','宋','宋词','song-ci','渔家傲','["\u94b1\u5858\u6c5f"]','本是潇湘渔艇客。',72,'宋词/ci.song.9000.json','["本是潇湘渔艇客。", "钱塘江上铺帆席。", "两处烟波天一色。", "云幂幂。", "吴山不似湘山碧。", "休费精神劳梦役。", "鸥凫难上铜驼陌。", "扰扰红尘人似织。", "山头石。", "潮生月落今如昔。"]'),
('song-ci-77','临江仙','侯置','宋','宋词','song-ci','临江仙','[]','一抹烟林屏样展，轻花岸柳无边。',70,'宋词/ci.song.9000.json','["一抹烟林屏样展，轻花岸柳无边。", "连朝春雨涨平川。", "冬冬迎社鼓，渺渺下陂船。", "同事多才饶我懒，乘闲纵饮郊园。", "髻花敧侧醉巾偏。", "时丰容卒岁，游乐更明年。"]'),
('song-ci-78','临江仙','侯置','宋','宋词','song-ci','临江仙','[]','失脚青云何所往，故山松竹应秋。',70,'宋词/ci.song.9000.json','["失脚青云何所往，故山松竹应秋。", "痴儿官事几时休。", "可怜双白鬓，斗栗尚迟留。", "尊酒偷闲聊放旷，夜凉河汉西流。", "从教孤笛喷高楼。", "与君同一醉，明日旋分愁。"]'),
('song-ci-79','柳梢青','侯置','宋','宋词','song-ci','柳梢青','[]','小院轻寒，酒浓香软，深沈帘幕。',61,'宋词/ci.song.9000.json','["小院轻寒，酒浓香软，深沈帘幕。", "我辈相逢，欢然一笑，春在杯酌。", "家山辜负猿鹤。", "轩冕意、秋云似薄。", "我自西风，扁舟归去，看君寥廓。"]'),
('song-ci-80','柳梢青','侯置','宋','宋词','song-ci','柳梢青','[]','楚天清绝。',61,'宋词/ci.song.9000.json','["楚天清绝。", "苇岸兰汀，素秋时节。", "帘卷湘鬟，香飞云篆，叵看轻别。", "明朝底处关山，算总是、愁花恨月。", "白马江寒，黄牛峡静，小梅初彻。"]'),
('song-ci-81','杏花天','侯置','宋','宋词','song-ci','杏花天','[]','宝钗整鬓双鸾斗。',66,'宋词/ci.song.9000.json','["宝钗整鬓双鸾斗。", "睡未醒、熏风襟袖。", "彩丝皓腕宜清昼。", "更艾虎、衫儿新就。", "玉杯共饮菖蒲酒。", "愿耐夏、宜春厮守。", "榴花故意红添皱。", "映得人来越瘦。"]'),
('song-ci-82','江城子','侯置','宋','宋词','song-ci','江城子','["\u897f\u6e56"]','萍蓬踪迹几时休。',86,'宋词/ci.song.9000.json','["萍蓬踪迹几时休。", "尽飘浮。", "为君留。", "共话当年，年少气横秋。", "莫叹两翁俱白发，今古事，尽悠悠。", "西风吹梦入江楼。", "故山幽。", "谩回头。", "又是手遮，西日望皇州。", "欲向西湖重载酒，君不去，与谁游。"]'),
('song-ci-83','南歌子','侯置','宋','宋词','song-ci','南歌子','[]','菊润初经雨，橙香独占秋。',62,'宋词/ci.song.9000.json','["菊润初经雨，橙香独占秋。", "碧琳仙酿试新篘。", "内集熙熙休试、蚁浮瓯。", "家世传黄阁，功名起黑头。", "双凫聊傍故人舟。", "咫尺青云岐路、看英游。"]'),
('song-ci-84','瑞鹧鸪','侯置','宋','宋词','song-ci','瑞鹧鸪','[]','遥天拍水共空明。',64,'宋词/ci.song.9000.json','["遥天拍水共空明。", "玉镜开奁特地晴。", "极目秋容无限好，举头醉眼暂须醒。", "白眉公子催行急，碧落仙人著句清。", "后夜萧萧葭苇岸，一尊独酌见离情。"]'),
('song-ci-85','天仙子','侯置','宋','宋词','song-ci','天仙子','[]','暖日丽晴春正好。',80,'宋词/ci.song.9000.json','["暖日丽晴春正好。", "杨柳池塘风弄晓。", "露桃云杏一番新，花窈窕。", "香飘缈。", "玉帐靓深闻语笑。", "新赐绣鞯花映照。", "须信浓恩春共到。", "汉家飞将久宣劳，迎禁诏。", "瞻天表。", "入卫帝庭常不老。"]'),
('song-ci-86','醉落魄・一斛珠','侯置','宋','宋词','song-ci','醉落魄・一斛珠','[]','铜壶漏歇。',67,'宋词/ci.song.9000.json','["铜壶漏歇。", "纱窗倒挂梅梢月。", "玉人酒晕消香雪。", "促轸调弦，弹个古离别。", "雏莺小凤交飞说。", "嘈嘈软语丁宁切。", "相如敧枕推红氎。", "脉脉无言，还记旧时节。"]'),
('song-ci-87','醉落魄・一斛珠','侯置','宋','宋词','song-ci','醉落魄・一斛珠','[]','梅花似雪。',67,'宋词/ci.song.9000.json','["梅花似雪。", "雪花却似梅清绝。", "小窗低映梅梢月。", "常记良宵，吹酒共攀折。", "如今客里都休说。", "潇潇洒洒情怀别。", "夜阑火冷孤灯灭。", "雪意梅情，分付漆园蝶。"]'),
('song-ci-88','醉落魄・一斛珠','侯置','宋','宋词','song-ci','醉落魄・一斛珠','[]','玉钩珠箔。',67,'宋词/ci.song.9000.json','["玉钩珠箔。", "夜凉庭院天垂幕。", "好风吹动纶巾角。", "羽扇休挥，已怯絺衣薄。", "扁舟明日清溪泊。", "归来依旧情怀恶。", "为君唤月骖鸾鹤。", "天近多寒，满引金凿落。"]'),
('song-ci-89','减字木兰花','侯置','宋','宋词','song-ci','减字木兰花','[]','春酲拚却。',52,'宋词/ci.song.9000.json','["春酲拚却。", "鶗鴂一声花雨落。", "密炬红残。", "人在青罗步障间。", "天公薄相。", "惯得柳绵高百丈。", "彩笔题诗。", "休诵骚人九辨词。"]'),
('song-ci-90','鹊桥仙','侯置','宋','宋词','song-ci','鹊桥仙','[]','鹤发萧森，玉颜腴润，养就黄芽金鼎。',68,'宋词/ci.song.9000.json','["鹤发萧森，玉颜腴润，养就黄芽金鼎。", "一区松菊老湘滨，但心远、何妨人境。", "衮衣家世，鸣鸾歌舞，到了春冰消尽。", "不须惆怅梦中身，这彩选、输赢谁省。"]'),
('song-ci-91','醉蓬莱','赵彦端','宋','宋词','song-ci','醉蓬莱','["\u897f\u6e56"]','向蓬莱云渺。',120,'宋词/ci.song.9000.json','["向蓬莱云渺。", "姑射山深，有春长好。", "香满枝南，笑人间惊早。", "试问寒柯，镂冰裁玉，费化工多少。", "东阁诗成，西湖梦觉，几番清晓。", "好是罗帏，麝温屏暖，却恨烟村，雨愁风恼。", "一一清芬，为东君倾倒。", "待得明年，翠阴青子，荫凤皇池沼。", "更把阳和，从头付与，繁花芳草。"]'),
('song-ci-92','满江红','赵彦端','宋','宋词','song-ci','满江红','[]','千种繁春，春已去、翩然无迹。',118,'宋词/ci.song.9000.json','["千种繁春，春已去、翩然无迹。", "谁信道、荼䕷枝上，静中留得。", "晓镜洗妆非粉白，晚衣弄舞馀衫碧。", "粲宝钿、珠珥不胜持，浓阴夕。", "金翦度，还堪惜。", "霜蝶睡，无从觅。", "知多少、好词清梦，酿成冰骨。", "天女散花无酒圣，仙人种玉惭香德。", "怅攀条、记得鬓丝青，东风客。"]'),
('song-ci-93','满江红','赵彦端','宋','宋词','song-ci','满江红','[]','津鼓冬冬，三老醉、知谁留得。',115,'宋词/ci.song.9000.json','["津鼓冬冬，三老醉、知谁留得。", "都不记、琵琵洲畔，草青江碧。", "桃李春风吹不断，烟霞秋兴清无极。", "怅樽前、桂子有馀香，曾相识。", "残雨昼，初凉夕。", "高烛烂，新醅白。", "长歌断，欢意不如愁色。", "父老能寻循吏传，关河暂枉诸侯客。", "待日边、一纸诏黄飞，胜相忆。"]'),
('song-ci-94','满江红','赵彦端','宋','宋词','song-ci','满江红','[]','赐被薰炉，曾同见、官槐重绿。',115,'宋词/ci.song.9000.json','["赐被薰炉，曾同见、官槐重绿。", "时归看、绮疏叠嶂，楚腰翻曲。", "君过蓬山轻岁月，我怀庐阜分符竹。", "道别离、待得再归来，人应俗。", "春欲动，醅初熟。", "追一笑，森三玉。", "且相对青眼，共裁红烛。", "小语人家闲意态，浅寒都下新装束。", "念平生、和雨醉东风，从今足。"]'),
('song-ci-95','水调歌头','赵彦端','宋','宋词','song-ci','水调歌头','["\u6d1e\u5ead\u6e56"]','秋色忽如许，风露皎如空。',114,'宋词/ci.song.9000.json','["秋色忽如许，风露皎如空。", "平生青鬓馀地，老与故人同。", "忆得鲈鱼来后，杂以洞庭新橘，月堕酒杯中。", "宾客可人意，歌舞转春风。", "坐间玉，花底扇，又从容。", "从容更好，无奈多病已衰翁。", "赖有主人风味，识我少年狂态，乞与酒颜红。", "一醉晓鸦起，流水任西东。"]'),
('song-ci-96','水调歌头','赵彦端','宋','宋词','song-ci','水调歌头','[]','淦水定何许，楼外满晴岚。',114,'宋词/ci.song.9000.json','["淦水定何许，楼外满晴岚。", "落霞蜚鸟无际，新酒为谁甘。", "闻道居邻玉笥，下有芝田琳苑，光景照江南。", "已转丹砂九，应降素云三。", "忆畴昔，翻舞袖，纵剧谈。", "玉壶倾倒，香务黄菊酿红柑。", "好在当时明月，只有炉薰一缕，缄寄可同参。", "剩肯南游不，蓬海试穷探。"]'),
('song-ci-97','瑞鹤仙','赵彦端','宋','宋词','song-ci','瑞鹤仙','[]','记河梁折柳。',127,'宋词/ci.song.9000.json','["记河梁折柳。", "问画堂乐事，燕鸿难偶。", "十年谩回首。", "但亭亭紫盖，差差南斗。", "传闻小有。", "种桃花、亲烦素手。", "怪归来、道骨仙风缥缈，迥然非旧。", "清昼。", "江南如画，紫菊冬前，翠橙霜后。", "扁舟渡口。", "佳客至，奉名酒。", "唤青鸾起舞，云窗月槛，一曲山明水秀。", "笑相看、玉海别来，浅如故否。"]'),
('song-ci-98','瑞鹤仙','赵彦端','宋','宋词','song-ci','瑞鹤仙','[]','揽垂杨细折。',127,'宋词/ci.song.9000.json','["揽垂杨细折。", "有别情遗爱，与君都说。", "文茵带雕轭。", "是行春来处，去年阡陌。", "柔桑半叶。", "转光风、轻扬秀麦。", "正人家共约，耕相借牛，社相留客。", "清绝。", "溪山犹记，脱帽吟风，倚楼招月。", "东君何事，将春至，放春歇。", "道从今江上，一花一柳，皆想油幢瑞节。", "纵离愁、瘦减腰围，带金正晔。"]'),
('song-ci-99','朝中措','赵彦端','宋','宋词','song-ci','朝中措','[]','山矾风味更梨花。',57,'宋词/ci.song.9000.json','["山矾风味更梨花。", "清白竞春华。", "试问西园清夜，何如山崦人家。", "楚东千嶂，吴江一棹，云路非赊。", "惟有相思两地，可怜淡月朝霞。"]'),
('song-ci-100','朝中措','赵彦端','宋','宋词','song-ci','朝中措','[]','烧灯已过禁烟前。',57,'宋词/ci.song.9000.json','["烧灯已过禁烟前。", "春信递相传。", "柳暗乍迷津路，花暄欲照江天。", "天涯宾主，相逢老矣，一笑欢然。", "晚岁许同庐社，西风不买吴船。"]'),
('song-ci-101','朝中措','赵彦端','宋','宋词','song-ci','朝中措','[]','长松擎月与天通。',57,'宋词/ci.song.9000.json','["长松擎月与天通。", "霜叶乱惊鸿。", "露炯乍疑杯滟，云生似觉衣重。", "江南胜处，青环楚嶂，红半溪枫。", "倦客会应归去，一亭长枕寒空。"]'),
('song-ci-102','朝中措','赵彦端','宋','宋词','song-ci','朝中措','[]','几枝筇竹半烟云。',57,'宋词/ci.song.9000.json','["几枝筇竹半烟云。", "钟鼓醉中闻。", "千点好山馀思，一湾流水能分。", "多情皓月，轮栖夜午，光动风文。", "看取清闲宾主，犹胜富贵封君。"]'),
('song-ci-103','朝中措','赵彦端','宋','宋词','song-ci','朝中措','[]','新凉溪阁暮山重。',57,'宋词/ci.song.9000.json','["新凉溪阁暮山重。", "水月共空濛。", "九转不须尘外，三峰只在壶中。", "他年盛业，云间可望，林下难逢。", "记取芗林岩洞，何如于越秋风。"]'),
('song-ci-104','朝中措','赵彦端','宋','宋词','song-ci','朝中措','[]','西城烟雾一重重。',57,'宋词/ci.song.9000.json','["西城烟雾一重重。", "潇洒便秋风。", "巧妒玉人装髻，无如禁钥难通。", "新声窈眇，怨传楚些，娇并吴宫。", "夜久三星为粲，皓娥宁为君容。"]'),
('song-ci-105','新荷叶','赵彦端','宋','宋词','song-ci','新荷叶','[]','欲暑还凉，如春有意重归。',100,'宋词/ci.song.9000.json','["欲暑还凉，如春有意重归。", "春若归来，任他莺老花飞。", "轻雷澹雨，似晚风、欺得单衣。", "檐声惊醉，起来新缘成围。", "回首分携。", "光风冉冉菲菲。", "曾几何时，故山疑梦还非。", "鸣琴再抚，将清恨、都入金徽。", "永怀桥下，系船溪柳依依。"]'),
('song-ci-106','新荷叶','赵彦端','宋','宋词','song-ci','新荷叶','[]','雨细梅黄，去年双燕还归。',100,'宋词/ci.song.9000.json','["雨细梅黄，去年双燕还归。", "多少繁红，尽随蝶舞蜂飞。", "阴浓绿暗，正麦秋、犹衣罗衣。", "香凝沈水，雅宜帘幕重围。", "绣扇仍携。", "花枝尘染芳菲。", "遥想当时，故交往往人非。", "天涯再见，悦情话、景仰清徽。", "可人怀抱，晚期莲社相依。"]'),
('song-ci-107','新荷叶','赵彦端','宋','宋词','song-ci','新荷叶','[]','玉井冰壶，人间有此清秋。',102,'宋词/ci.song.9000.json','["玉井冰壶，人间有此清秋。", "笑语雍雍，从今庭户初修。", "迎风待月，香凝处、四卷帘钩。", "月波奇观，未饶当日南楼。", "闻说三吴，江湖胜、从古风流。", "况有双轓，旧谙黄阁青油。", "金瓯屡启，应难解、久为人留。", "天池波滟，可怜苹满汀洲。"]'),
('song-ci-108','看花回','赵彦端','宋','宋词','song-ci','看花回','[]','注目。',126,'宋词/ci.song.9000.json','["注目。", "正江湖浩荡，烟云离属。", "美人衣兰佩玉。", "澹秋水凝神，阳春翻曲。", "烹鲜坐啸，清净五千言自足。", "横剑气、南斗光中，浩然一醉引双鹿。", "回雁到、归书未续。", "梦草处、旧芳重绿。", "谁忆潇湘岁晚，为唤起长风，吹飞黄鹄。", "功名异时，圮上家传谢荣辱。", "待封留，拜公堂下，授我长生箓。"]'),
('song-ci-109','看花回','赵彦端','宋','宋词','song-ci','看花回','[]','爱日。',126,'宋词/ci.song.9000.json','["爱日。", "报疏梅动意，春前呼得。", "画栋晓开寿城。", "度百和温馨，霜华无力。", "斑衣翠袖，人面年年照酒色。", "环四座、璧月琼枝，恍然江县拟乡国。", "闻道抚、东岩旧迹。", "又殊胜、谢家清逸。", "知与桃花笑了，定何似青鸟，层城消息。", "他年妙高峰上，优昙会堪折。", "拥轻轩、未妨游戏，看取朱轮十。"]'),
('song-ci-110','芰荷香','赵彦端','宋','宋词','song-ci','芰荷香','[]','燕初归。',120,'宋词/ci.song.9000.json','["燕初归。", "正春阴暗淡，客意凄迷。", "玉觞无味，晚花雨退凝脂。", "多情细柳，对沈腰、浑不胜垂。", "别袖忍见离披。", "江南陌上，强半红飞。", "乐事从今一梦散，纵锦囊空在，金碗谁挥。", "舞裙歌扇，故应间琐幽闺。", "练江诗就，算檥舟、宁不相思。", "肠断莫诉离杯。", "青云路稳，白首心期。"]'),
('song-ci-111','垂丝钓','赵彦端','宋','宋词','song-ci','垂丝钓','[]','短篷醉舣。',81,'宋词/ci.song.9000.json','["短篷醉舣。", "江南秋意如水。", "露草星明，风柳丝委。", "危槛倚。", "为故人宴喜。", "欢无几。", "念青鞋紫绮。", "论诗载酒，犹胜心寄双鲤。", "倦游晚矣。", "云路非吾事。", "湖海从君意。", "沙雁起。", "记夜阑隐几。"]'),
('song-ci-112','垂丝钓','赵彦端','宋','宋词','song-ci','垂丝钓','[]','莫愁有信。',81,'宋词/ci.song.9000.json','["莫愁有信。", "全胜春梦无准。", "篆缕欲销，衣粉堪认。", "残梦醒。", "枕夜凉满鬓。", "想香迳。", "正垂垂美荫。", "晚花在否，朱阑谁与同凭。", "断云怨冷。", "青鸟无凭问。", "红叶翻成恨。", "三五近。", "试预占破镜。"]'),
('song-ci-113','谒金门','赵彦端','宋','宋词','song-ci','谒金门','[]','朱槛曲。',53,'宋词/ci.song.9000.json','["朱槛曲。", "妆浅鬓云吹绿。", "半尺鹅溪凉意足。", "手香沾柄玉。", "午梦已惊难续。", "说与翠梧修竹。", "蓬海路遥天六六。", "乘鸾何处逐。"]'),
('song-ci-114','谒金门','赵彦端','宋','宋词','song-ci','谒金门','[]','劳顾曲。',53,'宋词/ci.song.9000.json','["劳顾曲。", "燕贡雅羞衣绿。", "鲁酒不能春味足。", "小杯空荐玉。", "只愿此欢常续。", "莫序水边丝竹。", "明日朝参同趁六。", "犹期归骑逐。"]'),
('song-ci-115','谒金门','赵彦端','宋','宋词','song-ci','谒金门','[]','休相忆。',53,'宋词/ci.song.9000.json','["休相忆。", "明夜远如今日。", "楼外绿烟村幂幂。", "花飞如许急。", "柳岸晚来船集。", "波底斜阳红湿。", "送尽去云成独立。", "酒醒愁又入。"]'),
('song-ci-116','谒金门','赵彦端','宋','宋词','song-ci','谒金门','[]','春已半。',53,'宋词/ci.song.9000.json','["春已半。", "绣绿新红如换。", "燕子还来帘幕畔。", "闲愁天不管。", "翠被曲屏香满。", "花叶彩笺人远。", "鹊喜蛛丝都未判。", "连环空约腕。"]'),
('song-ci-117','谒金门','赵彦端','宋','宋词','song-ci','谒金门','[]','春不尽。',53,'宋词/ci.song.9000.json','["春不尽。", "处处与情相趁。", "谁道刘郎家恁近。", "一年花不问。", "双剪画罗春胜。", "今夜月圆如镜。", "怎得酒阑心易定。", "试将金液镇。"]'),
('song-ci-118','谒金门','赵彦端','宋','宋词','song-ci','谒金门','[]','春似绣。',53,'宋词/ci.song.9000.json','["春似绣。", "不是别离时候。", "滴尽黄昏残刻漏。", "月高花影昼。", "好在画屏金兽。", "深琐粉窗兰牖。", "溪水南来堪问否。", "几时离渡口。"]'),
('song-ci-119','谒金门','赵彦端','宋','宋词','song-ci','谒金门','[]','朱户密。',53,'宋词/ci.song.9000.json','["朱户密。", "镇锁一庭春日。", "画幕黄帘芳草碧。", "游蜂初未识。", "脆管么弦无力。", "青子绿阴如织。", "花满深宫无路入。", "旧游浑记得。"]'),
('song-ci-120','谒金门','赵彦端','宋','宋词','song-ci','谒金门','[]','春意密。',53,'宋词/ci.song.9000.json','["春意密。", "不受人间风日。", "一曲清歌云暮碧。", "尊前今夜识。", "醉客倦吟无力。", "滞梦停愁相织。", "只道桃源难再入。", "有人还问得。"]'),
('song-ci-121','柳梢青','赵彦端','宋','宋词','song-ci','柳梢青','[]','衰翁自谪。',61,'宋词/ci.song.9000.json','["衰翁自谪。", "堪笑忘了，山林闲适。", "一岁花黄，一秋酒绿，一番头白。", "浮生似醉如客。", "问底事、归来未得。", "但愿长年，故人相与，春朝秋夕。"]');
